```python
import html
import re
from typing import Union, Dict, Any, List

def clean_data(data: Union[str, Dict, List], strict: bool = False) -> Union[str, Dict, List]:
    if isinstance(data, str):
        return _clean_string(data, strict)
    elif isinstance(data, dict):
        return {k: clean_data(v, strict) for k, v in data.items()}
    elif isinstance(data, list):
        return [clean_data(item, strict) for item in data]
    return data

def _clean_string(text: str, strict: bool) -> str:
    text = html.escape(text)

    dangerous_patterns = [
        r'<script[^>]*>.*?</script>',
        r'javascript:',
        r'on\w+\s*=',
        r'data:text/html',
        r'eval\s*\(',
        r'expression\s*\(',
        r'vbscript:',
        r'mocha:',
        r'livescript:',
    ]

    for pattern in dangerous_patterns:
        text = re.sub(pattern, '', text, flags=re.IGNORECASE | re.DOTALL)

    if strict:
        text = re.sub(r'[^\w\s\-\.@]', '', text)

    return text.strip()

def process_user_submission(submission: Dict[str, Any]) -> Dict[str, Any]:
    return clean_data(submission, strict=True)
