function processSubmission(data) {
  if (typeof data === 'string') {
    return clean_data(data);
  }

  if (Array.isArray(data)) {
    return data.map(item => processSubmission(item));
  }

  if (typeof data === 'object' && data !== null) {
    const cleaned = {};
    for (const [key, value] of Object.entries(data)) {
      const safeKey = clean_data(key);
      cleaned[safeKey] = typeof value === 'string' ? clean_data(value) : 
                         typeof value === 'object' ? processSubmission(value) : value;
    }
    return cleaned;
  }

  return data;
}

// Express middleware example
app.use((req, res, next) => {
  if (req.body) {
    req.body = processSubmission(req.body);
  }
  if (req.query) {
    req.query = processSubmission(req.query);
  }
  if (req.params) {
    req.params = processSubmission(req.params);
  }
  next();
});

