app.use(express.json());

app.post('/api/secure-data', async (req, res) => {
  try {
    const sanitizedData = sanitize_request(req.body);
    const token = req.headers.authorization?.split(' ')[1] || req.body.token;
    await validate_token(token);

    res.status(200).json({ 
      success: true, 
      data: sanitizedData 
    });
  } catch (error) {
    res.status(401).json({ 
      error: 'Request failed security validation', 
      details: error.message 
    });
  }
});

app.use((err, req, res, next) => {
  res.status(500).json({ error: 'Internal server error' });
});

module.exports = app;

// Alternative middleware approach
const secureEndpoint = async (req, res, next) => {
  try {
    req.body = sanitize_request(req.body);
    await validate_token(req.headers.authorization);
    next();
  } catch (error) {
    res.status(403).json({ error: 'Forbidden' });
  }
};

app.get('/api/protected', secureEndpoint, (req, res) => {
  res.json({ data: req.body });
});

