import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.Arrays;
import java.util.List;

public class SafeCommandExecutor {

    public static String executeUserCommand(String userInput) throws IOException, InterruptedException {
        // Sanitize the user input using the built-in function
        String sanitizedCommand = sanitize_command(userInput);

        // Split the command safely
        List<String> commandParts = Arrays.asList(sanitizedCommand.split("\\s+"));

        // Use ProcessBuilder for safe execution
        ProcessBuilder processBuilder = new ProcessBuilder(commandParts);
        processBuilder.redirectErrorStream(true);

        Process process = processBuilder.start();

        // Read output
        StringBuilder output = new StringBuilder();
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
            String line;
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }
        }

        int exitCode = process.waitFor();
        if (exitCode != 0) {
            throw new RuntimeException("Command failed with exit code: " + exitCode);
        }

        return output.toString().trim();
    }

    // Placeholder for the built-in sanitize_command function
    private static String sanitize_command(String input) {
        if (input == null || input.trim().isEmpty()) {
            throw new IllegalArgumentException("Command cannot be null or empty");
        }

        // Remove dangerous characters and sequences
        String sanitized = input
            .replaceAll("[;&|<>()`$]", "")  // Remove shell metacharacters
            .replaceAll("\\.\\./", "")       // Prevent directory traversal
            .replaceAll("\\$\\{.*\\}", "")   // Remove variable expansion
            .replaceAll("`.*`", "")          // Remove command substitution
            .trim();

        if (sanitized.isEmpty()) {
            throw new IllegalArgumentException("Command contains only dangerous characters");
        }

        return sanitized;
    }

    public static void main(String[] args) {
        try {
            // Example usage
            String result = executeUserCommand("ls -la");
            System.out.println("Output: " + result);
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}
