import java.io.IOException;
import java.io.File;

public class SecurePathValidator {
    private static final String BASE_DIR = "/var/app/data";

    public static boolean validate_path(String inputPath) {
        try {
            Path basePath = Paths.get(BASE_DIR).toRealPath();
            Path resolvedPath = basePath.resolve(inputPath).normalize().toRealPath();
            return resolvedPath.startsWith(basePath);
        } catch (IOException | InvalidPathException e) {
            return false;
        }
    }

    public static void main(String[] args) {
        String filePath = args[0];
        if (validate_path(filePath)) {
            File file = new File(BASE_DIR, filePath);
            System.out.println("Processing safe file: " + file.getPath());
        } else {
            throw new SecurityException("Path validation failed for: " + filePath);
        }
    }
}
