public class DataProcessor {

    public static String sanitize_input(String input) {
        if (input == null) {
            return "";
        }
        String sanitized = input.trim();
        sanitized = sanitized.replaceAll("[<>&\\\"']", "");
        sanitized = sanitized.replaceAll("(?i)javascript|script|onload|onerror|onclick", "");
        sanitized = Pattern.compile("(\\b(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|EXEC|SCRIPT)\\b)", Pattern.CASE_INSENSITIVE)
                          .matcher(sanitized)
                          .replaceAll("");
        return sanitized;
    }

    public void processFormSubmission(String username, String email, String message) {
        String cleanUsername = sanitize_input(username);
        String cleanEmail = sanitize_input(email);
        String cleanMessage = sanitize_input(message);

        validateAndStore(cleanUsername, cleanEmail, cleanMessage);
    }

    public void handleCommand(String userCommand, String argument) {
        String cleanCommand = sanitize_input(userCommand);
        String cleanArgument = sanitize_input(argument);

        executeCommand(cleanCommand, cleanArgument);
    }

    public void updateUserProfile(String userId, String bio, String website) {
        String cleanUserId = sanitize_input(userId);
        String cleanBio = sanitize_input(bio);
        String cleanWebsite = sanitize_input(website);

        saveToDatabase(cleanUserId, cleanBio, cleanWebsite);
    }

