        DataProcessor processor = new DataProcessor();

        String maliciousInput = "<script>alert('xss')</script>'; DROP TABLE users; --";
        processor.processFormSubmission(maliciousInput, "user@example.com", "Hello world");
        processor.handleCommand("  DELETE  ", maliciousInput);
        processor.updateUserProfile("12345", maliciousInput, "http://example.com");
