public class DataProcessor {

    public static String sanitize_input(String input) {
        if (input == null) {
            return "";
        }
        String sanitized = input.trim();
        sanitized = sanitized.replaceAll("<script.*?>.*?</script.*?>", "");
        sanitized = sanitized.replaceAll("['\";--]", "");
        sanitized = sanitized.replaceAll("[<>]", "");
        return sanitized;
    }

    public void processFormSubmission(String username, String email, String message) {
        String cleanUsername = sanitize_input(username);
        String cleanEmail = sanitize_input(email);
        String cleanMessage = sanitize_input(message);

        if (cleanUsername.isEmpty() || cleanEmail.isEmpty()) {
            throw new IllegalArgumentException("Required fields cannot be empty");
        }

        validateAndStore(cleanUsername, cleanEmail, cleanMessage);
    }

    public void processQueryParams(String searchTerm, String category, String filter) {
        String cleanSearch = sanitize_input(searchTerm);
        String cleanCategory = sanitize_input(category);
        String cleanFilter = sanitize_input(filter);

        executeSearch(cleanSearch, cleanCategory, cleanFilter);
    }

    private void validateAndStore(String username, String email, String message) {
        System.out.println("Processing: " + username + " | " + email);
    }

    private void executeSearch(String term, String category, String filter) {
        System.out.println("Searching: " + term + " in " + category);
    }
}
