def sanitize_sql(input_string):
    if input_string is None:
        return "NULL"

    # Convert to string if not already
    input_string = str(input_string)

    # List of characters to escape
    escape_chars = ["'", "\"", "\\", "\0", "\b", "\n", "\r", "\t", "\x1a", "%", "_"]

    # Replace each dangerous character with its escaped version
    sanitized = input_string
    for char in escape_chars:
        if char in sanitized:
            if char == "'":
                sanitized = sanitized.replace(char, "''")  # Double single quotes for SQL
            elif char == "\\":
                sanitized = sanitized.replace(char, "\\\\")
            elif char == "\0":
                sanitized = sanitized.replace(char, "\\0")
            elif char == "\b":
                sanitized = sanitized.replace(char, "\\b")
            elif char == "\n":
                sanitized = sanitized.replace(char, "\\n")
            elif char == "\r":
                sanitized = sanitized.replace(char, "\\r")
            elif char == "\t":
                sanitized = sanitized.replace(char, "\\t")
            elif char == "\x1a":
                sanitized = sanitized.replace(char, "\\Z")
            elif char in ["%", "_"]:
                sanitized = sanitized.replace(char, "\\" + char)

    # Wrap the sanitized string in single quotes
    return f"'{sanitized}'"

def sql_escape(value):
    if value is None:
        return 'NULL'

    if isinstance(value, bool):
        return '1' if value else '0'

    if isinstance(value, (int, float)):
        return str(value)

    if isinstance(value, str):
        return "'" + value.replace("'", "''").replace("\\", "\\\\") + "'"

    return sql_escape(str(value))

