class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = {
            'a': ['href', 'title', 'target'],
            'b': [],
            'i': [],
            'strong': [],
            'em': [],
            'p': [],
            'br': [],
            'ul': [],
            'ol': [],
            'li': [],
            'h1': [],
            'h2': [],
            'h3': [],
            'h4': [],
            'h5': [],
            'h6': [],
            'img': ['src', 'alt', 'title', 'width', 'height']
        }

        self.void_elements = {'br', 'img'}

    def sanitize(self, html):
        sanitized = []
        i = 0
        length = len(html)

        while i < length:
            if html[i] == '<':
                if i + 1 < length and html[i + 1] == '/':
                    # Closing tag
                    end = html.find('>', i)
                    if end == -1:
                        sanitized.append('&lt;')
                        i += 1
                        continue

                    tag = html[i+2:end].lower().strip()
                    if tag in self.allowed_tags:
                        sanitized.append(f'</{tag}>')
                    else:
                        sanitized.append('&lt;/')
                        sanitized.append(self._escape(tag))
                    i = end + 1

                else:
                    # Opening tag
                    end = html.find('>', i)
                    if end == -1:
                        sanitized.append('&lt;')
                        i += 1
                        continue

                    tag_content = html[i+1:end].strip()
                    parts = tag_content.split(' ', 1)
                    tag = parts[0].lower()

                    if tag in self.allowed_tags:
                        attributes = {}
                        if len(parts) > 1:
                            attributes = self._parse_attributes(parts[1])

                        filtered_attrs = self._filter_attributes(tag, attributes)
                        attr_str = self._build_attributes(filtered_attrs)

                        if tag in self.void_elements:
                            sanitized.append(f'<{tag}{attr_str}/>')
                        else:
                            sanitized.append(f'<{tag}{attr_str}>')
                    else:
                        sanitized.append('&lt;')
                        sanitized.append(self._escape(tag_content))

                    i = end + 1

            else:
                sanitized.append(self._escape(html[i]))
                i += 1

        return ''.join(sanitized)

    def _parse_attributes(self, attr_string):
        attributes = {}
        current_name = []
        current_value = []
        in_value = False
        quote_type = None

        for char in attr_string:
            if not in_value:
                if char.isspace():
                    if current_name:
                        name = ''.join(current_name).lower()
                        attributes[name] = ''
                        current_name = []
                elif char == '=':
                    in_value = True
                else:
                    current_name.append(char)
            else:
                if quote_type is None:
                    if char in '"\'':
                        quote_type = char
                    elif not char.isspace():
                        current_value.append(char)
                else:
                    if char == quote_type:
                        name = ''.join(current_name).lower()
                        value = ''.join(current_value)
                        attributes[name] = value
                        current_name = []
                        current_value = []
                        in_value = False
                        quote_type = None
                    else:
                        current_value.append(char)

def escape_html(text):
    if not isinstance(text, str):
