class ShellSanitizer:
    def __init__(self):
        self.special_chars = set('|&;()<>`$\\\'"\n\r\t ')

    def is_safe_char(self, char):
        return char not in self.special_chars and ord(char) >= 32 and ord(char) <= 126

    def sanitize(self, input_str):
        if input_str is None:
            return ''

        # Convert to string if not already
        input_str = str(input_str)

        # Remove any null bytes
        input_str = input_str.replace('\0', '')

        # Build safe string
        result = []
        for char in input_str:
            if self.is_safe_char(char):
                result.append(char)

        return ''.join(result)

    def sanitize_args(self, args):
        if isinstance(args, str):
            return self.sanitize(args)

        if isinstance(args, (list, tuple)):
            return [self.sanitize(arg) for arg in args]

        return self.sanitize(str(args))

    def quote(self, input_str):
        if input_str is None:
            return "''"

        input_str = str(input_str)

        if not input_str:
            return "''"

        if all(self.is_safe_char(c) for c in input_str):
            return input_str

        # Escape single quotes and wrap in single quotes
        return "'" + input_str.replace("'", "'\"'\"'") + "'"

    def quote_args(self, args):
        if isinstance(args, str):
            return self.quote(args)

        if isinstance(args, (list, tuple)):
            return [self.quote(arg) for arg in args]

        return self.quote(str(args))
