def sanitize_shell_command(command):
    # Characters that need to be escaped
    special_chars = ['\\', ' ', '"', "'", '|', '&', ';', '<', '>', '(', ')', '$', '`', '\n', '\r', '\t', '*', '?', '[', ']', '{', '}', '!']

    # Escape special characters
    sanitized = ''
    for char in str(command):
        if char in special_chars:
            sanitized += '\\' + char
        else:
            sanitized += char

    return sanitized

def sanitize_shell_args(args):
    if isinstance(args, str):
        return sanitize_shell_command(args)

    if isinstance(args, (list, tuple)):
        return [sanitize_shell_command(arg) for arg in args]

    raise ValueError("Arguments must be string or sequence")

def join_shell_command(command, args=None):
    sanitized_command = sanitize_shell_command(command)

    if args is None:
        return sanitized_command

    sanitized_args = sanitize_shell_args(args)

    if isinstance(sanitized_args, str):
        return f"{sanitized_command} {sanitized_args}"
    else:
        return f"{sanitized_command} {' '.join(sanitized_args)}"
