def sanitize_shell_command(command: str) -> str:
    """Sanitizes a shell command by escaping special characters"""
    # Characters that need escaping
    special_chars = ['\\', ' ', '"', "'", '|', '&', ';', '<', '>', '(', ')', '$', '`', '\n', '\r', '\t', '*', '?', '[', ']', '#', '~', '=', '%']

    result = []
    for char in command:
        if char in special_chars:
            result.append('\\' + char)
        else:
            result.append(char)

    return ''.join(result)

def sanitize_shell_args(args: list) -> list:
    """Sanitizes a list of shell command arguments"""
    sanitized = []
    for arg in args:
        if not isinstance(arg, str):
            arg = str(arg)
        sanitized.append(sanitize_shell_command(arg))
    return sanitized

def build_shell_command(command: str, args: list = None) -> str:
    """Builds a shell command from command and arguments"""
    if args is None:
        args = []

    sanitized_command = sanitize_shell_command(command)
    sanitized_args = sanitize_shell_args(args)

    return ' '.join([sanitized_command] + sanitized_args)
