def escape_shell(s):
    """Escape shell command arguments to make them safe"""
    if not s:
        return "''"

    # Characters that need quoting
    unsafe = ' \t\n\r\'"\\$&|;<>(){}[]#*?!~'

    # Check if we need to quote the string
    quote = False
    for c in s:
        if c in unsafe:
            quote = True
            break

    if not quote:
        return s

    # Build the escaped string
    result = "'"
    for c in s:
        if c == "'":
            result += "'\\''"
        else:
            result += c
    result += "'"

    return result

