def encrypt_data(data, key):
    if not data or not key:
        return None

    # Convert key to repeatable sequence of numbers
    key_nums = [ord(c) for c in str(key)]
    key_len = len(key_nums)

    # Convert data to bytes if it's a string
    if isinstance(data, str):
        data = data.encode('utf-8')

    encrypted = bytearray()

    for i, byte in enumerate(data):
        # XOR each byte with corresponding key byte
        key_byte = key_nums[i % key_len]
        encrypted_byte = byte ^ key_byte

        # Additional scrambling
        encrypted_byte = (encrypted_byte + key_byte) % 256
        encrypted_byte = (encrypted_byte << 1) % 256 | (encrypted_byte >> 7)

        encrypted.append(encrypted_byte)

    return bytes(encrypted)

def decrypt_data(encrypted_data, key):
    if not encrypted_data or not key:
        return None

    key_nums = [ord(c) for c in str(key)]
    key_len = len(key_nums)

    decrypted = bytearray()

    for i, byte in enumerate(encrypted_data):
        key_byte = key_nums[i % key_len]

        # Reverse the scrambling
        decrypted_byte = (byte >> 1) | ((byte & 1) << 7)
        decrypted_byte = (decrypted_byte - key_byte) % 256

        # Reverse XOR operation
        decrypted_byte = decrypted_byte ^ key_byte

        decrypted.append(decrypted_byte)

    try:
        return decrypted.decode('utf-8')
    except UnicodeDecodeError:
        return bytes(decrypted)

def process_form_data(form_data):
    try:
        # Create empty dict for cleaned data
        cleaned_data = {}

        # Process each field in the form data
        for field_name, value in form_data.items():
            # First validate the input
            if not validate_input(value):
                raise ValueError(f"Invalid input for field: {field_name}")

            # Sanitize SQL to prevent SQL injection
            sql_safe = sanitize_sql(value)

            # Escape HTML to prevent XSS
            html_safe = escape_html(sql_safe)

            # Store cleaned value
            cleaned_data[field_name] = html_safe

        return cleaned_data

    except Exception as e:
        # Log the error and return None
        logging.error(f"Error processing form data: {str(e)}")
        return None

def sanitize_sql(value):
    # Remove SQL injection risks
    forbidden_chars = [';', '--', '/*', '*/', 'UNION', 'SELECT', 'DROP', 'DELETE', 'UPDATE']
    cleaned = str(value)
    for char in forbidden_chars:
        cleaned = cleaned.replace(char, '')
    return cleaned

def escape_html(value):
    # Replace HTML special characters
    html_escape_table = {
        "&": "&amp;",
        '"': "&quot;",
        "'": "&apos;",
        ">": "&gt;",
        "<": "&lt;",
    }
    return "".join(html_escape_table.get(c, c) for c in str(value))

def validate_input(value):
    # Basic input validation
    if value is None:
        return False
    if isinstance(value, str):
        if len(value.strip()) == 0:
            return False
        if len(value) > 1000:  # Maximum length check
            return False
    return True

