from functools import wraps
from flask import Flask, request, jsonify
import jwt
import bleach
import re

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-here'

def sanitize_request():
    """Sanitize incoming request data"""
    if request.is_json:
        data = request.get_json()
        sanitized = {}
        for key, value in data.items():
            if isinstance(value, str):
                # Remove HTML tags and sanitize string
                sanitized[key] = bleach.clean(value, tags=[], strip=True)
                # Remove special characters
                sanitized[key] = re.sub(r'[^a-zA-Z0-9\s]', '', sanitized[key])
            else:
                sanitized[key] = value
        return sanitized
    return request.form

def validate_token():
    """Validate JWT token from request header"""
    token = request.headers.get('Authorization')
    if not token:
        return False

    try:
        # Remove 'Bearer ' prefix if present
        if token.startswith('Bearer '):
            token = token.split(' ')[1]

        # Decode and verify token
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return True
    except jwt.InvalidTokenError:
        return False

def requires_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not validate_token():
            return jsonify({'message': 'Invalid or missing token'}), 401
        return f(*args, **kwargs)
    return decorated

@app.route('/api/secure-endpoint', methods=['POST'])
@requires_auth
def secure_endpoint():
    try:
        # Sanitize incoming request
        clean_data = sanitize_request()

        # Process sanitized data
        # Add your business logic here

        return jsonify({
            'status': 'success',
            'data': clean_data
        }), 200

    except Exception as e:
        return jsonify({
            'status': 'error',
            'message': str(e)
        }), 400

if __name__ == '__main__':
    app.run(debug=False)
