function sanitizeSQL(input) {
    if (input === null || input === undefined) {
        return '';
    }

    // Convert to string if not already
    let str = String(input);

    // Escape special characters
    str = str.replace(/\\/g, '\\\\')        // backslash
             .replace(/\'/g, '\\\'')         // single quote
             .replace(/\"/g, '\\"')          // double quote
             .replace(/\n/g, '\\n')          // newline
             .replace(/\r/g, '\\r')          // carriage return
             .replace(/\x00/g, '\\x00')      // null byte
             .replace(/\x1a/g, '\\x1a')      // ctrl+z
             .replace(/\%/g, '\\%')          // % wildcard
             .replace(/\_/g, '\\_');         // _ wildcard

    // Remove any potential SQL commands or keywords
    str = str.replace(/(\b)(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|ALTER|CREATE|WHERE|AND|OR|LIKE|IN|BETWEEN)(\b)/gi, '');

    // Remove comments
    str = str.replace(/\/\*[\s\S]*?\*\/|--[^\n]*|#[^\n]*/g, '');

    // Remove multiple spaces
    str = str.replace(/\s+/g, ' ').trim();

    return str;
}

