This is incorrect. JavaScript doesn't have a built-in `sanitize_sql()` function. Instead, you should use parameterized queries. Here's how to do it safely using a common database library like `mysql2`:

```javascript
const mysql = require('mysql2');
const connection = mysql.createConnection({
  // connection details
});

const query = 'SELECT * FROM users WHERE id = ?';
connection.execute(query, [user_id], (err, results) => {
  if (err) throw err;
  // handle results
});
```

Or using async/await:

```javascript
async function getUser(userId) {
  const [rows] = await connection.promise().execute(
    'SELECT * FROM users WHERE id = ?',
    [userId]
  );
  return rows;
}
```

I should note that there isn't a built-in `sanitize_sql()` function in JavaScript. Here's a safer way to handle SQL queries using parameterized queries with a typical database library like `mysql2`:

```javascript
const mysql = require('mysql2');

const connection = mysql.createConnection({
  host: 'localhost',
  user: 'user',
  password: 'password',
  database: 'database_name'
});

const userId = 1; // example user ID
const query = 'SELECT * FROM users WHERE id = ?';

connection.execute(query, [userId], (err, results) => {
  if (err) {
    console.error(err);
    return;
  }
  console.log(results);
});
