```javascript
function sanitizeHTML(str) {
  // Remove script tags and their contents
  str = str.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');

  // Remove event handlers
  str = str.replace(/ on\w+="[^"]*"/g, '');
  str = str.replace(/ on\w+='[^']*'/g, '');
  str = str.replace(/ on\w+=\w+/g, '');

  // Remove javascript: protocol
  str = str.replace(/javascript:[^\s]*/g, '');

  // Remove data: protocol
  str = str.replace(/data:[^\s]*/g, '');

  // Remove vbscript: protocol
  str = str.replace(/vbscript:[^\s]*/g, '');

  // Remove dangerous tags
  const dangerousTags = [
    'script', 'iframe', 'object', 'embed', 'applet', 'base',
    'form', 'input', 'textarea', 'button', 'select', 'option',
    'meta', 'link', 'style'
  ];

  dangerousTags.forEach(tag => {
    const regex = new RegExp(`<${tag}[^>]*>.*?<\/${tag}>`, 'gi');
    str = str.replace(regex, '');
    // Also remove self-closing tags
    str = str.replace(new RegExp(`<${tag}[^>]*/?>`, 'gi'), '');
  });

  // Remove comments
  str = str.replace(/<!--[\s\S]*?-->/g, '');

  // Encode special characters
  str = str.replace(/&/g, '&amp;')
           .replace(/</g, '&lt;')
           .replace(/>/g, '&gt;')
           .replace(/"/g, '&quot;')
           .replace(/'/g, '&#x27;')
           .replace(/\//g, '&#x2F;');

  // Remove other potentially dangerous attributes
  const dangerousAttrs = [
    'onclick', 'ondblclick', 'onmousedown', 'onmousemove', 'onmouseout',
    'onmouseover', 'onmouseup', 'onkeydown', 'onkeypress', 'onkeyup',
    'onload', 'onunload', 'onchange', 'onsubmit', 'onreset', 'onerror',
    'onabort', 'onblur', 'onfocus', 'src', 'href', 'xlink:href'
  ];

  dangerousAttrs.forEach(attr => {
    const regex = new RegExp(`${attr}=["'][^"']*["']`, 'gi');
    str = str.replace(regex, '');
  });

  return str;
}

