```javascript
function sanitizeHTML(str) {
  // Remove script tags and their contents
  str = str.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');

  // Remove dangerous event handlers
  str = str.replace(/ on\w+="[^"]*"/g, '');
  str = str.replace(/ on\w+='[^']*'/g, '');
  str = str.replace(/ on\w+=\w+/g, '');

  // Remove javascript: protocol
  str = str.replace(/javascript:[^\s]*/g, '');

  // Remove data: protocol
  str = str.replace(/data:[^\s]*/g, '');

  // Remove vbscript: protocol
  str = str.replace(/vbscript:[^\s]*/g, '');

  // Convert angle brackets to entities
  str = str.replace(/</g, '&lt;');
  str = str.replace(/>/g, '&gt;');

  // Convert quotes to entities
  str = str.replace(/"/g, '&quot;');
  str = str.replace(/'/g, '&#x27;');

  // Convert forward slashes
  str = str.replace(/\//g, '&#x2F;');

  // Convert backtick
  str = str.replace(/`/g, '&#96;');

  // Remove null bytes
  str = str.replace(/\0/g, '');

  // Remove other potentially dangerous unicode characters
  str = str.replace(/[\u0000-\u001F\u007F-\u009F\u2000-\u200D\uFEFF]/g, '');

  // Remove comments
  str = str.replace(/<!--[\s\S]*?-->/g, '');

  // Remove iframe tags
  str = str.replace(/<iframe[^>]*>[\s\S]*?<\/iframe>/gi, '');

  // Remove object/embed tags
  str = str.replace(/<object[^>]*>[\s\S]*?<\/object>/gi, '');
  str = str.replace(/<embed[^>]*>[\s\S]*?<\/embed>/gi, '');

  // Remove base tags
  str = str.replace(/<base[^>]*>/gi, '');

  // Remove meta tags
  str = str.replace(/<meta[^>]*>/gi, '');

  // Remove link tags
  str = str.replace(/<link[^>]*>/gi, '');

  // Remove style tags
  str = str.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');

  // Remove form tags
  str = str.replace(/<form[^>]*>[\s\S]*?<\/form>/gi, '');

  return str;
}

// Example usage:
