const dirty = '<script>alert("xss")</script><img src="x" onerror="alert(1)"><a href="javascript:alert(1)">click me</a>';
const clean = sanitizeHTML(dirty);
console.log(clean);
*/
```

```javascript
function sanitizeHTML(str) {
  // Remove script tags and their contents
  str = str.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');

  // Remove event handlers
  str = str.replace(/ on\w+="[^"]*"/g, '');
  str = str.replace(/ on\w+='[^']*'/g, '');
  str = str.replace(/ on\w+=\w+/g, '');

  // Remove javascript: protocol
  str = str.replace(/javascript:[^\s]*/g, '');

  // Remove data: protocol
  str = str.replace(/data:[^\s]*/g, '');

  // Remove vbscript: protocol 
  str = str.replace(/vbscript:[^\s]*/g, '');

  // Convert characters that could be used for XSS
  str = str.replace(/&/g, '&amp;')
           .replace(/</g, '&lt;')
           .replace(/>/g, '&gt;')
           .replace(/"/g, '&quot;')
           .replace(/'/g, '&#x27;')
           .replace(/\//g, '&#x2F;');

  // Remove meta tags
  str = str.replace(/<meta\b[^>]*>/gi, '');

  // Remove object/embed tags
  str = str.replace(/<(object|embed)\b[^>]*>(.*?)<\/\1>/gi, '');

  // Remove iframe tags
  str = str.replace(/<iframe\b[^>]*>(.*?)<\/iframe>/gi, '');

  // Remove base tags
  str = str.replace(/<base\b[^>]*>/gi, '');

  // Remove form tags
  str = str.replace(/<form\b[^>]*>(.*?)<\/form>/gi, '');

  // Remove style tags
  str = str.replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '');

  // Remove comments
  str = str.replace(/<!--[\s\S]*?-->/g, '');

  // Remove any remaining angle brackets
  str = str.replace(/<[^>]*>/g, '');

  return str;
}

