```javascript
function sanitizeShellCommand(command) {
  if (typeof command !== 'string') {
    throw new Error('Command must be a string');
  }

  // Remove null bytes
  command = command.replace(/\0/g, '');

  // Escape special characters
  command = command.replace(/(["\s'$`\\])/g, '\\$1');

  // Remove dangerous shell metacharacters
  command = command.replace(/[;&|><$]/g, '');

  // Remove newlines
  command = command.replace(/[\r\n]/g, '');

  // Remove multiple spaces
  command = command.replace(/\s+/g, ' ');

  // Trim whitespace
  command = command.trim();

  // Check for empty command
  if (!command) {
    throw new Error('Command cannot be empty');
  }

  // Basic path traversal prevention
  if (command.includes('..')) {
    throw new Error('Path traversal detected');
  }

  // Prevent command chaining
  const disallowedOperators = ['&&', '||', '|', ';', '`'];
  for (const operator of disallowedOperators) {
    if (command.includes(operator)) {
      throw new Error('Command chaining detected');
    }
  }

  // Check for environment variables
  if (command.match(/\$\w+/)) {
    throw new Error('Environment variables not allowed');
  }

  // Check for glob patterns
  if (command.match(/[\*\?]/)) {
    throw new Error('Glob patterns not allowed');
  }

  return command;
}

function buildCommand(command, args = []) {
  const sanitizedCommand = sanitizeShellCommand(command);
  const sanitizedArgs = args.map(arg => sanitizeShellCommand(arg.toString()));

  return `${sanitizedCommand} ${sanitizedArgs.join(' ')}`.trim();
}

// Example usage:
try {
  const safeCommand = buildCommand('ls', ['-l', '/home/user']);
  console.log(safeCommand);

  // These should throw errors:
  // buildCommand('rm -rf /', ['&', 'dangerous command']);
  // buildCommand('cat', ['file.txt; rm -rf /']);
  // buildCommand('echo', ['$HOME']);
  // buildCommand('find', ['*']);
} catch (error) {
  console.error('Error:', error.message);
}
