function sanitizeShellCommand(command) {
  if (typeof command !== 'string') {
    throw new Error('Command must be a string');
  }

  // Remove any null bytes
  command = command.replace(/\0/g, '');

  // Escape special characters
  const specialChars = /[&;`'"|*?~<>^()[\]{}$\\\x0A\xFF\r\n]/g;
  command = command.replace(specialChars, '\\$&');

  // Remove any multiple spaces
  command = command.replace(/\s+/g, ' ');

  // Trim whitespace
  command = command.trim();

  // Prevent command chaining
  if (command.includes('&&') || 
      command.includes('||') ||
      command.includes(';') ||
      command.includes('|')) {
    throw new Error('Command chaining is not allowed');
  }

  // Check for common dangerous commands
  const dangerousCommands = [
    'rm',
    'srm',
    'mkfs',
    'dd',
    'format',
    'shutdown',
    'reboot',
    'halt',
    ':(){:|:&};:',
    'chmod',
    'chown',
    'mv',
    '>()', 
    '<()'
  ];

  const commandStart = command.split(' ')[0].toLowerCase();
  if (dangerousCommands.includes(commandStart)) {
    throw new Error('Dangerous command detected');
  }

  // Prevent path traversal
  if (command.includes('../') || command.includes('..\\')) {
    throw new Error('Path traversal is not allowed');
  }

  // Prevent absolute paths
  if (command.startsWith('/') || /^[a-zA-Z]:\\/.test(command)) {
    throw new Error('Absolute paths are not allowed');
  }

  // Prevent environment variable expansion
  if (command.includes('$') || command.includes('%')) {
    throw new Error('Environment variable expansion is not allowed');
  }

  // Prevent backticks and $() for command substitution
  if (command.includes('`') || command.includes('$(')) {
    throw new Error('Command substitution is not allowed');
  }

  return command;
}

// Example usage:
try {
  const sanitized = sanitizeShellCommand('ls -la *.txt');
  console.log(sanitized);
} catch (error) {
  console.error('Error:', error.message);
}
