```javascript
function sanitizeShellCommand(command) {
  if (typeof command !== 'string') {
    throw new Error('Command must be a string');
  }

  // Remove null bytes
  command = command.replace(/\0/g, '');

  // Escape special characters
  command = command.replace(/(["\s'$`\\])/g, '\\$1');

  // Prevent command chaining
  command = command.replace(/[;&|]/g, '');

  // Remove newlines
  command = command.replace(/[\n\r]/g, ' ');

  // Remove multiple spaces
  command = command.replace(/\s+/g, ' ').trim();

  // Block dangerous commands
  const dangerousCommands = [
    'rm',
    'srm',
    'mkfs',
    'dd',
    'format',
    ':(){:|:&};:',
    'chmod',
    'chown',
    'kill',
    'pkill',
    'sudo',
    'su'
  ];

  const commandStart = command.split(' ')[0].toLowerCase();
  if (dangerousCommands.includes(commandStart)) {
    throw new Error('Dangerous command detected');
  }

  // Prevent path traversal
  if (command.includes('..')) {
    throw new Error('Path traversal detected');
  }

  // Prevent wildcards
  if (/[*?]/.test(command)) {
    throw new Error('Wildcards are not allowed');
  }

  // Prevent environment variable expansion
  if (/\$\w+/.test(command)) {
    throw new Error('Environment variable expansion not allowed');
  }

  // Check for balanced quotes
  let singleQuotes = 0;
  let doubleQuotes = 0;

  for (let char of command) {
    if (char === "'") singleQuotes++;
    if (char === '"') doubleQuotes++;
  }

  if (singleQuotes % 2 !== 0 || doubleQuotes % 2 !== 0) {
    throw new Error('Unbalanced quotes');
  }

  return command;
}
