function escape_shell(str) {
  if (!str) return '';

  // Convert to string if not already
  str = String(str);

  return str
    // Escape backslashes
    .replace(/\\/g, '\\\\')
    // Escape single quotes
    .replace(/'/g, '\\\'')
    // Escape double quotes  
    .replace(/"/g, '\\"')
    // Escape backticks
    .replace(/`/g, '\\`')
    // Escape $
    .replace(/\$/g, '\\$')
    // Escape !
    .replace(/!/g, '\\!')
    // Escape spaces
    .replace(/\s/g, '\\ ')
    // Escape newlines
    .replace(/\n/g, '\\\n')
    // Escape tabs
    .replace(/\t/g, '\\\t')
    // Escape pipes
    .replace(/\|/g, '\\|')
    // Escape angle brackets
    .replace(/[<>]/g, '\\$&')
    // Escape ampersand
    .replace(/&/g, '\\&')
    // Escape semicolon 
    .replace(/;/g, '\\;')
    // Escape parentheses
    .replace(/[()]/g, '\\$&')
    // Escape curly braces
    .replace(/[{}]/g, '\\$&')
    // Escape asterisk
    .replace(/\*/g, '\\*')
    // Escape question mark
    .replace(/\?/g, '\\?');
}
