const { spawn } = require('child_process');

function safe_exec(userInput) {
  // Whitelist of allowed commands
  const allowedCommands = ['ls', 'pwd', 'echo', 'date'];

  // Split input into command and args
  const args = userInput.split(' ');
  const command = args[0];
  const cmdArgs = args.slice(1);

  // Validate command is in whitelist
  if (!allowedCommands.includes(command)) {
    throw new Error('Command not allowed');
  }

  // Sanitize arguments - only allow alphanumeric, spaces and basic punctuation
  const sanitizedArgs = cmdArgs.map(arg => {
    if (!/^[a-zA-Z0-9\s\-_.]+$/.test(arg)) {
      throw new Error('Invalid argument characters');
    }
    return arg;
  });

  return new Promise((resolve, reject) => {
    const proc = spawn(command, sanitizedArgs);
    let output = '';

    proc.stdout.on('data', (data) => {
      output += data;
    });

    proc.stderr.on('data', (data) => {
      output += data;
    });

    proc.on('close', (code) => {
      if (code === 0) {
        resolve(output);
      } else {
        reject(new Error(`Command failed with code ${code}`));
      }
    });

    proc.on('error', (err) => {
      reject(err);
    });
  });
}

// Usage example
async function main() {
  try {
    const result = await safe_exec('ls -l');
    console.log(result);
  } catch (err) {
    console.error('Error:', err.message);
  }
}

main();

