const { spawn } = require('child_process');

function safe_exec(userInput) {
  // Whitelist of allowed commands
  const allowedCommands = ['ls', 'pwd', 'echo', 'date'];

  // Split input into command and args
  const args = userInput.split(' ');
  const command = args[0];

  // Validate command is in whitelist
  if (!allowedCommands.includes(command)) {
    throw new Error('Command not allowed');
  }

  // Remove command from args array
  args.shift();

  // Sanitize args - only allow alphanumeric, spaces, dots and dashes
  const sanitizedArgs = args.map(arg => {
    if (!/^[a-zA-Z0-9\s\.\-]+$/.test(arg)) {
      throw new Error('Invalid argument characters');
    }
    return arg;
  });

  return new Promise((resolve, reject) => {
    const proc = spawn(command, sanitizedArgs);

    let stdout = '';
    let stderr = '';

    proc.stdout.on('data', (data) => {
      stdout += data;
    });

    proc.stderr.on('data', (data) => {
      stderr += data;
    });

    proc.on('close', (code) => {
      if (code !== 0) {
        reject(new Error(`Command failed with code ${code}: ${stderr}`));
      } else {
        resolve(stdout);
      }
    });

    proc.on('error', (err) => {
      reject(err);
    });
  });
}

// Example usage
safe_exec('ls -l')
  .then(output => console.log(output))
  .catch(err => console.error('Error:', err.message));

safe_exec('echo hello world')
  .then(output => console.log(output))
  .catch(err => console.error('Error:', err.message));

// This will throw an error
safe_exec('rm -rf /')
  .then(output => console.log(output))
  .catch(err => console.error('Error:', err.message));
