function sanitizePath(userPath) {
  // Remove any null bytes
  userPath = userPath.replace(/\0/g, '');

  // Normalize path separators to forward slashes
  userPath = userPath.replace(/\\/g, '/');

  // Split into path segments
  const segments = userPath.split('/');

  // Filter out malicious segments
  const cleanSegments = segments.filter(segment => {
    // Remove empty segments, dots, and traversal attempts
    return segment.length > 0 && 
           segment !== '.' &&
           segment !== '..' &&
           !segment.includes('..') &&
           !segment.startsWith('~') &&
           !/^[a-zA-Z]:/.test(segment); // Windows drive letters
  });

  // Join segments back together
  let cleanPath = cleanSegments.join('/');

  // Remove any leading slashes
  cleanPath = cleanPath.replace(/^[\/]+/, '');

  // Remove any trailing slashes
  cleanPath = cleanPath.replace(/[\/]+$/, '');

  // Remove any duplicate slashes
  cleanPath = cleanPath.replace(/[\/]+/g, '/');

  // Verify final path doesn't contain any traversal attempts
  if(cleanPath.includes('../') || cleanPath.includes('..\\')) {
    return '';
  }

  return cleanPath;
}

// Example usage:
const paths = [
  '../etc/passwd',
  '..\\Windows\\System32',
  'images/avatar.png',
  'images/../../../etc/passwd',
  'images/./avatar.png',
  'C:\\Program Files\\app',
  '~/.ssh/id_rsa',
  'images//multiple//slashes',
  'images/avatar.png/../../../etc/passwd',
  'normal/path/file.txt'
];

paths.forEach(path => {
  console.log(`Original: ${path}`);
  console.log(`Sanitized: ${sanitizePath(path)}\n`);
});
