```javascript
function sanitizePath(userPath) {
  // Remove null bytes
  userPath = userPath.replace(/\0/g, '');

  // Normalize path separators to forward slashes
  userPath = userPath.replace(/\\/g, '/');

  // Split path into segments
  const segments = userPath.split('/');

  // Filter out malicious segments
  const cleanSegments = segments.filter(segment => {
    // Remove empty segments and current directory markers
    if (!segment || segment === '.') {
      return false;
    }

    // Remove parent directory markers
    if (segment === '..') {
      return false;
    }

    // Remove hidden files/directories (starting with .)
    if (segment.startsWith('.')) {
      return false;
    }

    // Only allow alphanumeric chars, dash and underscore
    if (!/^[a-zA-Z0-9-_]+$/.test(segment)) {
      return false;
    }

    return true;
  });

  // Join segments back together
  let sanitizedPath = cleanSegments.join('/');

  // Ensure path doesn't start with slash
  sanitizedPath = sanitizedPath.replace(/^\/+/, '');

  // Ensure path doesn't end with slash
  sanitizedPath = sanitizedPath.replace(/\/+$/, '');

  // Return empty string if nothing valid remains
  if (!sanitizedPath) {
    return '';
  }

  return sanitizedPath;
}

