```javascript
function sanitizePath(userPath) {
    // Remove null bytes
    userPath = userPath.replace(/\0/g, '');

    // Convert to posix path
    userPath = userPath.replace(/\\/g, '/');

    // Remove multiple slashes
    userPath = userPath.replace(/\/+/g, '/');

    // Split path into segments
    const parts = userPath.split('/');

    // Filter segments
    const sanitizedParts = parts.filter(part => {
        // Remove empty parts, dots and dot-dots
        return part.length > 0 && 
               part !== '.' &&
               part !== '..' &&
               !part.match(/^\.{3,}$/);
    });

    // Ensure no parts contain invalid characters
    const validParts = sanitizedParts.map(part => {
        // Remove any non-alphanumeric chars except - and _
        return part.replace(/[^a-zA-Z0-9\-_]/g, '');
    });

    // Join parts back together
    let sanitized = validParts.join('/');

    // Ensure path doesn't start with slash
    sanitized = sanitized.replace(/^\/+/, '');

    // Ensure path doesn't end with slash
    sanitized = sanitized.replace(/\/+$/, '');

    return sanitized;
}

// Additional helper to join with base path safely
function safeJoinPath(basePath, userPath) {
    const sanitized = sanitizePath(userPath);
    if (!sanitized) {
        return basePath;
    }
    return `${basePath}/${sanitized}`;
}

