const path = require('path');

function secure_path(user_path) {
  // Normalize and resolve the path
  const normalized = path.normalize(user_path);
  const resolved = path.resolve(normalized);

  // Check if path tries to traverse up directories
  if (normalized.includes('../') || normalized.includes('..\\')) {
    throw new Error('Path traversal not allowed');
  }

  // Only allow certain file extensions
  const ext = path.extname(normalized).toLowerCase();
  const allowedExts = ['.txt', '.jpg', '.png', '.pdf'];
  if (!allowedExts.includes(ext)) {
    throw new Error('File extension not allowed');
  }

  // Set base directory that files must be under
  const baseDir = '/safe/files/dir/';
  if (!resolved.startsWith(baseDir)) {
    throw new Error('Path must be under base directory');
  }

  return resolved;
}

