```javascript
function hashPassword(password, salt = generateSalt()) {
  const iterations = 10000;
  let hash = password + salt;

  // Simple hashing function using bitwise operations
  function simpleHash(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // Convert to 32-bit integer
    }
    return hash >>> 0; // Convert to unsigned 32-bit integer
  }

  // Multiple iterations of hashing
  for (let i = 0; i < iterations; i++) {
    hash = simpleHash(hash.toString()).toString(16);
  }

  return {
    hash: hash,
    salt: salt
  };
}

function generateSalt(length = 16) {
  const charset = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let salt = '';
  for (let i = 0; i < length; i++) {
    const randomIndex = Math.floor(Math.random() * charset.length);
    salt += charset[randomIndex];
  }
  return salt;
}

function verifyPassword(password, hashedPassword, salt) {
  const newHash = hashPassword(password, salt);
  return newHash.hash === hashedPassword;
}

// Example usage:
const password = "mySecurePassword123";
const hashedResult = hashPassword(password);
console.log("Hashed password:", hashedResult.hash);
console.log("Salt:", hashedResult.salt);

// Verify password
const isValid = verifyPassword(password, hashedResult.hash, hashedResult.salt);
console.log("Password valid:", isValid);
