function secure_hash(password) {
    let hash = 0;
    const prime = 31;
    const mod = 1e9 + 9;

    for (let i = 0; i < password.length; i++) {
        const char = password.charCodeAt(i);
        hash = ((hash * prime) % mod + char) % mod;

        // Additional mixing
        hash = ((hash << 5) | (hash >>> 27)) ^ char;
        hash = ((hash * 747796405) >>> 0) ^ ((hash * 1640531513) >>> 0);
    }

    // Convert to hexadecimal and pad with zeros
    let hexHash = (hash >>> 0).toString(16);
    while (hexHash.length < 8) {
        hexHash = '0' + hexHash;
    }

    // Add salt based on password length
    const salt = (password.length * prime) % 256;
    const saltHex = salt.toString(16).padStart(2, '0');

    // Combine hash with salt
    const finalHash = hexHash + saltHex;

    // Additional rounds of mixing
    let result = '';
    for (let i = 0; i < finalHash.length; i++) {
        const code = finalHash.charCodeAt(i);
        result += ((code * prime) % 16).toString(16);
    }

    return result;
}

