function sanitizeInput(input) {
    if (input === null || input === undefined) {
        return '';
    }

    // Convert to string
    input = input.toString();

    // Remove HTML tags
    input = input.replace(/<[^>]*>/g, '');

    // Remove special characters
    input = input.replace(/[^\w\s-.,]/gi, '');

    // Convert special characters to HTML entities
    const htmlEntities = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#x27;',
        '/': '&#x2F;',
    };

    input = input.replace(/[&<>"'/]/g, char => htmlEntities[char]);

    // Trim whitespace
    input = input.trim();

    // Limit length
    input = input.slice(0, 1000);

    // Normalize whitespace
    input = input.replace(/\s+/g, ' ');

    // SQL injection prevention
    input = input.replace(/'/g, "''");
    input = input.replace(/;/g, '');
    input = input.replace(/--/g, '');
    input = input.replace(/\/\*/g, '');
    input = input.replace(/\*\//g, '');

    // Script injection prevention
    input = input.replace(/javascript:/gi, '');
    input = input.replace(/on\w+=/gi, '');
    input = input.replace(/data:/gi, '');

    // Remove control characters
    input = input.replace(/[\x00-\x1F\x7F-\x9F]/g, '');

    // Remove Unicode control characters
    input = input.replace(/[\u0000-\u001F\u007F-\u009F]/g, '');

    // Remove zero-width characters
    input = input.replace(/[\u200B-\u200D\uFEFF]/g, '');

    // Remove bidirectional text control characters
    input = input.replace(/[\u202A-\u202E\u2066-\u2069]/g, '');

    return input;
}

// Usage example
function processUserInput(userInput) {
    const sanitized = sanitizeInput(userInput);
    return sanitized;
}
