```javascript
function sanitizeInput(input) {
    if (input === null || input === undefined) {
        return '';
    }

    // Convert to string
    input = input.toString();

    // Remove HTML tags
    input = input.replace(/<[^>]*>/g, '');

    // Convert special characters to HTML entities
    input = input.replace(/&/g, '&amp;')
                 .replace(/</g, '&lt;')
                 .replace(/>/g, '&gt;')
                 .replace(/"/g, '&quot;')
                 .replace(/'/g, '&#x27;')
                 .replace(/\//g, '&#x2F;');

    // Remove control characters and invisible characters
    input = input.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g, '');

    // Trim whitespace
    input = input.trim();

    // Remove multiple spaces
    input = input.replace(/\s+/g, ' ');

    // Remove potentially dangerous characters
    input = input.replace(/[^\w\s-.,]/g, '');

    // Remove SQL injection attempts
    input = input.replace(/(\b)(on\S+)(\s*)=/g, '')
                 .replace(/javascript:/g, '')
                 .replace(/[\(\)\[\]\{\}]/g, '')
                 .replace(/select|insert|update|delete|drop|union|exec|eval/gi, '');

    // Limit length
    const MAX_LENGTH = 1000;
    input = input.substring(0, MAX_LENGTH);

    return input;
}

// Additional function to sanitize objects and arrays recursively
function deepSanitize(data) {
    if (Array.isArray(data)) {
        return data.map(item => deepSanitize(item));
    }

    if (typeof data === 'object' && data !== null) {
        const sanitizedObj = {};
        for (let key in data) {
            if (data.hasOwnProperty(key)) {
                // Sanitize both keys and values
                const sanitizedKey = sanitizeInput(key);
                sanitizedObj[sanitizedKey] = deepSanitize(data[key]);
            }
        }
        return sanitizedObj;
    }

    if (typeof data === 'string') {
        return sanitizeInput(data);
    }

    return data;
}

// URL parameter sanitizer
function sanitizeUrlParams(url) {
    try {
        const urlObj = new URL(url);
        const params = new URLSearchParams(urlObj.search);
        const sanitizedParams = new URLSearchParams();

        for (let [key, value] of params) {
            sanitizedParams.append(sanitizeInput(key), sanitizeInput(value));
        }

        urlObj.search = sanitizedParams.toString();
        return urlObj.toString();
    } catch (e) {
        return '';
    }
}

// Email sanitizer
function sanitizeEmail(email) {
    if (!email) return '';

    email = email.toString().toLowerCase().trim();

    // Basic email format check
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) return '';

    // Remove anything that's not allowed in an email
    email = email.replace(/[^a-z0-9@._-]/g, '');

    return email;
}

// Number sanitizer
function sanitizeNumber(num) {
    if (num === null || num === undefined) return 0;

    // Convert to string and remove anything that's not a number or decimal point
    const cleaned = num.toString().replace(/[^\d.-]/g, '');

    // Convert back to number
    const result = parseFloat(cleaned);

    return isNaN(result) ? 0 : result;
}
