function sanitizeInput(input) {
    if (input === null || input === undefined) {
        return '';
    }

    // Convert to string
    input = input.toString();

    // Remove HTML tags
    input = input.replace(/<[^>]*>/g, '');

    // Convert special characters to HTML entities
    input = input.replace(/&/g, '&amp;')
                 .replace(/</g, '&lt;')
                 .replace(/>/g, '&gt;')
                 .replace(/"/g, '&quot;')
                 .replace(/'/g, '&#x27;')
                 .replace(/\//g, '&#x2F;');

    // Remove control characters and invisible characters
    input = input.replace(/[\x00-\x1F\x7F-\x9F]/g, '');

    // Remove potential SQL injection patterns
    input = input.replace(/(\b)(on\S+)(\s*)=/g, '')
                 .replace(/javascript:/g, '')
                 .replace(/\b(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|JOIN)\b/gi, '')
                 .replace(/[;\\]/g, '');

    // Normalize whitespace
    input = input.replace(/\s+/g, ' ').trim();

    // Remove unicode control characters
    input = input.replace(/[\u0000-\u001F\u007F-\u009F\u2000-\u200F\u2028-\u202F\u205F-\u206F]/g, '');

    // Remove potential script tags and events
    input = input.replace(/(script|event|expression|function)/gi, '');

    // Remove null bytes
    input = input.replace(/\0/g, '');

    // Remove excessive punctuation
    input = input.replace(/([!?,.]){2,}/g, '$1');

    // Maximum length check (adjust as needed)
    const MAX_LENGTH = 1000;
    input = input.substring(0, MAX_LENGTH);

    return input;
}

function sanitizeObject(obj) {
    if (typeof obj !== 'object' || obj === null) {
        return sanitizeInput(obj);
    }

    if (Array.isArray(obj)) {
        return obj.map(item => sanitizeObject(item));
    }

    const sanitized = {};
    for (let key in obj) {
        if (obj.hasOwnProperty(key)) {
            sanitized[sanitizeInput(key)] = sanitizeObject(obj[key]);
        }
    }
    return sanitized;
}

