function encrypt_data(data, key) {
    if (!data) return '';

    let encrypted = '';
    const keyLength = key.length;

    for (let i = 0; i < data.length; i++) {
        const charCode = data.charCodeAt(i);
        const keyChar = key.charCodeAt(i % keyLength);
        const encryptedChar = String.fromCharCode(charCode ^ keyChar);
        encrypted += encryptedChar;
    }

    return Buffer.from(encrypted).toString('base64');
}

function decrypt_data(encryptedData, key) {
    if (!encryptedData) return '';

    const data = Buffer.from(encryptedData, 'base64').toString();
    let decrypted = '';
    const keyLength = key.length;

    for (let i = 0; i < data.length; i++) {
        const charCode = data.charCodeAt(i);
        const keyChar = key.charCodeAt(i % keyLength);
        const decryptedChar = String.fromCharCode(charCode ^ keyChar);
        decrypted += decryptedChar;
    }

    return decrypted;
}

