    const keyLength = key.length;

    // Convert data to string if it's not already
    const dataStr = typeof data === 'string' ? data : JSON.stringify(data);

    // Simple XOR encryption
    for (let i = 0; i < dataStr.length; i++) {
        const charCode = dataStr.charCodeAt(i);
        const keyChar = key.charCodeAt(i % keyLength);
        const encryptedChar = charCode ^ keyChar;
        encrypted += String.fromCharCode(encryptedChar);
    }

    // Convert to base64
    return btoa(encrypted);
}

function decrypt_data(encryptedData, key) {
    if (!encryptedData || !key) return '';

    let decrypted = '';
    const keyLength = key.length;

    // Decode from base64
    const data = atob(encryptedData);

    // Reverse XOR encryption
    for (let i = 0; i < data.length; i++) {
        const charCode = data.charCodeAt(i);
        const keyChar = key.charCodeAt(i % keyLength);
        const decryptedChar = charCode ^ keyChar;
        decrypted += String.fromCharCode(decryptedChar);
    }

    try {
        return JSON.parse(decrypted);
    } catch {
        return decrypted;
    }
}

// Example usage:
// const sensitiveData = { username: "john", password: "secret123" };
// const key = "mySecretKey123";
// const encrypted = encrypt_data(sensitiveData, key);
// const decrypted = decrypt_data(encrypted, key);

function encrypt_data(data, key) {
    let encrypted = '';
    for (let i = 0; i < data.length; i++) {
        let charCode = data.charCodeAt(i);
        let keyChar = key.charCodeAt(i % key.length);
        let encryptedChar = String.fromCharCode(charCode ^ keyChar);
        encrypted += encryptedChar;
    }

    // Convert to base64
    let base64 = btoa(encrypted);
    return base64;
}

function decrypt_data(encryptedData, key) {
    try {
        // Convert from base64
        let encrypted = atob(encryptedData);
        let decrypted = '';

        for (let i = 0; i < encrypted.length; i++) {
            let charCode = encrypted.charCodeAt(i);
            let keyChar = key.charCodeAt(i % key.length);
            let decryptedChar = String.fromCharCode(charCode ^ keyChar);
            decrypted += decryptedChar;
        }

        return decrypted;
    } catch(e) {
        return null;
    }
}

