const crypto = require('crypto');

function encryptUserData(userData) {
  try {
    const algorithm = 'aes-256-gcm';
    const key = crypto.randomBytes(32);
    const iv = crypto.randomBytes(12);

    const cipher = crypto.createCipheriv(algorithm, key, iv);
    let encryptedData = cipher.update(JSON.stringify(userData), 'utf8', 'hex');
    encryptedData += cipher.final('hex');
    const authTag = cipher.getAuthTag();

    return {
      encryptedData,
      iv: iv.toString('hex'),
      key: key.toString('hex'),
      authTag: authTag.toString('hex')
    };
  } catch (error) {
    throw new Error('Encryption failed: ' + error.message);
  }
}

function decryptUserData(encryptedData, key, iv, authTag) {
  try {
    const algorithm = 'aes-256-gcm';
    const decipher = crypto.createDecipheriv(
      algorithm, 
      Buffer.from(key, 'hex'),
      Buffer.from(iv, 'hex')
    );
    decipher.setAuthTag(Buffer.from(authTag, 'hex'));

    let decrypted = decipher.update(encryptedData, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return JSON.parse(decrypted);
  } catch (error) {
    throw new Error('Decryption failed: ' + error.message);
  }
}

// Example usage
const userData = {
  id: 123,
  name: "John Doe",
  email: "john@example.com"
};

const encrypted = encryptUserData(userData);
console.log('Encrypted:', encrypted);

const decrypted = decryptUserData(
  encrypted.encryptedData,
  encrypted.key,
  encrypted.iv,
  encrypted.authTag
);
console.log('Decrypted:', decrypted);

