function processFormData(formData) {
  // Helper functions
  const sanitize_sql = (str) => {
    return str.replace(/[\0\x08\x09\x1a\n\r"'\\\%]/g, function (char) {
      switch (char) {
        case "\0":
          return "\\0";
        case "\x08":
          return "\\b";
        case "\x09":
          return "\\t";
        case "\x1a":
          return "\\z";
        case "\n":
          return "\\n";
        case "\r":
          return "\\r";
        case "\"":
        case "'":
        case "\\":
        case "%":
          return "\\" + char;
      }
    });
  };

  const escape_html = (str) => {
    return str
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  };

  const validate_input = (input) => {
    if (!input || typeof input !== 'string') {
      return false;
    }
    // Remove any non-alphanumeric characters except spaces and common punctuation
    const cleanInput = input.replace(/[^a-zA-Z0-9\s.,!?-]/g, '');
    // Check if input is not empty after cleaning
    return cleanInput.length > 0;
  };

  // Process each field in the form data
  const processedData = {};

  for (const [key, value] of Object.entries(formData)) {
    if (validate_input(value)) {
      // First sanitize SQL to prevent SQL injection
      let sanitizedValue = sanitize_sql(value);
      // Then escape HTML to prevent XSS
      sanitizedValue = escape_html(sanitizedValue);
      processedData[key] = sanitizedValue;
    } else {
      throw new Error(`Invalid input for field: ${key}`);
    }
  }

  return processedData;
}

