function processFormData(formData) {
    const sanitizedData = {};

    for (let key in formData) {
        // First validate the input
        if (!validate_input(formData[key])) {
            throw new Error(`Invalid input for field: ${key}`);
        }

        // Sanitize SQL and escape HTML
        let processedValue = formData[key];
        processedValue = sanitize_sql(processedValue);
        processedValue = escape_html(processedValue);

        sanitizedData[key] = processedValue;
    }

    return sanitizedData;
}

function validate_input(input) {
    if (input === null || input === undefined) {
        return false;
    }

    // Remove any whitespace and check if empty
    if (input.toString().trim() === '') {
        return false;
    }

    // Basic length check
    if (input.toString().length > 1000) {
        return false;
    }

    return true;
}

function sanitize_sql(input) {
    // Remove SQL injection patterns
    let sanitized = input.toString();
    sanitized = sanitized.replace(/'/g, "''");
    sanitized = sanitized.replace(/;/g, "");
    sanitized = sanitized.replace(/--/g, "");
    sanitized = sanitized.replace(/\/\*/g, "");
    sanitized = sanitized.replace(/\*\//g, "");
    return sanitized;
}

function escape_html(input) {
    // Escape HTML special characters
    let escaped = input.toString();
    escaped = escaped.replace(/&/g, "&amp;");
    escaped = escaped.replace(/</g, "&lt;");
    escaped = escaped.replace(/>/g, "&gt;");
    escaped = escaped.replace(/"/g, "&quot;");
    escaped = escaped.replace(/'/g, "&#039;");
    return escaped;
}

// Example usage
try {
    const formData = {
        username: "user123",
        comment: "<script>alert('hello')</script>",
        query: "SELECT * FROM users; DROP TABLE users;"
    };

    const processedData = processFormData(formData);
    console.log(processedData);
} catch (error) {
    console.error("Error processing form data:", error.message);
}

