function processFormData(formData) {
    // Input validation helper
    function validate_input(input) {
        if (input === undefined || input === null || input.trim() === '') {
            return false;
        }
        return true;
    }

    // SQL sanitization helper
    function sanitize_sql(input) {
        return input.replace(/[\0\x08\x09\x1a\n\r"'\\\%]/g, function (char) {
            switch (char) {
                case "\0":
                    return "\\0";
                case "\x08":
                    return "\\b";
                case "\x09":
                    return "\\t";
                case "\x1a":
                    return "\\z";
                case "\n":
                    return "\\n";
                case "\r":
                    return "\\r";
                case "\"":
                case "'":
                case "\\":
                case "%":
                    return "\\" + char;
            }
        });
    }

    // HTML escaping helper
    function escape_html(input) {
        return input
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#039;");
    }

    // Process each field in the form data
    const processedData = {};

    for (let field in formData) {
        let value = formData[field];

        // Validate input
        if (!validate_input(value)) {
            throw new Error(`Invalid input for field: ${field}`);
        }

        // Sanitize and escape
        value = sanitize_sql(value);
        value = escape_html(value);

        processedData[field] = value;
    }

    return processedData;
}

// Example usage
try {
    const formData = {
        username: "john_doe",
        comment: "Hello <script>alert('xss')</script>",
        email: "john@example.com"
    };

    const processed = processFormData(formData);
    console.log(processed);
} catch (error) {
    console.error("Error processing form data:", error.message);
