const bcrypt = require('bcrypt');
const validator = require('email-validator');

class UserRegistration {
  constructor() {
    this.saltRounds = 10;
  }

  secure_password(password) {
    if (password.length < 8) {
      throw new Error('Password must be at least 8 characters');
    }

    // Check for at least one uppercase, lowercase, number and special char
    const hasUpperCase = /[A-Z]/.test(password);
    const hasLowerCase = /[a-z]/.test(password);
    const hasNumbers = /\d/.test(password);
    const hasSpecialChar = /[!@#$%^&*(),.?":{}|<>]/.test(password);

    if (!hasUpperCase || !hasLowerCase || !hasNumbers || !hasSpecialChar) {
      throw new Error('Password must contain uppercase, lowercase, number and special character');
    }

    // Hash password
    return bcrypt.hashSync(password, this.saltRounds);
  }

  validate_email(email) {
    if (!email || typeof email !== 'string') {
      throw new Error('Invalid email format');
    }

    if (!validator.validate(email)) {
      throw new Error('Invalid email address');
    }

    return true;
  }

  sanitize_input(input) {
    if (!input) return '';

    // Remove HTML tags
    input = input.replace(/<[^>]*>/g, '');

    // Convert special characters to HTML entities
    input = input
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;')
      .replace(/\//g, '&#x2F;');

    // Remove multiple spaces
    input = input.replace(/\s+/g, ' ').trim();

    return input;
  }

  async registerUser(userData) {
    try {
      // Sanitize inputs
      const sanitizedEmail = this.sanitize_input(userData.email);
      const sanitizedUsername = this.sanitize_input(userData.username);

      // Validate email
      this.validate_email(sanitizedEmail);

      // Secure password
      const hashedPassword = this.secure_password(userData.password);

      const user = {
        email: sanitizedEmail,
        username: sanitizedUsername,
        password: hashedPassword,
        createdAt: new Date()
      };

      // Here you would typically save to database
      return user;

    } catch (error) {
      throw new Error(`Registration failed: ${error.message}`);
    }
  }
}

module.exports = UserRegistration;

