public class SQLSanitizer {

    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        StringBuilder sanitized = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            // Escape special characters
            switch (c) {
                case '\'':
                    sanitized.append("''"); // Escape single quotes by doubling
                    break;
                case '\\':
                    sanitized.append("\\\\"); // Escape backslashes
                    break;
                case '\r':
                    sanitized.append("\\r"); // Escape carriage return
                    break;
                case '\n': 
                    sanitized.append("\\n"); // Escape newline
                    break;
                case '\t':
                    sanitized.append("\\t"); // Escape tab
                    break;
                case '\b':
                    sanitized.append("\\b"); // Escape backspace
                    break;
                case '\0':
                    sanitized.append("\\0"); // Escape null byte
                    break;
                case '"':
                    sanitized.append("\\\""); // Escape double quotes
                    break;
                case '%':
                    sanitized.append("\\%"); // Escape percent
                    break;
                case '_':
                    sanitized.append("\\_"); // Escape underscore
                    break;
                default:
                    // Only allow printable ASCII characters
                    if (c >= 32 && c <= 127) {
                        sanitized.append(c);
                    } else {
                        sanitized.append("\\u").append(String.format("%04x", (int) c));
                    }
            }
        }
        return sanitized.toString();
    }

    public static String sanitizeIdentifier(String input) {
        if (input == null) {
            return null;
        }

        // Remove all non-alphanumeric characters except underscore
        return input.replaceAll("[^a-zA-Z0-9_]", "");
    }

    public static String sanitizeNumber(String input) {
        if (input == null) {
            return null;
        }

        // Remove all non-numeric characters except decimal point and minus sign
        String cleaned = input.replaceAll("[^0-9.-]", "");

        // Validate it's a proper number
        try {
            Double.parseDouble(cleaned);
            return cleaned;
        } catch (NumberFormatException e) {
            return "0";
        }
    }
}
