public class HtmlSanitizer {
    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        StringBuilder sanitized = new StringBuilder();
        boolean inTag = false;
        boolean inAttribute = false;
        char attributeQuote = 0;

        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            if (c == '<') {
                inTag = true;
                continue;
            }

            if (inTag) {
                if (c == '>') {
                    inTag = false;
                    inAttribute = false;
                    attributeQuote = 0;
                } else if (c == '"' || c == '\'') {
                    if (inAttribute) {
                        if (c == attributeQuote) {
                            inAttribute = false;
                            attributeQuote = 0;
                        }
                    } else {
                        inAttribute = true;
                        attributeQuote = c;
                    }
                }
                continue;
            }

            if (c == '&') {
                sanitized.append("&amp;");
                continue;
            }

            if (c == '"') {
                sanitized.append("&quot;");
                continue;
            }

            if (c == '\'') {
                sanitized.append("&#x27;");
                continue;
            }

            if (c == '<') {
                sanitized.append("&lt;");
                continue;
            }

            if (c == '>') {
                sanitized.append("&gt;");
                continue;
            }

            if (c == '/') {
                sanitized.append("&#x2F;");
                continue;
            }

            // Only allow printable ASCII characters
            if (c >= 32 && c <= 126) {
                sanitized.append(c);
            }
        }

        return sanitized.toString();
    }

    public static String stripAllTags(String input) {
        if (input == null) {
            return null;
        }

        // Remove all HTML tags
        return input.replaceAll("<[^>]*>", "");
    }

    public static String allowSafeTags(String input, String[] safeTags) {
        if (input == null) {
            return null;
        }

        // First sanitize the input
        String sanitized = sanitize(input);

        // Create regex pattern for safe tags
        StringBuilder pattern = new StringBuilder();
        pattern.append("(?i)</?(?!");
        for (int i = 0; i < safeTags.length; i++) {
            if (i > 0) {
                pattern.append("|");
            }
            pattern.append(safeTags[i]);
        }
        pattern.append(")[^>]*>");

        // Remove all tags except safe ones
        return sanitized.replaceAll(pattern.toString(), "");
    }

