public class HtmlSanitizer {
    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        // Replace potentially dangerous characters
        StringBuilder sanitized = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '<':
                    sanitized.append("&lt;");
                    break;
                case '>':
                    sanitized.append("&gt;");
                    break;
                case '"':
                    sanitized.append("&quot;");
                    break;
                case '\'':
                    sanitized.append("&#x27;");
                    break;
                case '&':
                    sanitized.append("&amp;");
                    break;
                case '/':
                    sanitized.append("&#x2F;");
                    break;
                default:
                    // Only allow printable ASCII characters
                    if (isPrintableAscii(c)) {
                        sanitized.append(c);
                    }
                    break;
            }
        }

        // Remove potential JavaScript events
        String result = sanitized.toString();
        result = removeJavaScriptEvents(result);

        // Remove CSS expressions
        result = removeCssExpressions(result);

        return result;
    }

    private static boolean isPrintableAscii(char c) {
        return c >= 32 && c <= 126;
    }

    private static String removeJavaScriptEvents(String input) {
        String[] events = {
            "onabort", "onblur", "onchange", "onclick", "ondblclick", 
            "onerror", "onfocus", "onkeydown", "onkeypress", "onkeyup", 
            "onload", "onmousedown", "onmousemove", "onmouseout", 
            "onmouseover", "onmouseup", "onreset", "onresize", 
            "onselect", "onsubmit", "onunload"
        };

        String result = input.toLowerCase();
        for (String event : events) {
            result = result.replaceAll(event, "");
        }
        return result;
    }

    private static String removeCssExpressions(String input) {
        return input.replaceAll("expression\\s*\\(", "")
                   .replaceAll("javascript:", "")
                   .replaceAll("vbscript:", "")
                   .replaceAll("mocha:", "")
                   .replaceAll("livescript:", "");
    }

    // Example usage
    public static void main(String[] args) {
        String unsafeHtml = "<script>alert('XSS')</script><img src=\"javascript:alert('XSS')\" onclick=\"evil()\"/>";
        String safeHtml = sanitize(unsafeHtml);
        System.out.println("Sanitized HTML: " + safeHtml);
    }
}
