public class HTMLSanitizer {
    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        // Remove script tags and content
        input = input.replaceAll("(?i)<script.*?>.*?</script.*?>", "");

        // Remove style tags and content
        input = input.replaceAll("(?i)<style.*?>.*?</style.*?>", "");

        // Remove event handlers
        input = input.replaceAll("(?i)\\son\\w+\\s*=", "");

        // Remove javascript: protocol
        input = input.replaceAll("(?i)javascript:", "");

        // Remove data: protocol 
        input = input.replaceAll("(?i)data:", "");

        // Remove vbscript: protocol
        input = input.replaceAll("(?i)vbscript:", "");

        // Convert < and > to entities
        input = input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;");

        // Convert quotes to entities
        input = input.replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#x27;");

        // Convert backslash to entity
        input = input.replaceAll("\\\\", "&#x5C;");

        // Remove iframe tags
        input = input.replaceAll("(?i)<iframe.*?>.*?</iframe.*?>", "");

        // Remove object tags
        input = input.replaceAll("(?i)<object.*?>.*?</object.*?>", "");

        // Remove embed tags
        input = input.replaceAll("(?i)<embed.*?>.*?</embed.*?>", "");

        // Remove base tags
        input = input.replaceAll("(?i)<base.*?>", "");

        // Remove meta tags
        input = input.replaceAll("(?i)<meta.*?>", "");

        // Remove link tags
        input = input.replaceAll("(?i)<link.*?>", "");

        // Remove form tags
        input = input.replaceAll("(?i)<form.*?>.*?</form.*?>", "");

        // Remove eval and similar functions
        input = input.replaceAll("(?i)eval\\(.*?\\)", "");
        input = input.replaceAll("(?i)expression\\(.*?\\)", "");

        // Remove comments
        input = input.replaceAll("<!--.*?-->", "");

        return input;
    }

    public static String sanitizeAllowBasicFormatting(String input) {
        if (input == null) {
            return null;
        }

        // First apply basic sanitization
        input = sanitize(input);

        // Allow specific HTML tags
        String[] allowedTags = {"b", "i", "u", "p", "br", "hr", "h1", "h2", "h3", "h4", "h5", "h6"};

        for (String tag : allowedTags) {
            // Replace encoded tags back
            input = input.replaceAll("(?i)&lt;" + tag + "&gt;", "<" + tag + ">");
            input = input.replaceAll("(?i)&lt;/" + tag + "&gt;", "</" + tag + ">");
        }

        return input;
    }

    public static String stripAllTags(String input) {
        if (input == null) {
            return null;
        }

        // Remove all HTML tags
        return input.replaceAll("<[^>]*>", "");
    }

