public class HtmlSanitizer {
    private static final PolicyFactory policy = new HtmlPolicyBuilder()
        .allowElements("b", "i", "p", "br")
        .allowCommonBlockElements()
        .allowCommonInlineFormattingElements()
        .toFactory();

