// Import required packages
import org.apache.commons.lang3.StringEscapeUtils;
import javax.servlet.http.HttpServletRequest;

public class XSSPrevention {

    public String prevent_xss(String input) {
        // Escape HTML special characters
        return StringEscapeUtils.escapeHtml4(input);
    }

    public void processUserInput(HttpServletRequest request) {
        // Get user input from request
        String userInput = request.getParameter("userInput");

        // Apply XSS prevention before rendering
        String safeInput = prevent_xss(userInput);

        // Now safe to render safeInput to the page
        request.setAttribute("safeInput", safeInput);
    }
}

