    public void renderToPage(String userInput) {
        // Sanitize input before rendering
        String safeInput = prevent_xss(userInput);

        // Now safe to render to page
        System.out.println(safeInput);
    }

    public static void main(String[] args) {
        XSSPrevention xss = new XSSPrevention();

        // Example user input
        String userInput = "<script>alert('xss')</script>";

        // Render sanitized input
        xss.renderToPage(userInput);
    }
