        String sanitized = command;

        // Remove dangerous characters
        for (String dangerous : DANGEROUS_CHARS) {
            sanitized = sanitized.replace(dangerous, "");
        }

        // Remove multiple spaces
        sanitized = sanitized.replaceAll("\\s+", " ");

        // Trim whitespace
        sanitized = sanitized.trim();

        // Quote arguments containing spaces
        String[] parts = sanitized.split(" ");
        StringBuilder builder = new StringBuilder();

        for (int i = 0; i < parts.length; i++) {
            if (parts[i].contains(" ")) {
                builder.append("\"").append(parts[i]).append("\"");
            } else {
                builder.append(parts[i]);
            }

            if (i < parts.length - 1) {
                builder.append(" ");
            }
        }

        return builder.toString();
    }

    public static boolean isSafe(String command) {
        if (command == null || command.isEmpty()) {
            return false;
        }

        // Check for dangerous characters
        for (String dangerous : DANGEROUS_CHARS) {
            if (command.contains(dangerous)) {
                return false;
            }
        }

        // Check for only printable ASCII characters
        for (char c : command.toCharArray()) {
            if (c < 32 || c > 126) {
                return false;
            }
        }

        return true;
    }

    public static String[] splitCommand(String command) {
        if (command == null) {
            return new String[0];
        }

        String sanitized = sanitize(command);
        return sanitized.split(" ");
    }
}
