public class ShellCommandSanitizer {
    private static final String[] DANGEROUS_CHARS = {";", "|", "&", ">", "<", "`", "$", "(", ")", "{", "}", "[", "]", "\\", "\n", "\r"};

    public static String sanitize(String input) {
        if (input == null) {
            return "";
        }

        // Remove dangerous characters
        String sanitized = input;
        for (String dangerousChar : DANGEROUS_CHARS) {
            sanitized = sanitized.replace(dangerousChar, "");
        }

        // Remove quotes
        sanitized = sanitized.replace("\"", "");
        sanitized = sanitized.replace("'", "");

        // Trim whitespace
        sanitized = sanitized.trim();

        // Replace multiple spaces with single space
        sanitized = sanitized.replaceAll("\\s+", " ");

        // Only allow alphanumeric chars and some safe special chars
        sanitized = sanitized.replaceAll("[^a-zA-Z0-9\\s\\-_.,/]", "");

        // Prevent command injection by ensuring no -- or // sequences
        sanitized = sanitized.replace("--", "");
        sanitized = sanitized.replace("//", "/");

        return sanitized;
    }

    public static boolean isSafe(String input) {
        if (input == null) {
            return false;
        }

        // Check for dangerous characters
        for (String dangerousChar : DANGEROUS_CHARS) {
            if (input.contains(dangerousChar)) {
                return false;
            }
        }

        // Check for quotes
        if (input.contains("\"") || input.contains("'")) {
            return false;
        }

        // Check for multiple consecutive dots (could traverse directories)
        if (input.contains("..")) {
            return false;
        }

        // Check for non-alphanumeric chars except allowed special chars
        if (!input.matches("^[a-zA-Z0-9\\s\\-_.,/]*$")) {
            return false;
        }

        return true;
    }

    public static String[] sanitizeArray(String[] args) {
        if (args == null) {
            return new String[0];
        }

        String[] sanitized = new String[args.length];
        for (int i = 0; i < args.length; i++) {
            sanitized[i] = sanitize(args[i]);
        }

        return sanitized;
    }
}
