public class ShellCommandSanitizer {
    private static final String[] DANGEROUS_CHARS = {"|", "&", ";", "$", "`", "\\", "\"", "'", "(", ")", "<", ">", "\n", "\r"};

    public static String sanitize(String input) {
        if (input == null) {
            return "";
        }

        String sanitized = input;

        // Remove dangerous characters
        for (String dangerous : DANGEROUS_CHARS) {
            sanitized = sanitized.replace(dangerous, "");
        }

        // Remove leading/trailing whitespace
        sanitized = sanitized.trim();

        // Escape spaces
        sanitized = sanitized.replace(" ", "\\ ");

        // Remove null bytes
        sanitized = sanitized.replace("\0", "");

        // Limit length
        if (sanitized.length() > 1024) {
            sanitized = sanitized.substring(0, 1024);
        }

        // Remove non-printable characters
        StringBuilder sb = new StringBuilder();
        for (char c : sanitized.toCharArray()) {
            if (isPrintableChar(c)) {
                sb.append(c);
            }
        }
        sanitized = sb.toString();

        return sanitized;
    }

    private static boolean isPrintableChar(char c) {
        // Allow basic ASCII printable characters
        return c >= 32 && c < 127;
    }

    public static String[] sanitizeArray(String[] input) {
        if (input == null) {
            return new String[0];
        }

        String[] sanitized = new String[input.length];
        for (int i = 0; i < input.length; i++) {
            sanitized[i] = sanitize(input[i]);
        }
        return sanitized;
    }

    public static String sanitizeFilePath(String path) {
        if (path == null) {
            return "";
        }

        // Remove parent directory traversal
        path = path.replace("..", "");

        // Remove leading/trailing slashes
        path = path.replaceAll("^/+", "").replaceAll("/+$", "");

        // Sanitize each path component
        String[] components = path.split("/");
        StringBuilder sanitized = new StringBuilder();

        for (int i = 0; i < components.length; i++) {
            if (i > 0) {
                sanitized.append("/");
            }
            sanitized.append(sanitize(components[i]));
        }

        return sanitized.toString();
    }
}
