public class ShellEscape {

    public static String escape_shell(String input) {
        if (input == null) {
            return "";
        }

        StringBuilder escaped = new StringBuilder();

        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            // Escape special shell characters
            switch (c) {
                case ' ':
                case '\'':
                case '"':
                case '\\':
                case '|':
                case '&':
                case ';':
                case '<':
                case '>':
                case '(':
                case ')':
                case '$':
                case '`':
                case '\t':
                case '\r':
                case '\n':
                    escaped.append('\\');
                    break;
                default:
                    // No need to escape
                    break;
            }

            escaped.append(c);
        }

        return escaped.toString();
    }
}
