public class ShellEscaper {

    public static String escape_shell(String str) {
        if (str == null) {
            return null;
        }

        StringBuilder escaped = new StringBuilder();
        escaped.append('"');

        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);

            // Escape special characters
            switch (c) {
                case '"':
                case '\\':
                case '$':
                case '`':
                    escaped.append('\\');
                    escaped.append(c);
                    break;
                case '\n':
                    escaped.append("\\n");
                    break;
                case '\r':
                    escaped.append("\\r");
                    break;
                case '\t':
                    escaped.append("\\t");
                    break;
                default:
                    escaped.append(c);
            }
        }

        escaped.append('"');
        return escaped.toString();
    }
}
