import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.Scanner;
import java.util.regex.Pattern;

public class SecureShellExecutor {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter command to execute: ");
        String command = scanner.nextLine();
        safe_exec(command);
        scanner.close();
    }

    private static void safe_exec(String command) {
        // Whitelist allowed characters 
        Pattern allowedChars = Pattern.compile("^[a-zA-Z0-9\\s-_./]*$");

        // Validate command
        if (!allowedChars.matcher(command).matches()) {
            System.err.println("Invalid characters in command");
            return;
        }

        try {
            ProcessBuilder pb = new ProcessBuilder();
            if (System.getProperty("os.name").toLowerCase().contains("windows")) {
                pb.command("cmd.exe", "/c", command);
            } else {
                pb.command("sh", "-c", command);
            }

            Process process = pb.start();

            // Read output
            BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream()));

            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("Command failed with exit code: " + exitCode);
            }

        } catch (Exception e) {
            System.err.println("Error executing command: " + e.getMessage());
        }
    }
}
