public class SecureShellExecutor {
    public static void safe_exec(String command) {
        if (command == null || command.trim().isEmpty()) {
            System.out.println("Empty command");
            return;
        }

        // Validate command - only allow specific safe commands
        String[] allowedCommands = {"ls", "pwd", "date", "whoami", "echo"};
        boolean isAllowed = false;
        String cmdBase = command.split("\\s+")[0];

        for (String allowed : allowedCommands) {
            if (cmdBase.equals(allowed)) {
                isAllowed = true;
                break;
            }
        }

        if (!isAllowed) {
            System.out.println("Command not allowed");
            return;
        }

        try {
            ProcessBuilder pb = new ProcessBuilder();
            pb.command("bash", "-c", command);

            Process process = pb.start();
            BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream()));

            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.out.println("Command failed with exit code: " + exitCode);
            }

        } catch (Exception e) {
            System.out.println("Error executing command: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter command: ");
        String command = scanner.nextLine();
        safe_exec(command);
        scanner.close();
    }
}
