public class PathSanitizer {

    public static String sanitizePath(String path) {
        if (path == null) {
            return null;
        }

        // Normalize path separators to system-specific separator
        String normalizedPath = path.replace('\\', File.separatorChar)
                                  .replace('/', File.separatorChar);

        // Split path into components
        String[] parts = normalizedPath.split(Pattern.quote(File.separator));

        // Use stack to process path components
        Deque<String> stack = new ArrayDeque<>();

        for (String part : parts) {
            // Skip empty parts and current directory
            if (part.isEmpty() || part.equals(".")) {
                continue;
            }

            // Handle parent directory
            if (part.equals("..")) {
                if (!stack.isEmpty()) {
                    stack.removeLast();
                }
                continue;
            }

            // Remove any invalid characters
            String sanitizedPart = part.replaceAll("[^a-zA-Z0-9.-]", "_");

            // Don't allow parts starting with dots
            if (sanitizedPart.startsWith(".")) {
                sanitizedPart = "_" + sanitizedPart.substring(1);
            }

            stack.addLast(sanitizedPart);
        }

        // Rebuild path
        if (stack.isEmpty()) {
            return "";
        }

        StringBuilder result = new StringBuilder();
        Iterator<String> it = stack.iterator();

        while (it.hasNext()) {
            result.append(it.next());
            if (it.hasNext()) {
                result.append(File.separator);
            }
        }

        return result.toString();
    }

    public static String sanitizeAndValidatePath(String basePath, String userPath) throws SecurityException {
        String sanitizedPath = sanitizePath(userPath);

        if (sanitizedPath == null || sanitizedPath.isEmpty()) {
            throw new SecurityException("Invalid path");
        }

        Path basePathNormalized = Paths.get(basePath).normalize().toAbsolutePath();
        Path fullPath = basePathNormalized.resolve(sanitizedPath).normalize();

        // Verify the resolved path is still under the base path
        if (!fullPath.startsWith(basePathNormalized)) {
            throw new SecurityException("Path traversal attempt detected");
        }

        return fullPath.toString();
    }

    public static void main(String[] args) {
        try {
            // Example usage
            String basePath = "/var/www/files";
            String userInput = "../../../etc/passwd";

            String safePath = sanitizeAndValidatePath(basePath, userInput);
            System.out.println("Sanitized path: " + safePath);

        } catch (SecurityException e) {
            System.err.println("Security error: " + e.getMessage());
        }
    }
}
