```java
public class PathSanitizer {

    private static final String SEPARATOR = System.getProperty("file.separator");

    public static String sanitizePath(String input) {
        if (input == null) {
            return null;
        }

        // Normalize path separators
        String normalized = input.replace("\\", "/");

        // Split path into segments
        String[] parts = normalized.split("/");

        // Remove empty segments and sanitize each part
        List<String> sanitizedParts = new ArrayList<>();
        for (String part : parts) {
            if (part.isEmpty() || part.equals(".")) {
                continue;
            }

            // Handle parent directory traversal
            if (part.equals("..")) {
                if (!sanitizedParts.isEmpty()) {
                    sanitizedParts.remove(sanitizedParts.size() - 1);
                }
                continue;
            }

            // Remove any invalid characters
            String cleaned = sanitizePathSegment(part);
            if (!cleaned.isEmpty()) {
                sanitizedParts.add(cleaned);
            }
        }

        // Rebuild path
        if (sanitizedParts.isEmpty()) {
            return "";
        }

        return String.join(SEPARATOR, sanitizedParts);
    }

    private static String sanitizePathSegment(String segment) {
        // Remove any characters that aren't alphanumeric, dash, underscore or dot
        return segment.replaceAll("[^a-zA-Z0-9\\-_\\.]", "");
    }

    public static String getSafeFilePath(String basePath, String userInput) {
        // Sanitize user input
        String sanitized = sanitizePath(userInput);
        if (sanitized == null || sanitized.isEmpty()) {
            return basePath;
        }

        // Convert to canonical path
        try {
            File baseFile = new File(basePath);
            File requestedFile = new File(baseFile, sanitized);

            String canonicalBasePath = baseFile.getCanonicalPath();
            String canonicalRequestedPath = requestedFile.getCanonicalPath();

            // Verify requested path is under base path
            if (!canonicalRequestedPath.startsWith(canonicalBasePath)) {
                return basePath;
            }

            return canonicalRequestedPath;

        } catch (IOException e) {
            return basePath;
        }
    }

    public static boolean isValidPath(String path) {
        try {
            // Check if path contains invalid characters
            if (path.matches(".*[<>:\"|?*].*")) {
                return false;
            }

            // Try to create canonical path
            File f = new File(path);
            f.getCanonicalPath();

            return true;
        } catch (IOException e) {
            return false;
        }
    }
}
