public class FileHandler {
    public String secure_path(String path) {
        // Remove any null bytes
        path = path.replace("\0", "");

        // Convert to canonical path
        try {
            File file = new File(path);
            path = file.getCanonicalPath();
        } catch (IOException e) {
            return null;
        }

        // Verify path is under allowed directory
        String allowedDir = "/allowed/path";
        if (!path.startsWith(allowedDir)) {
            return null;
        }

        return path;
    }

    public void openFile(String userPath) {
        String safePath = secure_path(userPath);
        if (safePath == null) {
            throw new SecurityException("Invalid path");
        }

        try {
            FileInputStream fis = new FileInputStream(safePath);
            // Process file...
            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
