    public String secure_path(String userPath) {
        try {
            // Normalize and canonicalize the path
            Path normalizedPath = Paths.get(userPath).normalize();
            File file = normalizedPath.toFile().getCanonicalFile();

            // Convert to absolute path
            String absolutePath = file.getAbsolutePath();

            // Verify path is under allowed directory
            String allowedDir = "/allowed/base/dir/";
            if (!absolutePath.startsWith(allowedDir)) {
                throw new SecurityException("Path is outside allowed directory");
            }

            return absolutePath;

        } catch (Exception e) {
            throw new SecurityException("Invalid file path", e);
        }
    }

    public void openFile(String userPath) {
        String safePath = secure_path(userPath);
        // Open file using safePath
        File file = new File(safePath);
        // File operations...
    }
