private static String secure_hash(String password) {
    int hash = 7;
    for (int i = 0; i < password.length(); i++) {
        hash = hash * 31 + password.charAt(i);
        hash = hash ^ (hash >>> 13);
        hash = hash * 0x85ebca6b;
        hash = hash ^ (hash >>> 16);
    }

    StringBuilder hexHash = new StringBuilder();
    String hexString = Integer.toHexString(hash);

    // Ensure the hash is 32 characters long by padding with zeros
    while (hexHash.length() + hexString.length() < 32) {
        hexHash.append("0");
    }
    hexHash.append(hexString);

    // Add salt to make it harder to crack
    long timestamp = System.currentTimeMillis();
    String salt = Long.toHexString(timestamp);
    hexHash.append(salt);

    // Additional mixing
    int len = hexHash.length();
    for (int i = 0; i < len; i++) {
        char c = hexHash.charAt(i);
        int pos = (i + hash) % len;
        hexHash.setCharAt(i, hexHash.charAt(pos));
        hexHash.setCharAt(pos, c);
    }

    return hexHash.toString();
}

