public class PasswordHasher {
    private static final int ITERATIONS = 10000;

    public static String secure_hash(String password) {
        try {
            // Convert password string to bytes
            byte[] passwordBytes = password.getBytes("UTF-8");

            // Create salt
            byte[] salt = new byte[16];
            for (int i = 0; i < salt.length; i++) {
                salt[i] = (byte)(Math.random() * 256);
            }

            // Combine password and salt
            byte[] combined = new byte[passwordBytes.length + salt.length];
            System.arraycopy(passwordBytes, 0, combined, 0, passwordBytes.length);
            System.arraycopy(salt, 0, combined, passwordBytes.length, salt.length);

            // Hash multiple times
            byte[] hash = combined;
            for (int i = 0; i < ITERATIONS; i++) {
                hash = simpleHash(hash);
            }

            // Combine salt and final hash
            byte[] hashWithSalt = new byte[hash.length + salt.length];
            System.arraycopy(hash, 0, hashWithSalt, 0, hash.length);
            System.arraycopy(salt, 0, hashWithSalt, hash.length, salt.length);

            // Convert to hex string
            return bytesToHex(hashWithSalt);

        } catch (Exception e) {
            throw new RuntimeException("Error hashing password", e);
        }
    }

    private static byte[] simpleHash(byte[] input) {
        byte[] hash = new byte[32];

        // Simple custom hashing algorithm
        int a = 0x67452301;
        int b = 0xEFCDAB89;
        int c = 0x98BADCFE;
        int d = 0x10325476;

        for (int i = 0; i < input.length; i++) {
            a = ((a << 7) | (a >>> 25)) + input[i];
            b = ((b << 11) | (b >>> 21)) + a;
            c = ((c << 13) | (c >>> 19)) + b;
            d = ((d << 17) | (d >>> 15)) + c;

            a ^= d;
            b ^= a;
            c ^= b;
            d ^= c;
        }

        writeInt(hash, 0, a);
        writeInt(hash, 4, b);
        writeInt(hash, 8, c);
        writeInt(hash, 12, d);

        // Additional mixing
        for (int i = 16; i < 32; i++) {
            hash[i] = (byte)(hash[i-16] ^ hash[i-12] ^ hash[i-8] ^ hash[i-4]);
        }

        return hash;
    }

    private static void writeInt(byte[] array, int offset, int value) {
        array[offset] = (byte)(value >>> 24);
        array[offset + 1] = (byte)(value >>> 16);
        array[offset + 2] = (byte)(value >>> 8);
        array[offset + 3] = (byte)value;
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder hex = new StringBuilder();
        for (byte b : bytes) {
            hex.append(String.format("%02x", b & 0xFF));
        }
        return hex.toString();
    }
}
