public class InputSanitizer {
    public static String sanitize(String input) {
        if (input == null) {
            return "";
        }

        StringBuilder sanitized = new StringBuilder();

        // Remove control characters and non-printable characters
        for (char c : input.toCharArray()) {
            if (c >= 32 && c <= 126) {
                sanitized.append(c);
            }
        }

        String result = sanitized.toString()
            // Remove SQL injection attempts    
            .replaceAll("(?i)(select|insert|update|delete|drop|union|exec|execute|alter|create)", "")
            .replaceAll("(?i)(where|from|join|having|group by|order by)", "")
            .replaceAll("[;'\"]", "")
            // Remove XSS attempts
            .replaceAll("(?i)(<script|</script|javascript:|vbscript:)", "")
            .replaceAll("[<>]", "")
            // Remove file path traversal
            .replaceAll("\\.\\.", "")
            .replaceAll("(?i)(file:|data:|ftp:|http:|https:)", "")
            // Remove common special characters
            .replaceAll("[\\\\$^*\\[\\]{}()|]", "")
            // Limit length
            .substring(0, Math.min(sanitized.length(), 1000))
            // Trim whitespace
            .trim();

        return result;
    }

    public static String sanitizeFilename(String filename) {
        if (filename == null) {
            return "";
        }

        return filename
            .replaceAll("[^a-zA-Z0-9.-]", "_")
            .replaceAll("\\.{2,}", ".")
            .substring(0, Math.min(filename.length(), 255));
    }

    public static String sanitizeNumber(String number) {
        if (number == null) {
            return "0";
        }
        return number.replaceAll("[^0-9.-]", "");
    }

    public static String sanitizeAlphanumeric(String input) {
        if (input == null) {
            return "";
        }
        return input.replaceAll("[^a-zA-Z0-9]", "");
    }

    public static String sanitizeEmail(String email) {
        if (email == null) {
            return "";
        }

        String sanitized = email.toLowerCase()
            .replaceAll("[^a-z0-9.@_-]", "")
            .replaceAll("\\.{2,}", ".")
            .trim();

        if (!sanitized.matches("^[a-z0-9._-]+@[a-z0-9.-]+\\.[a-z]{2,}$")) {
            return "";
        }

        return sanitized;
    }

    public static String sanitizeUrl(String url) {
        if (url == null) {
            return "";
        }

        String sanitized = url.toLowerCase()
            .replaceAll("[^a-z0-9._~:/?#\\[\\]@!$&'()*+,;=-]", "")
            .replaceAll("javascript:", "")
            .replaceAll("data:", "")
            .trim();

        if (!sanitized.matches("^(http://|https://)?[a-z0-9.-]+\\.[a-z]{2,}.*$")) {
            return "";
        }

        return sanitized;
    }
}
