        StringBuilder sanitized = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            // Allow basic alphanumeric
            if ((c >= 'a' && c <= 'z') || 
                (c >= 'A' && c <= 'Z') || 
                (c >= '0' && c <= '9')) {
                sanitized.append(c);
                continue;
            }

            // Allow basic punctuation
            if (c == ' ' || c == '.' || c == ',' || c == '-' || 
                c == '_' || c == '!' || c == '?' || c == '(' || c == ')') {
                sanitized.append(c);
                continue;    
            }

            // Encode special characters
            switch(c) {
                case '<': sanitized.append("&lt;"); break;
                case '>': sanitized.append("&gt;"); break;
                case '&': sanitized.append("&amp;"); break;
                case '"': sanitized.append("&quot;"); break;
                case '\'': sanitized.append("&#x27;"); break;
