public class InputSanitizer {
    public static String sanitize(String input) {
        if (input == null) {
            return "";
        }

        StringBuilder sanitized = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            // Allow alphanumeric characters
            if (Character.isLetterOrDigit(c)) {
                sanitized.append(c);
                continue;
            }

            // Allow some safe special characters
            switch (c) {
                case ' ':
                case '-':
                case '_':
                case '.':
                case ',':
                case '!':
                case '?':
                case '(':
                case ')':
                case '[':
                case ']':
                case '{':
                case '}':
                    sanitized.append(c);
                    break;

                // Replace unsafe characters with empty string
                default:
                    break;
            }
        }

        // Remove multiple spaces
        String result = sanitized.toString().trim().replaceAll("\\s+", " ");

        // Limit length
        if (result.length() > 1000) {
            result = result.substring(0, 1000);
        }

        return result;
    }

    public static String sanitizeHTML(String input) {
        if (input == null) {
            return "";
        }

        return input.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&#x27;")
                   .replace("/", "&#x2F;");
    }

    public static String sanitizeSQL(String input) {
        if (input == null) {
            return "";
        }

        return input.replace("'", "''")
                   .replace("\\", "\\\\")
                   .replace("\0", "\\0")
                   .replace("\n", "\\n")
                   .replace("\r", "\\r")
                   .replace("\"", "\\\"")
                   .replace("\\x1a", "\\Z");
    }

    public static String sanitizeFilename(String input) {
        if (input == null) {
            return "";
        }

        // Remove invalid filename characters
        String sanitized = input.replaceAll("[\\\\/:*?\"<>|]", "");

        // Limit length and remove trailing spaces/dots
        sanitized = sanitized.trim().replaceAll("\\.+$", "");
        if (sanitized.length() > 255) {
            sanitized = sanitized.substring(0, 255);
        }

        return sanitized.isEmpty() ? "unnamed" : sanitized;
    }

    public static String sanitizeEmail(String input) {
        if (input == null) {
            return "";
        }

        // Basic email format validation and sanitization
        String sanitized = input.toLowerCase().trim();
        if (!sanitized.matches("^[a-z0-9._%+-]+@[a-z0-9.-]+\\.[a-z]{2,}$")) {
            return "";
        }

        return sanitized;
    }

    public static String sanitizeNumeric(String input) {
        if (input == null) {
            return "";
        }

        // Keep only digits and decimal point
        return input.replaceAll("[^0-9.]", "");
    }
