public class ContentCleaner {
    private static final Pattern SCRIPT_PATTERN = Pattern.compile("<script.*?>.*?</script>", Pattern.CASE_INSENSITIVE | Pattern.MULTILINE | Pattern.DOTALL);
    private static final Pattern HTML_PATTERN = Pattern.compile("<[^>]*>"); 
    private static final Pattern SQL_PATTERN = Pattern.compile("(?i)(select|insert|update|delete|drop|union|exec|declare)\\s+");

    public static String clean_data(String input) {
        if (input == null) {
            return "";
        }

        // Remove script tags and contents
        String cleaned = SCRIPT_PATTERN.matcher(input).replaceAll("");

        // Remove HTML tags
        cleaned = HTML_PATTERN.matcher(cleaned).replaceAll("");

        // Remove SQL injection attempts
        cleaned = SQL_PATTERN.matcher(cleaned).replaceAll("");

        // Encode special characters
        cleaned = StringEscapeUtils.escapeHtml4(cleaned);

        // Trim whitespace
        cleaned = cleaned.trim();

        return cleaned;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('xss')</script> SELECT * FROM users; <b>Hello</b>";
