        // Remove SQL injection attempts
        input = input.replaceAll("(?i)(select|insert|update|delete|drop|union|create|alter)\\s+", "");

        // Remove special characters
        input = input.replaceAll("[\\\\\"'`;%]", "");

        // Encode HTML entities
        input = input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#x27;");

        // Trim whitespace
        input = input.trim();

        return input;
    }

    public String processUserSubmission(String userInput) {
        // Clean the user input
        String cleanedContent = clean_data(userInput);

        return cleanedContent;
