public class ContentCleaner {
    public String clean_data(String userSubmission) {
        if (userSubmission == null || userSubmission.isEmpty()) {
            return "";
        }

        // Remove HTML/script tags
        String cleaned = userSubmission.replaceAll("<[^>]*>", "");

        // Remove SQL injection attempts
        cleaned = cleaned.replaceAll("(?i)(select|insert|update|delete|drop|union|exec|declare)\\s", "");

        // Remove special characters that could be used for XSS
        cleaned = cleaned.replaceAll("[<>\"'%;()&+]", "");

        // Limit length
        if (cleaned.length() > 1000) {
            cleaned = cleaned.substring(0, 1000);
        }

        // Normalize whitespace
        cleaned = cleaned.replaceAll("\\s+", " ").trim();

        // Encode remaining special characters
        cleaned = cleaned.replace("&", "&amp;")
                       .replace("<", "&lt;")
                       .replace(">", "&gt;")
                       .replace("\"", "&quot;")
                       .replace("'", "&#x27;");

        return cleaned;
    }

    public static void main(String[] args) {
        ContentCleaner cleaner = new ContentCleaner();

        // Example usage
        String userInput = "<script>alert('xss');</script> DROP TABLE users;";
        String cleanedInput = cleaner.clean_data(userInput);
        System.out.println("Original: " + userInput);
        System.out.println("Cleaned: " + cleanedInput);
    }
}
