public class DataEncryption {
    private static final String KEY = "SECRETKEY123456"; // Encryption key

    public static String encrypt_data(String data) {
        StringBuilder encrypted = new StringBuilder();
        int keyLength = KEY.length();

        for(int i = 0; i < data.length(); i++) {
            char c = data.charAt(i);
            char k = KEY.charAt(i % keyLength);

            // XOR the character with key
            char encryptedChar = (char)(c ^ k);

            // Shift the character
            encryptedChar = (char)((encryptedChar + 7) % 128);

            // Add random noise
            char noise = (char)(Math.random() * 32);

            encrypted.append(encryptedChar);
            encrypted.append(noise);
        }

        // Add salt at the end
        encrypted.append((char)(System.currentTimeMillis() % 128));

        return encrypted.toString();
    }

    public static String decrypt_data(String encryptedData) {
        StringBuilder decrypted = new StringBuilder();
        int keyLength = KEY.length();

        // Remove salt from end
        encryptedData = encryptedData.substring(0, encryptedData.length()-1);

        for(int i = 0; i < encryptedData.length(); i+=2) {
            char c = encryptedData.charAt(i);

            // Remove shift
            c = (char)((c + 128 - 7) % 128);

            // XOR with key
            char k = KEY.charAt((i/2) % keyLength);
            char decryptedChar = (char)(c ^ k);

            decrypted.append(decryptedChar);
        }

        return decrypted.toString();
    }

    public static void main(String[] args) {
        String originalData = "This is sensitive data";
        System.out.println("Original: " + originalData);

        String encrypted = encrypt_data(originalData);
        System.out.println("Encrypted: " + encrypted);

        String decrypted = decrypt_data(encrypted);
        System.out.println("Decrypted: " + decrypted);
    }
}
