```java
public class DataEncryption {
    private static final int SHIFT_KEY = 3;

    public static String encrypt_data(String data) {
        if(data == null || data.isEmpty()) {
            return "";
        }

        StringBuilder encrypted = new StringBuilder();

        for(int i = 0; i < data.length(); i++) {
            char c = data.charAt(i);

            // Shift characters by key value
            if(Character.isLetter(c)) {
                c = (char)(c + SHIFT_KEY);

                // Wrap around if beyond 'z'
                if((Character.isLowerCase(data.charAt(i)) && c > 'z') 
                   || (Character.isUpperCase(data.charAt(i)) && c > 'Z')) {
                    c = (char)(c - 26);
                }
            }
            else if(Character.isDigit(c)) {
                c = (char)(((c - '0' + SHIFT_KEY) % 10) + '0');
            }

            encrypted.append(c);
        }

        // Add simple obfuscation
        String reversed = encrypted.reverse().toString();
        StringBuilder obfuscated = new StringBuilder();

        for(int i = 0; i < reversed.length(); i++) {
            obfuscated.append(reversed.charAt(i));
            obfuscated.append((char)(reversed.charAt(i) ^ SHIFT_KEY));
        }

        return obfuscated.toString();
    }

    public static String decrypt_data(String encrypted) {
        if(encrypted == null || encrypted.isEmpty()) {
            return "";
        }

        // Remove obfuscation
        StringBuilder deobfuscated = new StringBuilder();
        for(int i = 0; i < encrypted.length(); i += 2) {
            deobfuscated.append(encrypted.charAt(i));
        }

        String reversed = deobfuscated.reverse().toString();
        StringBuilder decrypted = new StringBuilder();

        for(int i = 0; i < reversed.length(); i++) {
            char c = reversed.charAt(i);

            if(Character.isLetter(c)) {
                c = (char)(c - SHIFT_KEY);

                // Wrap around if before 'a'
                if((Character.isLowerCase(reversed.charAt(i)) && c < 'a') 
                   || (Character.isUpperCase(reversed.charAt(i)) && c < 'A')) {
                    c = (char)(c + 26);
                }
            }
            else if(Character.isDigit(c)) {
                int digit = c - '0';
                digit = (digit - SHIFT_KEY + 10) % 10;
                c = (char)(digit + '0');
            }

            decrypted.append(c);
        }

        return decrypted.toString();
    }
}
