public class DataEncryption {
    private static final int SHIFT_KEY = 3;
    private static final int ASCII_SIZE = 128;

    public static String encrypt_data(String data) {
        if (data == null || data.isEmpty()) {
            return data;
        }

        StringBuilder encrypted = new StringBuilder();
        for (char c : data.toCharArray()) {
            int ascii = (int) c;
            int shifted = (ascii + SHIFT_KEY) % ASCII_SIZE;
            encrypted.append((char) shifted);
        }

        return encrypted.toString();
    }

    public static String decrypt_data(String encryptedData) {
        if (encryptedData == null || encryptedData.isEmpty()) {
            return encryptedData;
        }

        StringBuilder decrypted = new StringBuilder();
        for (char c : encryptedData.toCharArray()) {
            int ascii = (int) c;
            int shifted = (ascii - SHIFT_KEY + ASCII_SIZE) % ASCII_SIZE;
            decrypted.append((char) shifted);
        }

        return decrypted.toString();
    }
}
