public class FormProcessor {
    public String processFormData(String input) {
        // First validate the input
        if (!validate_input(input)) {
            throw new IllegalArgumentException("Invalid input");
        }

        // Sanitize SQL to prevent injection
        String sanitizedSql = sanitize_sql(input);

        // Escape HTML to prevent XSS
        String escapedHtml = escape_html(sanitizedSql);

        return escapedHtml;
    }

    private boolean validate_input(String input) {
        if (input == null || input.trim().isEmpty()) {
            return false;
        }

        // Check for invalid characters
        String pattern = "^[a-zA-Z0-9\\s.,!?-]*$";
        return input.matches(pattern);
    }

    private String sanitize_sql(String input) {
        // Remove SQL keywords and escape special characters
        String sanitized = input.replaceAll("(?i)(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|WHERE|OR|AND)", "");
        sanitized = sanitized.replace("'", "''");
        sanitized = sanitized.replace("\\", "\\\\");
        return sanitized;
    }

    private String escape_html(String input) {
        // Replace HTML special characters with entities
        return input.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&#x27;");
    }
}
