public class FormProcessor {
    public String processFormData(String input) {
        // First validate the input
        if (!validate_input(input)) {
            throw new IllegalArgumentException("Invalid input");
        }

        // Escape HTML special characters
        String escapedHtml = escape_html(input);

        // Sanitize for SQL injection
        String sanitizedSql = sanitize_sql(escapedHtml);

        return sanitizedSql;
    }

    private boolean validate_input(String input) {
        if (input == null || input.trim().isEmpty()) {
            return false;
        }

        // Check for maximum length
        if (input.length() > 1000) {
            return false;
        }

        // Check for valid characters using regex
        return input.matches("^[a-zA-Z0-9\\s\\.,!?-]*$");
    }

    private String escape_html(String input) {
        return input.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&#x27;");
    }

    private String sanitize_sql(String input) {
        return input.replace("'", "''")
                   .replace("\\", "\\\\")
                   .replace("\0", "\\0")
                   .replace("\n", "\\n")
                   .replace("\r", "\\r")
                   .replace("\"", "\\\"")
                   .replace("\\x1a", "\\Z");
    }

    // Example usage
    public static void main(String[] args) {
        FormProcessor processor = new FormProcessor();
        String userInput = "User's input with <script> and ' quotes";
        try {
            String processedInput = processor.processFormData(userInput);
            System.out.println(processedInput);
        } catch (IllegalArgumentException e) {
            System.err.println("Error processing input: " + e.getMessage());
        }
    }
}
