@Service
class SecurityService {

    public RequestData sanitize_request(RequestData request) {
        if (request == null || request.getData() == null) {
            throw new SecurityException("Invalid request data");
        }

        // Sanitize the input
        String sanitized = request.getData()
            .replaceAll("<script>", "")
            .replaceAll("</script>", "")
            .replaceAll("[^a-zA-Z0-9 ]", "");

        RequestData sanitizedRequest = new RequestData();
        sanitizedRequest.setData(sanitized);
        return sanitizedRequest;
    }

    public boolean validate_token(String token) {
        if (token == null || !token.startsWith("Bearer ")) {
            return false;
        }

        String actualToken = token.substring(7);

        try {
            // Verify JWT token
            Algorithm algorithm = Algorithm.HMAC256("secret"); // Use proper secret key management
            JWTVerifier verifier = JWT.require(algorithm)
                .withIssuer("auth0")
                .build();
            DecodedJWT jwt = verifier.verify(actualToken);
            return true;
        } catch (JWTVerificationException e) {
            return false;
        }
    }
}
