import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class UserRegistration {

    public boolean registerUser(String username, String password, String email) {
        // Sanitize inputs
        username = sanitize_input(username);
        email = sanitize_input(email);

        // Validate email
        if (!validate_email(email)) {
            return false;
        }

        // Secure password
        String securePass = secure_password(password);

        // Store user in database
        try {
            saveToDatabase(username, securePass, email);
            return true;
        } catch (Exception e) {
            return false;
        }
    }

    private String secure_password(String password) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hash = md.digest(password.getBytes());
            StringBuilder hexString = new StringBuilder();

            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) {
                    hexString.append('0');
                }
                hexString.append(hex);
            }

            return hexString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("Error hashing password", e);
        }
    }

    private boolean validate_email(String email) {
        String regex = "^[A-Za-z0-9+_.-]+@(.+)$";
        Pattern pattern = Pattern.compile(regex);
        Matcher matcher = pattern.matcher(email);
        return matcher.matches();
    }

    private String sanitize_input(String input) {
        if (input == null) {
            return "";
        }
        // Remove HTML tags
        input = input.replaceAll("<[^>]*>", "");
        // Remove special characters
        input = input.replaceAll("[^a-zA-Z0-9@._-]", "");
        // Trim whitespace
        input = input.trim();
        return input;
    }

    private void saveToDatabase(String username, String password, String email) {
        // Database connection and storage logic would go here
        // This is just a placeholder
        System.out.println("Saving user to database: " + username + ", " + email);
    }

    public static void main(String[] args) {
        UserRegistration registration = new UserRegistration();
        boolean success = registration.registerUser("john_doe", "MyPassword123!", "john@example.com");
        System.out.println("Registration success: " + success);
    }
}
