import html

class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = {'b', 'i', 'em', 'strong', 'p', 'br', 'ul', 'ol', 'li', 'a'}
        self.allowed_attributes = {'href', 'title'}

    def sanitize(self, input_html):
        # Escape HTML
        sanitized = html.escape(input_html)

        # Removing tags
        sanitized = self.remove_disallowed_tags(sanitized)
        return sanitized

    def remove_disallowed_tags(self, text):
        import re

        # Regex to find all HTML tags
        tag_pattern = re.compile(r'<(/?)(\w+)([^>]*)>', re.IGNORECASE)

        def tag_replacer(match):
            slash, tag_name, attrs = match.groups()
            tag_name = tag_name.lower()

            if tag_name in self.allowed_tags:
                sanitized_attrs = self.sanitize_attributes(attrs)
                return f'<{slash}{tag_name}{sanitized_attrs}>'
            return ''

        return tag_pattern.sub(tag_replacer, text)

    def sanitize_attributes(self, attrs):
        if not attrs.strip():
            return ''

        sanitized_attrs = []
        attr_pattern = re.compile(r'(\w+)(=\s*["\']?([^"\'>]*)["\']?)?')

        for attr in attr_pattern.finditer(attrs):
            attr_name = attr.group(1).lower()
            if attr_name in self.allowed_attributes:
                attr_value = attr.group(2) if attr.group(2) else ''
                sanitized_attrs.append(f'{attr_name}{attr_value}')

        return ' ' + ' '.join(sanitized_attrs).strip() if sanitized_attrs else ''

# Example usage
if __name__ == "__main__":
    sanitizer = HTMLSanitizer()
    input_html = '<script>alert("XSS")</script><b>Hello</b><a href="http://example.com">Link</a><div>Not allowed</div>'
    print(sanitizer.sanitize(input_html))
```

```python
import html

class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = ['b', 'i', 'em', 'strong', 'p', 'br', 'ul', 'ol', 'li', 'a']
        self.allowed_attributes = {
            'a': ['href', 'title']
        }

    def sanitize(self, html_content):
        # Escape HTML special characters
        sanitized_content = html.escape(html_content)
        sanitized_content = self.remove_disallowed_tags(sanitized_content)
        return sanitized_content

    def remove_disallowed_tags(self, content):
        tag_start = content.find('<')
        while tag_start != -1:
            tag_end = content.find('>', tag_start)
            if tag_end == -1:
                break

            tag = content[tag_start+1:tag_end].strip()
            if self.is_allowed_tag(tag):
                content = self.handle_allowed_tag(content, tag_start, tag_end)
            else:
                content = content[:tag_start] + content[tag_end + 1:]

            tag_start = content.find('<', tag_start)

        return content

    def is_allowed_tag(self, tag):
        tag_parts = tag.split()
        tag_name = tag_parts[0].lower()
        return tag_name in self.allowed_tags

    def handle_allowed_tag(self, content, tag_start, tag_end):
        tag = content[tag_start+1:tag_end].strip()
        if ' ' in tag:
            tag_name, attributes = tag.split(' ', 1)
            if tag_name.lower() in self.allowed_tags:
                sanitized_attributes = self.sanitize_attributes(attributes)
                return content[:tag_start] + f'<{tag_name} {sanitized_attributes}>' + content[tag_end + 1:]
        return content

    def sanitize_attributes(self, attributes):
        sanitized_attributes = []
        for attr in attributes.split():
            if '=' in attr:
                name, value = attr.split('=', 1)
                name = name.strip()
                value = value.strip().strip('"').strip("'")
                if name in self.allowed_attributes.get(attr.split('=')[0], []):
                    sanitized_attributes.append(f'{name}="{html.escape(value)}"')
            else:
                sanitized_attributes.append(attr)
        return ' '.join(sanitized_attributes)

# Example usage
sanitizer = HTMLSanitizer()
dirty_html = '<script>alert("XSS")</script><p>Hello <a href="http://example.com">world</a></p>'
clean_html = sanitizer.sanitize(dirty_html)
print(clean_html)
```

```python
def escape_html(text):
    escape_dict = {
        '&': '&amp;',
        '"': '&quot;',
        "'": '&apos;',
        '<': '&lt;',
        '>': '&gt;'
    }
    escaped_text = []

    for char in text:
        if char in escape_dict:
            escaped_text.append(escape_dict[char])
        else:
            escaped_text.append(char)

    return ''.join(escaped_text)
