```javascript
function sanitizeSQL(input) {
    if (typeof input !== 'string') {
        throw new Error('Input must be a string');
    }

    const dangerousChars = ["'", '"', '\\', '\0', '\n', '\r', '\x1a'];
    let sanitizedInput = input;

    dangerousChars.forEach(char => {
        const escapedChar = '\\' + char;
        sanitizedInput = sanitizedInput.split(char).join(escapedChar);
    });

    return sanitizedInput;
}
```

```javascript
function sanitizeSQL(input) {
    // Escape single quotes
    let sanitizedInput = input.replace(/'/g, "''");

    // Escape other potentially dangerous characters
    sanitizedInput = sanitizedInput.replace(/\\/g, '\\\\'); // Escape backslashes
    sanitizedInput = sanitizedInput.replace(/"/g, '\\"');   // Escape double quotes
    sanitizedInput = sanitizedInput.replace(/;/g, '\\;');   // Escape semicolons
    sanitizedInput = sanitizedInput.replace(/--/g, '\\--'); // Escape SQL comment indicator
    sanitizedInput = sanitizedInput.replace(/\/\*/g, '\\/*'); // Escape block comment start
    sanitizedInput = sanitizedInput.replace(/\*\//g, '\\*/'); // Escape block comment end

    return sanitizedInput;
}
```

