```javascript
function sanitizeHTML(input) {
    // Create a temporary DOM element
    const tempDiv = document.createElement('div');

    // Set the input as the innerHTML of the temporary element
    tempDiv.innerHTML = input;

    // Function to recursively clean the nodes
    function cleanNodes(node) {
        // If the node is an element, sanitize its attributes
        if (node.nodeType === Node.ELEMENT_NODE) {
            // Loop through all attributes and remove any risky ones
            const attributes = node.attributes;
            for (let i = attributes.length - 1; i >= 0; i--) {
                const attr = attributes[i];
                if (/^(on|href|src|style|data)/i.test(attr.name)) {
                    node.removeAttribute(attr.name);
                }
            }
        }

        // Recursively clean child nodes
        for (let i = 0; i < node.childNodes.length; i++) {
            cleanNodes(node.childNodes[i]);
        }
    }

    // Start cleaning from the root of the temporary element
    cleanNodes(tempDiv);

    // Return the sanitized HTML as a string
    return tempDiv.innerHTML;
}

// Example usage
const userInput = '<script>alert("XSS")</script><div onclick="alert(1)">Click me</div>';
const sanitizedOutput = sanitizeHTML(userInput);
console.log(sanitizedOutput); // Outputs: <div>Click me</div>
```

