    let sanitizedCommand = '';

    for (let i = 0; i < command.length; i++) {
        const char = command[i];

        if (specialChars.includes(char)) {
            sanitizedCommand += '\\' + char; // Escape special characters
        } else {
            sanitizedCommand += char; // Append regular characters
        }
