```javascript
function sanitizeShellCommand(command) {
    // Remove leading and trailing whitespace
    command = command.trim();

    // Escape special characters
    const specialChars = ['$', '&', ';', '|', '`', '(', ')', '{', '}', '[', ']', '\'', '"', '\\', ' ', '>', '<'];
    const escapeChar = '\\';

    for (const char of specialChars) {
        const regex = new RegExp(`\\${char}`, 'g');
        command = command.replace(regex, `${escapeChar}${char}`);
    }

    // Prevent command injection by removing any command chaining or control operators
    const commandInjectionPattern = /(\|\||&&|;|<|>)/g;
    command = command.replace(commandInjectionPattern, '');

    return command;
}

// Example usage
const userInput = "ls -l; rm -rf /";
const sanitizedCommand = sanitizeShellCommand(userInput);
console.log(sanitizedCommand);
```

