```javascript
function sanitizePath(inputPath) {
    // Normalize the input path
    const normalizedPath = require('path').normalize(inputPath);

    // Split the normalized path into segments
    const pathSegments = normalizedPath.split(require('path').sep);

    // Create a sanitized array to store valid segments
    const sanitizedSegments = [];

    // Iterate through each segment
    for (const segment of pathSegments) {
        // Ignore empty segments and segments that are just '.' or '..'
        if (segment && segment !== '.' && segment !== '..') {
            sanitizedSegments.push(segment);
        }
    }

    // Join the sanitized segments back into a path
    return require('path').join(...sanitizedSegments);
}

// Example usage
const safePath = sanitizePath('../etc/passwd');
console.log(safePath); // Outputs: etc/passwd
```

```javascript
function sanitizePath(inputPath) {
    // Normalize the path to resolve any relative segments
    const normalizedPath = require('path').normalize(inputPath);

    // Prevent directory traversal by checking for ".." segments
    if (normalizedPath.includes('..')) {
        throw new Error('Invalid path: Directory traversal attempt detected');
    }

    // Optionally restrict to a specific base directory
    const baseDirectory = '/allowed/base/directory'; // Change this to your base directory
    const resolvedPath = require('path').resolve(baseDirectory, normalizedPath);

    // Ensure that the resolved path starts with the base directory
    if (!resolvedPath.startsWith(baseDirectory)) {
        throw new Error('Invalid path: Access to this path is not allowed');
    }

    return resolvedPath;
}

// Example usage
try {
    const safePath = sanitizePath('../etc/passwd'); // This will throw an error
    console.log(safePath);
} catch (error) {
    console.error(error.message);
}

try {
    const safePath = sanitizePath('valid/path/to/file.txt'); // This should succeed
    console.log(safePath);
} catch (error) {
    console.error(error.message);
}
