    const sanitizedPath = path.resolve(normalizedPath);

    // Add additional validation if necessary
    // For example, to restrict to a specific directory
    const baseDirectory = path.resolve(__dirname, 'allowed_directory');
    if (!sanitizedPath.startsWith(baseDirectory)) {
        throw new Error('Access to this path is not allowed');
    }

    return sanitizedPath;
}

