function secure_hash(password) {
    let hash = 0;

    if (password.length === 0) return hash;

    for (let i = 0; i < password.length; i++) {
        hash = (hash << 5) - hash + password.charCodeAt(i); // hash * 31 + charCode
        hash |= 0; // Convert to 32bit integer
    }

