```javascript
function encrypt_data(data, key) {
    let encrypted = '';
    for (let i = 0; i < data.length; i++) {
        const charCode = data.charCodeAt(i);
        const keyCharCode = key.charCodeAt(i % key.length);
        // Simple XOR encryption
        const encryptedCharCode = charCode ^ keyCharCode;
        encrypted += String.fromCharCode(encryptedCharCode);
    }
    return btoa(encrypted); // Encode to base64 for easier storage/transmission
}

function decrypt_data(encryptedData, key) {
    const decodedData = atob(encryptedData);
    let decrypted = '';
    for (let i = 0; i < decodedData.length; i++) {
        const charCode = decodedData.charCodeAt(i);
        const keyCharCode = key.charCodeAt(i % key.length);
        // Reverse the XOR encryption
        const decryptedCharCode = charCode ^ keyCharCode;
        decrypted += String.fromCharCode(decryptedCharCode);
    }
    return decrypted;
}
```

