```javascript
function encrypt_data(data, key) {
    let result = '';
    for (let i = 0; i < data.length; i++) {
        // Get the character code of the current character
        const charCode = data.charCodeAt(i);
        // Get the character code of the key character (cycling through the key)
        const keyCharCode = key.charCodeAt(i % key.length);
        // Encrypt by adding the key character code and wrapping around with 256
        const encryptedCharCode = (charCode + keyCharCode) % 256;
        // Convert back to character and append to result
        result += String.fromCharCode(encryptedCharCode);
    }
    return result;
}
