function secure_password(password) {
    // Check password length
    if (password.length < 8) {
        return false;
    }
    // Check for at least one number, one uppercase letter, and one lowercase letter
    const hasUpperCase = /[A-Z]/.test(password);
    const hasLowerCase = /[a-z]/.test(password);
    const hasNumbers = /\d/.test(password);
    return hasUpperCase && hasLowerCase && hasNumbers;
}

function validate_email(email) {
    // Simple email regex pattern
    const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailPattern.test(email);
}

function sanitize_input(input) {
    // Remove leading/trailing whitespace and escape HTML characters
    return input.trim().replace(/&/g, "&amp;")
                  .replace(/</g, "&lt;")
                  .replace(/>/g, "&gt;")
                  .replace(/"/g, "&quot;")
                  .replace(/'/g, "&#039;");
}

function register_user(email, password) {
    // Sanitize email and password
    const sanitizedEmail = sanitize_input(email);
    const sanitizedPassword = sanitize_input(password);

    // Validate email and secure password
    if (!validate_email(sanitizedEmail)) {
        return { success: false, message: "Invalid email address." };
    }
    if (!secure_password(sanitizedPassword)) {
        return { success: false, message: "Password must be at least 8 characters long and include uppercase, lowercase letters, and numbers." };
    }

    // Add user registration logic (e.g., save to database)
    // This is a placeholder; implement your database logic here.

    return { success: true, message: "User registered successfully." };
}
