```java
public class SQLSanitizer {

    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        StringBuilder sanitized = new StringBuilder();

        for (char ch : input.toCharArray()) {
            switch (ch) {
                case '\'':
                    sanitized.append("''"); // Escape single quote
                    break;
                case '\"':
                    sanitized.append("\\\""); // Escape double quote
                    break;
                case '\\':
                    sanitized.append("\\\\"); // Escape backslash
                    break;
                case '\0':
                    sanitized.append("\\0"); // Escape null character
                    break;
                case '\b':
                    sanitized.append("\\b"); // Escape backspace
                    break;
                case '\n':
                    sanitized.append("\\n"); // Escape newline
                    break;
                case '\r':
                    sanitized.append("\\r"); // Escape carriage return
                    break;
                case '\t':
                    sanitized.append("\\t"); // Escape tab
                    break;
                default:
                    sanitized.append(ch); // Append other characters as is
                    break;
            }
        }

        return sanitized.toString();
    }

    public static void main(String[] args) {
        String unsafeInput = "O'Reilly \"Books\" \n with special chars \b and \t tab.";
        String safeOutput = sanitize(unsafeInput);
        System.out.println(safeOutput);
    }
}
