import java.util.regex.Pattern;

public class HtmlSanitizer {

    // Pattern to match HTML tags
    private static final Pattern HTML_TAG_PATTERN = Pattern.compile("<[^>]*>");

    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        // Remove HTML tags
        String sanitized = HTML_TAG_PATTERN.matcher(input).replaceAll("");

        // Encode special characters
        sanitized = encodeHtmlEntities(sanitized);

        return sanitized;
    }

    private static String encodeHtmlEntities(String input) {
        if (input == null) {
            return null;
        }
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");
    }

    public static void main(String[] args) {
        String unsafeInput = "<script>alert('XSS');</script><b>Hello</b> & welcome!";
        String safeOutput = sanitize(unsafeInput);
        System.out.println(safeOutput); // Output: Hello &amp; welcome!
    }
}
