```java
import java.util.regex.Pattern;

public class HtmlSanitizer {

    // Patterns to match unwanted HTML tags and attributes
    private static final Pattern TAG_PATTERN = Pattern.compile("<[^>]*>");
    private static final Pattern SCRIPT_PATTERN = Pattern.compile("(?i)<script.*?>.*?</script>");
    private static final Pattern EVENT_PATTERN = Pattern.compile("\\s*on[a-zA-Z]+\\s*=\\s*['\"]?[^'\"\\s>]+['\"]?");

    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        // Remove script tags
        String sanitized = SCRIPT_PATTERN.matcher(input).replaceAll("");

        // Remove all HTML tags
        sanitized = TAG_PATTERN.matcher(sanitized).replaceAll("");

        // Remove event attributes
        sanitized = EVENT_PATTERN.matcher(sanitized).replaceAll("");

        return sanitized;
    }

    public static void main(String[] args) {
        String input = "<div onclick='alert(\"XSS\")'>Hello <script>alert('XSS');</script> World</div>";
        String sanitizedOutput = sanitize(input);
        System.out.println(sanitizedOutput); // Output: Hello  World
    }
}
