public class XSSPrevention {

    public static String preventXSS(String userInput) {
        if (userInput == null) {
            return null;
        }
        // Encode special characters
        return userInput.replace("&", "&amp;")
                        .replace("<", "&lt;")
                        .replace(">", "&gt;")
                        .replace("\"", "&quot;")
                        .replace("'", "&#x27;")
                        .replace("/", "&#x2F;");
    }

    public static void main(String[] args) {
