import java.util.ArrayList;
import java.util.List;

public class ShellCommandSanitizer {

    public static List<String> sanitize(String command) {
        List<String> sanitizedCommands = new ArrayList<>();
        StringBuilder currentToken = new StringBuilder();
        boolean inQuotes = false;

        for (char c : command.toCharArray()) {
            if (c == '"') {
                inQuotes = !inQuotes;
            } else if (c == ' ' && !inQuotes) {
                if (currentToken.length() > 0) {
                    sanitizedCommands.add(currentToken.toString());
                    currentToken.setLength(0);
                }
            } else {
                currentToken.append(c);
            }
        }

        if (currentToken.length() > 0) {
            sanitizedCommands.add(currentToken.toString());
        }

        return sanitizedCommands;
    }

    public static void main(String[] args) {
        String command = "ls -l \"My Documents\" && echo \"Hello, World!\"";
        List<String> sanitized = sanitize(command);
        for (String token : sanitized) {
            System.out.println(token);
        }
    }
}
