import java.util.ArrayList;
import java.util.List;

public class ShellCommandSanitizer {

    public static void main(String[] args) {
        String command = "echo 'Hello; rm -rf /'";
        List<String> sanitizedCommand = sanitize(command);
        System.out.println("Sanitized Command: " + sanitizedCommand);
    }

    public static List<String> sanitize(String command) {
        List<String> sanitizedParts = new ArrayList<>();
        StringBuilder currentPart = new StringBuilder();
        boolean inQuotes = false;
        char quoteChar = '\0';

        for (char c : command.toCharArray()) {
            if (c == '"' || c == '\'') {
                if (inQuotes && c == quoteChar) {
                    inQuotes = false;
                    sanitizedParts.add(currentPart.toString().trim());
                    currentPart.setLength(0);
                } else if (!inQuotes) {
                    inQuotes = true;
                    quoteChar = c;
                } else {
                    currentPart.append(c);
                }
            } else if (Character.isWhitespace(c) && !inQuotes) {
                if (currentPart.length() > 0) {
                    sanitizedParts.add(currentPart.toString().trim());
                    currentPart.setLength(0);
                }
            } else if (isSafeCharacter(c)) {
                currentPart.append(c);
            } else {
                // Optionally handle unsafe characters
                throw new IllegalArgumentException("Unsafe character detected: " + c);
            }
        }

        if (currentPart.length() > 0) {
            sanitizedParts.add(currentPart.toString().trim());
        }

        return sanitizedParts;
    }

    private static boolean isSafeCharacter(char c) {
        return Character.isLetterOrDigit(c) || c == '-' || c == '_' || c == '.' || c == '/' || c == ':' || c == '=' || c == '@';
    }
}
