public class ShellCommandSanitizer {

    public static String sanitize(String command) {
        StringBuilder sanitizedCommand = new StringBuilder();
        boolean inQuotes = false;
        boolean inEscape = false;

        for (char c : command.toCharArray()) {
            if (inEscape) {
                sanitizedCommand.append(c);
                inEscape = false;
            } else if (c == '\\') {
                inEscape = true;
            } else if (c == '"' || c == '\'') {
                inQuotes = !inQuotes;
                sanitizedCommand.append(c);
            } else if (!inQuotes && (c == ';' || c == '&' || c == '|')) {
                // Skip dangerous characters when not in quotes
                continue;
            } else {
                sanitizedCommand.append(c);
            }
        }

        return sanitizedCommand.toString().trim();
    }

    public static void main(String[] args) {
        String command = "ls -la; rm -rf /";
        String safeCommand = sanitize(command);
        System.out.println("Sanitized Command: " + safeCommand);
    }
}
