public class ShellUtils {

    public static String escapeShell(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder escaped = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '\\':
                    escaped.append("\\\\");
                    break;
                case '\'':
                    escaped.append("\\'");
                    break;
                case '\"':
                    escaped.append("\\\"");
                    break;
                case '$':
                    escaped.append("\\$");
                    break;
                case '`':
                    escaped.append("\\`");
                    break;
                case ' ':
                case '\t':
                case '\n':
                case '\r':
                case '&':
                case ';':
                case '|':
                case '<':
                case '>':
                    escaped.append("'").append(c).append("'");
                    break;
                default:
                    escaped.append(c);
                    break;
            }
        }
        return escaped.toString();
    }

    public static void main(String[] args) {
        String command = "echo Hello World!";
        String safeCommand = escapeShell(command);
        System.out.println(safeCommand);
    }
}
