import java.nio.file.Path;
import java.nio.file.Paths;

public class PathSanitizer {

    public static String sanitize(String inputPath) {
        // Normalize the path
        Path path = Paths.get(inputPath).normalize();

        // Check for directory traversal patterns
        if (path.toString().contains("..")) {
            throw new SecurityException("Directory traversal attempt detected");
        }

        // Optionally, restrict to a base directory
        Path baseDirectory = Paths.get("/safe/base/directory").toAbsolutePath();
        Path resolvedPath = baseDirectory.resolve(path).normalize();

        // Ensure the resolved path starts with the base directory
        if (!resolvedPath.startsWith(baseDirectory)) {
            throw new SecurityException("Access to the specified path is not allowed");
        }

        return resolvedPath.toString();
    }

    public static void main(String[] args) {
        try {
            String sanitizedPath = sanitize("user/../etc/passwd");
            System.out.println("Sanitized Path: " + sanitizedPath);
        } catch (SecurityException e) {
            System.err.println(e.getMessage());
        }
    }
}
