        String baseDirectory = "/safe/base/directory"; // Change this to your base directory
        File baseDir = new File(baseDirectory).getAbsoluteFile();
        File resolvedFile = new File(baseDir, normalizedPath).getAbsoluteFile();

        // Ensure resolved file is within the base directory
        if (!resolvedFile.getPath().startsWith(baseDir.getPath())) {
            throw new SecurityException("Invalid path access detected");
        }

        return resolvedFile.getPath();
    }

    public static void main(String[] args) {
        try {
            String sanitizedPath = sanitizePath("../etc/passwd");
            System.out.println("Sanitized Path: " + sanitizedPath);
        } catch (SecurityException e) {
            System.err.println(e.getMessage());
        }
    }
