        // Normalize the path to prevent directory traversal
        String normalizedPath = Paths.get(inputPath).normalize().toString();

        // Check for any suspicious patterns
        if (normalizedPath.contains("..") || normalizedPath.contains("./") || normalizedPath.contains("/.")) {
            throw new IllegalArgumentException("Invalid path: directory traversal detected.");
        }

        // Optionally, restrict to specific base directory
        String baseDirectory = "/safe/base/directory";
        if (!normalizedPath.startsWith(baseDirectory)) {
            throw new IllegalArgumentException("Invalid path: outside of allowed directory.");
        }

        return normalizedPath;
    }

    public static void main(String[] args) {
        try {
            String safePath = sanitizePath("some/valid/path.txt");
            System.out.println("Sanitized Path: " + safePath);
        } catch (IllegalArgumentException e) {
