```java
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;

public class PasswordHasher {

    public static String hashPassword(String password) {
        byte[] salt = getSalt();
        byte[] hashedPassword = hash(password, salt);
        return bytesToHex(salt) + ":" + bytesToHex(hashedPassword);
    }

    public static boolean verifyPassword(String originalPassword, String storedHash) {
        String[] parts = storedHash.split(":");
        byte[] salt = hexToBytes(parts[0]);
        byte[] hashToVerify = hash(originalPassword, salt);
        return bytesToHex(hashToVerify).equals(parts[1]);
    }

    private static byte[] hash(String password, byte[] salt) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            md.update(salt);
            return md.digest(password.getBytes());
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    private static byte[] getSalt() {
        byte[] salt = new byte[16];
        new SecureRandom().nextBytes(salt);
        return salt;
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    private static byte[] hexToBytes(String hex) {
        int len = hex.length();
        byte[] data = new byte[len / 2];
        for (int i = 0; i < len; i += 2) {
            data[i / 2] = (byte) ((Character.digit(hex.charAt(i), 16) << 4)
                                 + Character.digit(hex.charAt(i + 1), 16));
        }
        return data;
    }

    public static void main(String[] args) {
        String password = "mySecurePassword";
        String hashed = hashPassword(password);
        System.out.println("Hashed Password: " + hashed);
        System.out.println("Password Verified: " + verifyPassword(password, hashed));
    }
}
