public class InputSanitizer {

    public static String sanitizeInput(String input) {
        if (input == null) {
            return null;
        }

        // Remove leading and trailing whitespace
        String sanitized = input.trim();

        // Replace HTML tags
        sanitized = sanitized.replaceAll("<[^>]*>", "");

        // Escape special characters
        sanitized = sanitized.replace("&", "&amp;");
        sanitized = sanitized.replace("\"", "&quot;");
        sanitized = sanitized.replace("'", "&#39;");
        sanitized = sanitized.replace("<", "&lt;");
        sanitized = sanitized.replace(">", "&gt;");

        // Remove any script tags
        sanitized = sanitized.replaceAll("(?i)<script[^>]*>.*?</script>", "");

        // Remove SQL injection patterns
        sanitized = sanitized.replaceAll("(?i)(--|;|\\b(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|WHERE|FROM|EXEC|CAST|ALTER|CREATE|TRUNCATE|REPLACE|SHOW|DESCRIBE|DECLARE|JOIN|LIKE|IN|AND|OR|NOT|IS|NULL|EXECUTE|GRANT|REVOKE|SET|BEGIN|END|COMMIT|ROLLBACK|SAVEPOINT|LOCK|UNLOCK|TABLE|COLUMN|CONCAT|DATABASE|USER|PASSWORD|IF|THEN|ELSE|CASE|WHEN|THEN|ENDIF|BETWEEN|EXISTS|LIMIT|OFFSET|ORDER|GROUP|BY|HAVING|DISTINCT|ASC|DESC|AS|FOR|INTO|VALUES|RETURN|FETCH|TO)\\b)", "");

        return sanitized;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('xss')</script> SELECT * FROM users WHERE id = 1; --";
        String cleanInput = sanitizeInput(userInput);
        System.out.println("Sanitized Input: " + cleanInput);
    }
}
