public class InputSanitizer {

    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        // Remove leading and trailing whitespace
        input = input.trim();

        // Remove any HTML tags
        input = input.replaceAll("<[^>]*>", "");

        // Remove any SQL injection attempts
        input = input.replaceAll("(['\";--])", "");

        // Escape special characters for safe output
        input = input.replace("&", "&amp;")
                     .replace("<", "&lt;")
                     .replace(">", "&gt;")
                     .replace("\"", "&quot;")
                     .replace("'", "&#39;");

        // Limit input length (for example, 1000 characters)
        if (input.length() > 1000) {
            input = input.substring(0, 1000);
        }

        return input;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script> Hello World; DROP TABLE users;";
        String sanitizedInput = sanitize(userInput);
        System.out.println("Sanitized Input: " + sanitizedInput);
    }
}
