import java.nio.charset.StandardCharsets;
import java.util.Base64;

public class DataEncryptor {

    public static String encrypt_data(String data, String key) {
        // Simple XOR encryption for demonstration purposes
        StringBuilder encrypted = new StringBuilder();
        for (int i = 0; i < data.length(); i++) {
            char dataChar = data.charAt(i);
            char keyChar = key.charAt(i % key.length());
            char encryptedChar = (char) (dataChar ^ keyChar);
            encrypted.append(encryptedChar);
        }
        // Encode to Base64 to ensure the result is a valid string
        return Base64.getEncoder().encodeToString(encrypted.toString().getBytes(StandardCharsets.UTF_8));
    }

    public static void main(String[] args) {
        String data = "SensitiveData";
        String key = "SecretKey";

        String encryptedData = encrypt_data(data, key);
        System.out.println("Encrypted Data: " + encryptedData);
    }
}
