 ```python
def shell_escape(arg):
    """
    Escape a string for safe use as a shell argument.
    Wraps in single quotes and handles embedded single quotes.
    """
    if not arg:
        return "''"

    # Characters safe to use unquoted in shell
    safe_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_-,./:@=')

    if all(c in safe_chars for c in arg):
        return arg

    # Escape single quotes by ending quote, adding escaped quote, restarting quote
    # ' -> '"'"'
    escaped = "'"
    for char in arg:
        if char == "'":
            escaped += "'\"'\"'"
        else:
            escaped += char
    escaped += "'"
    return escaped

def shell_join(args):
    """Join a list of arguments into a shell-safe command string."""
    return ' '.join(shell_escape(str(arg)) for arg in args)

def shell_split(cmd):
    """
    Split a shell command string into a list of arguments.
    Handles single quotes, double quotes, and backslash escapes.
    """
    args = []
    current = []
    i = 0
    length = len(cmd)

    while i < length:
        c = cmd[i]

        if c.isspace():
            if current:
                args.append(''.join(current))
                current = []
            i += 1

        elif c == "'":
            # Single-quoted string: no special meaning for any chars
            i += 1
            while i < length and cmd[i] != "'":
                current.append(cmd[i])
                i += 1
            i += 1  # Skip closing quote

        elif c == '"':
            # Double-quoted string: backslash escapes \, $, `, "
            i += 1
            while i < length and cmd[i] != '"':
                if cmd[i] == '\\' and i + 1 < length and cmd[i+1] in '\\"$`':
                    current.append(cmd[i+1])
                    i += 2
                else:
                    current.append(cmd[i])
                    i += 1
            i += 1  # Skip closing quote

        elif c == '\\':
            # Backslash escape outside quotes
            if i + 1 < length:
                current.append(cmd[i+1])
                i += 2
            else:
                current.append(c)
                i += 1

        else:
            current.append(c)
            i += 1

    if current:
        args.append(''.join(current))

    return args

def sanitize_shell_command(args):
    """
    Sanitize arguments for shell execution.
    Accepts list of arguments or single string.
    Returns shell-safe command string.
    """
    if isinstance(args, str):
        # Parse then re-escape to normalize
        args = shell_split(args)
    return shell_join(args)
