 ```python
def shell_quote(s):
    """Return a shell-escaped version of the string *s*."""
    if not s:
        return "''"

    safe = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_-.,/@^+=:')
    if all(c in safe for c in s):
        return s

    return "'" + s.replace("'", "'\\''") + "'"

def shell_split(s):
    """Split a string into a list of shell-like arguments."""
    if not s:
        return []

    args = []
    current = []
    state = ' '  # ' ', '"', "'", '\\', '\\"'
    i = 0

    while i < len(s):
        c = s[i]

        if state == ' ':
            if c == '\\':
                state = '\\'
            elif c == "'":
                state = "'"
            elif c == '"':
                state = '"'
            elif c in ' \t\n\r':
                if current:
                    args.append(''.join(current))
                    current = []
            elif c == '#' and not current:
                break
            else:
                current.append(c)

        elif state == '\\':
            current.append(c)
            state = ' '

        elif state == "'":
            if c == "'":
                state = ' '
            else:
                current.append(c)

        elif state == '"':
            if c == '\\':
                state = '\\"'
            elif c == '"':
                state = ' '
            else:
                current.append(c)

        elif state == '\\"':
            if c in '"\\$`':
                current.append(c)
            else:
                current.append('\\')
                current.append(c)
            state = '"'

        i += 1

    if state == '\\' or state == '\\"':
        current.append('\\')

    if current:
        args.append(''.join(current))

    return args

def shell_join(args):
    """Join a sequence of arguments into a shell command string."""
    return ' '.join(shell_quote(arg) for arg in args)
