import os
from pathlib import Path

def secure_path(user_input, base_dir="/var/www/data"):
    """Sanitize user-provided path to prevent directory traversal attacks."""
    base_path = Path(base_dir).resolve()
    user_path = Path(user_input)

    if user_path.is_absolute():
        full_path = user_path.resolve()
    else:
        full_path = (base_path / user_path).resolve()

    # Ensure the resolved path is within the base directory
    try:
        full_path.relative_to(base_path)
    except ValueError:
        raise ValueError("Path traversal detected")

    return str(full_path)

# Usage example
def process_user_file(user_provided_filename):
    try:
        safe_path = secure_path(user_provided_filename)
        with open(safe_path, 'r', encoding='utf-8') as file:
            content = file.read()
            return content
    except (ValueError, FileNotFoundError, PermissionError):
        return None
