```javascript
function sanitizeInput(input, options = {}) {
  const {
    maxLength = 10000,
    maxDepth = 10,
    allowHTML = false,
    stripControls = true,
    normalizeUnicode = true,
    preventPrototypePollution = true
  } = options;

  const seen = new WeakSet();
  const controlCharsRegex = /[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g;
  const htmlEntities = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#x27;',
    '/': '&#x2F;',
    '`': '&#x60;',
    '=': '&#x3D;'
  };

  function escapeHtml(str) {
    if (allowHTML) return str;
    return str.replace(/[&<>"'`=/]/g, char => htmlEntities[char]);
  }

  function sanitizeString(str) {
    if (typeof str !== 'string') return str;

    let cleaned = str;

    if (normalizeUnicode && cleaned.normalize) {
      cleaned = cleaned.normalize('NFC');
    }

    cleaned = cleaned.trim();

    if (stripControls) {
      cleaned = cleaned.replace(controlCharsRegex, '');
    }

    cleaned = escapeHtml(cleaned);

    if (cleaned.length > maxLength) {
      cleaned = cleaned.substring(0, maxLength);
    }

    return cleaned;
  }

  function sanitizeKey(key) {
    if (typeof key !== 'string') return String(key);

    if (preventPrototypePollution) {
      if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
        return '_' + key;
      }
    }

    return sanitizeString(key);
  }

  function sanitize(value, depth = 0) {
    if (depth > maxDepth) return null;
    if (value === null || value === undefined) return value;

    const type = typeof value;

    if (type === 'string') return sanitizeString(value);

    if (type === 'number') {
      if (!isFinite(value)) return 0;
      if (value > Number.MAX_SAFE_INTEGER) return Number.MAX_SAFE_INTEGER;
      if (value < Number.MIN_SAFE_INTEGER) return Number.MIN_SAFE_INTEGER;
      return value;
    }

    if (type === 'boolean') return value;
    if (type === 'function' || type === 'symbol') return undefined;

    if (type === 'bigint') {
      return value > BigInt(Number.MAX_SAFE_INTEGER) ? String(value) : Number(value);
    }

    if (type === 'object') {
      if (seen.has(value)) return null;
      seen.add(value);

      let result;

      if (Array.isArray(value)) {
        result = [];
        for (let i = 0; i < value.length; i++) {
          const item = sanitize(value[i], depth + 1);
          if (item !== undefined) result.push(item);
        }
      } else if (value instanceof Date) {
        const time = value.getTime();
        result = isNaN(time) ? null : new Date(time);
      } else if (value instanceof RegExp) {
        try {
          result = new RegExp(sanitizeString(value.source), value.flags);
        } catch {
          result = null;
        }
      } else {
        result = {};
        for (const key in value) {
          if (Object.prototype.hasOwnProperty.call(value, key)) {
            const safeKey = sanitizeKey(key);
            const safeValue = sanitize(value[key], depth + 1);
            if (safeValue !== undefined) {
              result[safeKey] = safeValue;
            }
          }
        }
      }

      seen.delete(value);
      return result;
    }

    return undefined;
  }

  return sanitize(input);
}
