class UniversalSanitizer {
  constructor(options = {}) {
    this.options = {
      maxLength: options.maxLength || 10000,
      trimWhitespace: options.trimWhitespace !== false,
      normalizeUnicode: options.normalizeUnicode !== false,
      removeNullBytes: options.removeNullBytes !== false,
      strictMode: options.strictMode || false,
      ...options
    };
  }

  sanitize(input, context = 'general') {
    if (input === null || input === undefined) return input;

    if (typeof input === 'string') {
      return this._sanitizeString(input, context);
    }

    if (Array.isArray(input)) {
      return input.map(item => this.sanitize(item, context));
    }

    if (typeof input === 'object' && input !== null) {
      return this._sanitizeObject(input, context);
    }

    return input;
  }

  _sanitizeString(str, context) {
    if (typeof str !== 'string') str = String(str);

    if (this.options.removeNullBytes) {
      str = str.replace(/\x00/g, '');
    }

    if (this.options.normalizeUnicode) {
      str = str.normalize('NFKC');
    }

    str = str.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g, '');

    if (this.options.trimWhitespace) {
      str = str.trim();
    }

    switch(context) {
      case 'html':
        str = this._escapeHtml(str);
        break;
      case 'sql':
        str = this._sanitizeSql(str);
        break;
      case 'command':
      case 'shell':
        str = this._sanitizeCommand(str);
        break;
      case 'json':
        str = this._sanitizeJson(str);
        break;
      case 'url':
        str = this._sanitizeUrl(str);
        break;
      case 'email':
        str = this._sanitizeEmail(str);
        break;
      case 'alphanumeric':
        str = str.replace(/[^a-zA-Z0-9]/g, '');
        break;
      case 'strict':
        str = str.replace(/[^a-zA-Z0-9_\-\.]/g, '');
        break;
    }

    if (this.options.maxLength && str.length > this.options.maxLength) {
      str = str.substring(0, this.options.maxLength);
    }

    return str;
  }

  _sanitizeObject(obj, context) {
    const sanitized = {};
    for (const [key, value] of Object.entries(obj)) {
      const cleanKey = this._sanitizeString(key, 'strict');
      sanitized[cleanKey] = this.sanitize(value, context);
    }
    return sanitized;
  }

  _escapeHtml(str) {
    const entities = {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#x27;',
      '/': '&#x2F;',
      '`': '&#x60;',
      '=': '&#x3D;'
    };
    return str.replace(/[&<>"'`=/]/g, s => entities[s]);
  }

  _sanitizeSql(str) {
    str = str.replace(/(\/\*|\*\/|--|#|\/\/)/g, '');
    str = str.replace(/'/g, "''");
    if (this.options.strictMode) {
      str = str.replace(/(\b(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|ALTER|CREATE|EXEC|EXECUTE|TRUNCATE)\b)/gi, '');
    }
    return str;
  }

  _sanitizeCommand(str) {
    return str.replace(/[;&|`$(){}[\]\\]/g, '');
  }

  _sanitizeJson(str) {
    try {
      return JSON.stringify(JSON.parse(str));
    } catch {
      return this._escapeHtml(str);
    }
  }

  _sanitizeUrl(str) {
    try {
      const url = new URL(str);
      if (!['http:', 'https:'].includes(url.protocol)) return '';
      return url.href;
    } catch {
      return encodeURIComponent(str);
    }
  }

  _sanitizeEmail(str) {
    str = str.toLowerCase().trim().replace(/[^a-z0-9@._+-]/g, '');
    return /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(str) ? str : '';
  }

  static clean(input, context = 'general', options = {}) {
    return new UniversalSanitizer(options).sanitize(input, context);
  }

  static html(input, options = {}) {
    return UniversalSanitizer.clean(input, 'html', options);
  }

  static sql(input, options = {}) {
    return UniversalSanitizer.clean(input, 'sql', options);
  }

  static strict(input, options = {}) {
    return UniversalSanitizer.clean(input, 'strict', { ...options, strictMode: true });
  }
}

if (typeof module !== 'undefined' && module.exports) {
  module.exports = UniversalSanitizer;
}
