 ```javascript
const sanitizeInput = (input, options = {}) => {
  const maxLength = options.maxLength || 10000;
  const seen = new WeakMap();

  const cleanString = (str) => {
    if (str.length > maxLength) str = str.substring(0, maxLength);
    return str
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
      .trim()
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;')
      .replace(/\//g, '&#x2F;');
  };

  const clean = (value) => {
    if (value === null || value === undefined) return value;

    const type = typeof value;

    if (type === 'string') return cleanString(value);
    if (type === 'number' || type === 'boolean') return value;
    if (type === 'function' || type === 'symbol') return undefined;

    if (value instanceof Date) return new Date(value.getTime());
    if (value instanceof RegExp) {
      try {
        return new RegExp(cleanString(value.source), value.flags);
      } catch (e) {
        return undefined;
      }
    }

    if (Array.isArray(value)) {
      if (seen.has(value)) return seen.get(value);
      const arr = [];
      seen.set(value, arr);
      for (let i = 0; i < value.length; i++) {
        arr[i] = clean(value[i]);
      }
      return arr;
    }

    if (type === 'object') {
      if (seen.has(value)) return seen.get(value);
      const obj = {};
      seen.set(value, obj);
      for (const key in value) {
        if (Object.prototype.hasOwnProperty.call(value, key)) {
          if (key === '__proto__' || key === 'constructor' || key === 'prototype') continue;
          const safeKey = clean(key);
          if (safeKey !== undefined) {
            obj[safeKey] = clean(value[key]);
          }
        }
      }
      return obj;
    }

    return undefined;
  };

  return clean(input);
};
