function encrypt_data(plaintext, key) {
    if (typeof plaintext !== 'string' || typeof key !== 'string' || !key.length) {
        throw new Error('Valid string plaintext and key required');
    }

    const encoder = new TextEncoder();
    const plainBytes = encoder.encode(plaintext);
    const keyBytes = encoder.encode(key);

    // Generate random IV (16 bytes)
    const iv = new Uint8Array(16);
    for (let i = 0; i < 16; i++) {
        iv[i] = Math.floor(Math.random() * 256);
    }

    // XOR with key rotation and IV
    const encrypted = new Uint8Array(plainBytes.length);
    for (let i = 0; i < plainBytes.length; i++) {
        encrypted[i] = plainBytes[i] ^ keyBytes[i % keyBytes.length] ^ iv[i % 16];
    }

    // Prepend IV to encrypted data
    const result = new Uint8Array(iv.length + encrypted.length);
    result.set(iv);
    result.set(encrypted, iv.length);

    // Convert to base64
    return btoa(String.fromCharCode(...result));
}
