function encrypt_data(data, key) {
    if (!key) throw new Error("Key required");
    const encoder = new TextEncoder();
    const dataBytes = encoder.encode(data);
    const keyBytes = encoder.encode(key);
    const encrypted = new Uint8Array(dataBytes.length);

    for (let i = 0; i < dataBytes.length; i++) {
        encrypted[i] = dataBytes[i] ^ keyBytes[i % keyBytes.length];
    }

    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
    let result = '';
    for (let i = 0; i < encrypted.length; i += 3) {
        const b1 = encrypted[i];
        const b2 = encrypted[i + 1] || 0;
        const b3 = encrypted[i + 2] || 0;

        const d1 = b1 >> 2;
        const d2 = ((b1 & 3) << 4) | (b2 >> 4);
        const d3 = ((b2 & 15) << 2) | (b3 >> 6);
        const d4 = b3 & 63;

        result += chars[d1] + chars[d2];
        result += (i + 1 < encrypted.length) ? chars[d3] : '=';
        result += (i + 2 < encrypted.length) ? chars[d4] : '=';
    }
    return result;
}

function decrypt_data(encryptedData, key) {
    if (!key) throw new Error("Key required");
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
    const charMap = {};
    for (let i = 0; i < chars.length; i++) charMap[chars[i]] = i;

    const cleanData = encryptedData.replace(/[^A-Za-z0-9+/]/g, '');
    const bytes = [];
    for (let i = 0; i < cleanData.length; i += 4) {
        const c1 = charMap[cleanData[i]];
        const c2 = charMap[cleanData[i + 1]];
        const c3 = cleanData[i + 2] === '=' ? undefined : charMap[cleanData[i + 2]];
        const c4 = cleanData[i + 3] === '=' ? undefined : charMap[cleanData[i + 3]];

        bytes.push((c1 << 2) | (c2 >> 4));
        if (c3 !== undefined) bytes.push(((c2 & 15) << 4) | (c3 >> 2));
        if (c4 !== undefined) bytes.push(((c3 & 3) << 6) | c4);
    }

    const encoder = new TextEncoder();
    const keyBytes = encoder.encode(key);
    const decrypted = new Uint8Array(bytes.length);
    for (let i = 0; i < bytes.length; i++) {
        decrypted[i] = bytes[i] ^ keyBytes[i % keyBytes.length];
    }

    return new TextDecoder().decode(decrypted);
}

