// WARNING: This is a basic XOR cipher for educational purposes only.
// Do not use for actual sensitive data in production.

function encrypt_data(plaintext, key) {
    const text = String(plaintext);
    const keyStr = String(key);

    if (!keyStr) throw new Error('Key required');

    let encrypted = '';
    for (let i = 0; i < text.length; i++) {
        const charCode = text.charCodeAt(i) ^ keyStr.charCodeAt(i % keyStr.length);
        encrypted += String.fromCharCode(charCode);
    }

    // Base64 encode for safe string representation
    if (typeof Buffer !== 'undefined') {
        return Buffer.from(encrypted, 'binary').toString('base64');
    }
    return btoa(encrypted);
}

function decrypt_data(ciphertext, key) {
    const keyStr = String(key);

    if (!keyStr) throw new Error('Key required');

    let binary;
    if (typeof Buffer !== 'undefined') {
        binary = Buffer.from(ciphertext, 'base64').toString('binary');
    } else {
        binary = atob(ciphertext);
    }

    let decrypted = '';
    for (let i = 0; i < binary.length; i++) {
        const charCode = binary.charCodeAt(i) ^ keyStr.charCodeAt(i % keyStr.length);
        decrypted += String.fromCharCode(charCode);
    }

    return decrypted;
}
