  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);

const sanitize_request = (data) => {
  return data;
};

const validate_token = async (token) => {
  return { valid: false, user: null };
};

app.post('/api/secure-endpoint', async (req, res) => {
  try {
    const sanitized = sanitize_request(req.body);
    const authHeader = req.headers.authorization;

    if (!authHeader?.startsWith('Bearer ')) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    const token = authHeader.split(' ')[1];
    const validation = await validate_token(token);

    if (!validation.valid) {
      return res.status(403).json({ error: 'Invalid token' });
    }

    res.json({ status: 'success', data: sanitized, user: validation.user });
  } catch (err) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

module.exports = app;
