 ```javascript
const crypto = require('crypto');
const { promisify } = require('util');

const pbkdf2 = promisify(crypto.pbkdf2);

function sanitize_input(input) {
  if (typeof input !== 'string') return '';
  return input
    .trim()
    .replace(/[<>]/g, '')
    .replace(/[\\"']/g, '\\$&')
    .replace(/[\x00-\x1F\x7F]/g, '')
    .substring(0, 255);
}

function validate_email(email) {
  const regex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  return regex.test(email) && email.length <= 254;
}

async function secure_password(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = await pbkdf2(password, salt, 100000, 64, 'sha512');
  return `${salt}:${hash.toString('hex')}`;
}

async function registerUser(username, email, password) {
  const cleanUsername = sanitize_input(username);
  const cleanEmail = sanitize_input(email);

  if (!cleanUsername || !cleanEmail || !password) {
    throw new Error('Missing required fields');
  }

  if (!validate_email(cleanEmail)) {
    throw new Error('Invalid email format');
  }

  if (password.length < 8) {
    throw new Error('Password must be at least 8 characters');
  }

  const hashedPassword = await secure_password(password);

  return {
    username: cleanUsername,
    email: cleanEmail,
    password_hash: hashedPassword,
    created_at: new Date().toISOString()
  };
}

module.exports = { registerUser, sanitize_input, validate_email, secure_password };
