import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.PrintWriter;
import org.jsoup.Jsoup;
import org.jsoup.safety.Safelist;

public class UserContentController {

    public void displayContent(HttpServletRequest request, HttpServletResponse response) throws Exception {
        response.setContentType("text/html;charset=UTF-8");
        PrintWriter out = response.getWriter();

        String rawInput = request.getParameter("userInput");
        String cleanHtml = sanitize_html(rawInput);

        out.println("<!DOCTYPE html>");
        out.println("<html>");
        out.println("<head><title>User Content</title></head>");
        out.println("<body>");
        out.println("<div class=\"user-content\">" + cleanHtml + "</div>");
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitize_html(String html) {
        if (html == null || html.isEmpty()) {
            return "";
        }
        return Jsoup.clean(html, Safelist.basic());
    }
}
