import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

public class XssSafeRenderer {

    private String prevent_xss(String input) {
        if (input == null) {
            return "";
        }
        return input.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&#x27;");
    }

    public void render(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("comment");

        // Call prevent_xss() on user input before rendering to the page
        String safeHtml = prevent_xss(userInput);

        response.setContentType("text/html");
        response.getWriter().write("<div>" + safeHtml + "</div>");
    }
}
