 ```java
import java.util.ArrayList;
import java.util.List;

public class ShellCommandSanitizer {

    public static String sanitize(String argument) {
        if (argument == null || argument.isEmpty()) {
            return "''";
        }

        if (argument.matches("^[a-zA-Z0-9_\\-\\.\\/]+$")) {
            return argument;
        }

        return "'" + argument.replace("'", "'\\''") + "'";
    }

    public static String[] split(String command) {
        List<String> tokens = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean inSingleQuotes = false;
        boolean inDoubleQuotes = false;
        boolean escaped = false;

        for (int i = 0; i < command.length(); i++) {
            char c = command.charAt(i);

            if (escaped) {
                current.append(c);
                escaped = false;
                continue;
            }

            if (c == '\\' && !inSingleQuotes) {
                escaped = true;
                continue;
            }

            if (c == '\'' && !inDoubleQuotes) {
                inSingleQuotes = !inSingleQuotes;
                continue;
            }

            if (c == '"' && !inSingleQuotes) {
                inDoubleQuotes = !inDoubleQuotes;
                continue;
            }

            if (Character.isWhitespace(c) && !inSingleQuotes && !inDoubleQuotes) {
                if (current.length() > 0) {
                    tokens.add(current.toString());
                    current = new StringBuilder();
                }
            } else {
                current.append(c);
            }
        }

        if (escaped) {
            current.append('\\');
        }

        if (current.length() > 0) {
            tokens.add(current.toString());
        }

        return tokens.toArray(new String[0]);
    }

    public static String join(String[] arguments) {
        if (arguments == null || arguments.length == 0) {
            return "";
        }

        StringBuilder result = new StringBuilder();
        for (int i = 0; i < arguments.length; i++) {
            if (i > 0) {
                result.append(' ');
            }
            result.append(sanitize(arguments[i]));
        }
        return result.toString();
    }

    public static boolean isDangerous(String input) {
        if (input == null) return false;
        return input.matches(".*[|;\\&\\$\\(\\)`<>\\\\!\\*\\?\\[\\]\\{\\}#~%\\n\\r].*");
    }

    public static String escapeDangerous(String input) {
        if (input == null) return "";
        return input.replaceAll("([|;\\&\\$\\(\\)`<>\\\\!\\*\\?\\[\\]\\{\\}#~%\\n\\r])", "\\\\$1");
    }
}
