```java
public class ShellUtils {
    /**
     * Escapes a string for safe use in POSIX shell commands (sh, bash, zsh, dash).
     * Wraps the argument in single quotes and handles embedded single quotes.
     */
    public static String escape_shell(String arg) {
        if (arg == null || arg.isEmpty()) {
            return "''";
        }
        // Replace ' with '"'"' (close quote, open double quote, quote, close double quote, open quote)
        // In single quotes, everything is literal except single quote itself.
        // To escape a single quote: end single quote, insert escaped quote, restart single quote.
        return "'" + arg.replace("'", "'\\''") + "'";
    }

    /**
     * Escapes a string for Windows Command Prompt (cmd.exe).
     * Uses double quotes and escapes special characters.
     */
    public static String escape_shell_windows(String arg) {
        if (arg == null || arg.isEmpty()) {
            return "\"\"";
        }

        // Escape special characters with ^
        StringBuilder escaped = new StringBuilder();
        escaped.append('\"');

        for (char c : arg.toCharArray()) {
            switch (c) {
                case '\"':
                case '\\':
                case '&':
                case '|':
                case '(':
                case ')':
                case '<':
                case '>':
                case '^':
                    escaped.append('^');
                    break;
                case '!':
                    // Delayed expansion
                    escaped.append('^');
                    break;
                case '%':
                    // Need to double % to escape
                    escaped.append('%');
                    break;
            }
            escaped.append(c);
        }

        escaped.append('\"');
        return escaped.toString();
    }
}
