 ```java
import java.io.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.regex.Pattern;

public class SecureExecutor {
    private static final Set<String> ALLOWED_COMMANDS = Set.of("ls", "cat", "echo", "pwd", "whoami");
    private static final Pattern SAFE_ARG_PATTERN = Pattern.compile("^[a-zA-Z0-9_./-]+$");
    private static final long TIMEOUT_SECONDS = 10;

    public static String safe_exec(String command, List<String> arguments) throws Exception {
        if (command == null || command.trim().isEmpty()) {
            throw new IllegalArgumentException("Command cannot be empty");
        }

        if (!ALLOWED_COMMANDS.contains(command)) {
            throw new SecurityException("Command not in allowlist: " + command);
        }

        List<String> cmdList = new ArrayList<>();
        cmdList.add(command);

        for (String arg : arguments) {
            if (arg != null && !arg.isEmpty()) {
                if (!SAFE_ARG_PATTERN.matcher(arg).matches()) {
                    throw new SecurityException("Invalid argument characters: " + arg);
                }
                cmdList.add(arg);
            }
        }

        ProcessBuilder pb = new ProcessBuilder(cmdList);
        pb.redirectErrorStream(true);
        pb.directory(new File(System.getProperty("user.dir")));

        Process process = pb.start();
        ExecutorService executor = Executors.newSingleThreadExecutor();

        Future<String> outputFuture = executor.submit(() -> {
            StringBuilder output = new StringBuilder();
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    output.append(line).append(System.lineSeparator());
                }
            }
            return output.toString();
        });

        try {
            boolean finished = process.waitFor(TIMEOUT_SECONDS, TimeUnit.SECONDS);
            if (!finished) {
                process.destroyForcibly();
                throw new TimeoutException("Command execution timed out");
            }

            String output = outputFuture.get(TIMEOUT_SECONDS, TimeUnit.SECONDS);
            int exitCode = process.exitValue();

            if (exitCode != 0) {
                throw new RuntimeException("Command failed with exit code: " + exitCode);
            }

            return output;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            process.destroyForcibly();
            throw new RuntimeException("Execution interrupted");
        } finally {
            executor.shutdownNow();
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter command: ");
        String userCommand = scanner.nextLine().trim();

        System.out.print("Enter arguments (space-separated): ");
        String userArgsLine = scanner.nextLine();
        List<String> userArgs = Arrays.asList(userArgsLine.trim().split("\\s+"));

        try {
            String result = safe_exec(userCommand, userArgs);
            System.out.println("Output:\n" + result);
        } catch (SecurityException e) {
            System.err.println("Security violation: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("Execution error: " + e.getMessage());
        } finally {
            scanner.close();
        }
    }
}
