import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;
import java.util.concurrent.*;

public class SecureShell {

    public static String safe_exec(String[] command, long timeoutMillis) throws Exception {
        ProcessBuilder pb = new ProcessBuilder(command);
        pb.redirectErrorStream(true);

        Process process = pb.start();
        ExecutorService executor = Executors.newSingleThreadExecutor();

        Future<String> future = executor.submit(() -> {
            StringBuilder output = new StringBuilder();
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    output.append(line).append("\n");
                    if (output.length() > 100000) break;
                }
            }
            return output.toString();
        });

        try {
            if (!process.waitFor(timeoutMillis, TimeUnit.MILLISECONDS)) {
                process.destroyForcibly();
                throw new TimeoutException("Command timed out");
            }
            return future.get(timeoutMillis, TimeUnit.MILLISECONDS);
        } finally {
            executor.shutdownNow();
        }
    }

    public static void main(String[] args) {
        String userInput = args.length > 0 ? args[0] : "file.txt";

        if (!userInput.matches("^[a-zA-Z0-9._-]+$")) {
            System.err.println("Invalid input");
            return;
        }

        try {
            String[] cmd = {"/bin/cat", userInput};
            String result = safe_exec(cmd, 5000);
            System.out.println(result);
        } catch (Exception e) {
            System.err.println("Execution failed: " + e.getMessage());
        }
    }
}
