import java.io.File;
import java.io.IOException;
import java.text.Normalizer;
import java.util.ArrayList;
import java.util.List;
import java.util.regex.Pattern;

public class PathSanitizer {
    private static final Pattern NULL_BYTE = Pattern.compile("\0");
    private static final Pattern CONTROL_CHARS = Pattern.compile("[\\x00-\\x1F\\x7F]");
    private final String baseDir;
    private final boolean allowAbsolute;

    public PathSanitizer(String baseDirectory) {
        this(baseDirectory, false);
    }

    public PathSanitizer(String baseDirectory, boolean allowAbsolute) {
        if (baseDirectory == null || baseDirectory.isEmpty()) {
            throw new IllegalArgumentException("Base directory required");
        }
        this.baseDir = baseDirectory.replace('\\', '/').replaceAll("/+$", "");
        this.allowAbsolute = allowAbsolute;
    }

    public String sanitize(String input) throws SecurityException {
        if (input == null) {
            throw new SecurityException("Path cannot be null");
        }

        String path = Normalizer.normalize(input, Normalizer.Form.NFC);
        path = NULL_BYTE.matcher(path).replaceAll("");
        path = CONTROL_CHARS.matcher(path).replaceAll("");
        path = path.replace('\\', '/').trim();

        if (!allowAbsolute) {
            if (path.startsWith("/") || path.startsWith("~") || 
                (path.length() > 1 && path.charAt(1) == ':')) {
                throw new SecurityException("Absolute paths not allowed: " + input);
            }
        }

        String[] components = path.split("/");
        List<String> stack = new ArrayList<>();

        for (String component : components) {
            if (component.isEmpty() || ".".equals(component)) {
                continue;
            }
            if ("..".equals(component)) {
                if (stack.isEmpty()) {
                    throw new SecurityException("Directory traversal attempt: " + input);
                }
                stack.remove(stack.size() - 1);
            } else {
                if (component.contains("..")) {
                    throw new SecurityException("Invalid component: " + component);
                }
                if (component.matches(".*[:|?*<>\"].*")) {
                    throw new SecurityException("Illegal characters in: " + component);
                }
                stack.add(component);
            }
        }

        StringBuilder result = new StringBuilder();
        for (int i = 0; i < stack.size(); i++) {
            if (i > 0) result.append('/');
            result.append(stack.get(i));
        }

        String sanitized = result.toString();
        validateWithinBase(sanitized);
        return sanitized;
    }

    private void validateWithinBase(String relativePath) throws SecurityException {
        try {
            File base = new File(baseDir).getCanonicalFile();
            File target = new File(base, relativePath).getCanonicalFile();

            String canonicalBase = base.getAbsolutePath();
            String canonicalTarget = target.getAbsolutePath();

            if (!canonicalTarget.toLowerCase().startsWith(canonicalBase.toLowerCase())) {
                throw new SecurityException("Path escapes base directory");
            }
        } catch (IOException e) {
            throw new SecurityException("Path validation failed: " + e.getMessage());
        }
    }

    public File getSafeFile(String input) throws SecurityException {
        return new File(baseDir, sanitize(input));
    }
}
