import java.io.File;
import java.io.UnsupportedEncodingException;
import java.net.URLDecoder;
import java.util.ArrayList;
import java.util.List;
import java.util.regex.Pattern;

public class PathSanitizer {
    private static final Pattern ILLEGAL_CHARS = Pattern.compile("[\\x00\\x0a\\x0d\\\\<>:\"|?*\\x7f]");
    private static final Pattern RESERVED_NAMES = Pattern.compile("^(CON|PRN|AUX|NUL|COM[1-9]|LPT[1-9])(\\.|$)", Pattern.CASE_INSENSITIVE);
    private final String baseDirectory;
    private final boolean allowAbsolute;

    public PathSanitizer(String baseDirectory) {
        this(baseDirectory, false);
    }

    public PathSanitizer(String baseDirectory, boolean allowAbsolutePaths) {
        if (baseDirectory == null || baseDirectory.isEmpty()) {
            throw new IllegalArgumentException("Base directory required");
        }
        this.baseDirectory = normalizeSeparators(baseDirectory);
        this.allowAbsolute = allowAbsolutePaths;
    }

    private String normalizeSeparators(String path) {
        return path.replace('\\', '/').replaceAll("/+", "/");
    }

    public String sanitize(String input) throws SecurityException {
        if (input == null || input.isEmpty()) {
            throw new SecurityException("Null or empty path");
        }

        String decoded = urlDecode(input);
        String normalized = normalizeSeparators(decoded).replace("\0", "");

        if (normalized.contains("..")) {
            normalized = resolveTraversal(normalized);
        }

        if (!allowAbsolute) {
            if (normalized.startsWith("/") || (normalized.length() > 1 && normalized.charAt(1) == ':')) {
                throw new SecurityException("Absolute paths not allowed");
            }
        } else {
            if (normalized.startsWith("/")) {
                normalized = normalized.substring(1);
            }
            if (normalized.length() > 1 && normalized.charAt(1) == ':') {
                normalized = normalized.substring(2).replaceFirst("^/+", "");
            }
        }

        validateComponents(normalized);
        return normalized;
    }

    private String resolveTraversal(String path) throws SecurityException {
        String[] parts = path.split("/");
        List<String> stack = new ArrayList<>();

        for (String part : parts) {
            if (part.isEmpty() || ".".equals(part)) continue;

            if ("..".equals(part)) {
                if (stack.isEmpty()) {
                    throw new SecurityException("Directory traversal detected");
                }
                stack.remove(stack.size() - 1);
            } else {
                stack.add(part);
            }
        }

        StringBuilder result = new StringBuilder();
        if (path.startsWith("/")) result.append("/");

        for (int i = 0; i < stack.size(); i++) {
            if (i > 0) result.append("/");
            result.append(stack.get(i));
        }

        return result.toString();
    }

    private void validateComponents(String path) throws SecurityException {
        for (String component : path.split("/")) {
            if (component.isEmpty()) continue;

            if (ILLEGAL_CHARS.matcher(component).find()) {
                throw new SecurityException("Illegal characters in: " + component);
            }
            if (RESERVED_NAMES.matcher(component).matches()) {
                throw new SecurityException("Reserved name: " + component);
            }
            if (component.startsWith(" ") || component.endsWith(" ") || component.endsWith(".")) {
                throw new SecurityException("Invalid leading/trailing characters in: " + component);
            }
        }
    }

    private String urlDecode(String input) {
        try {
            return URLDecoder.decode(input, "UTF-8");
        } catch (UnsupportedEncodingException e) {
            return input;
        } catch (IllegalArgumentException e) {
            throw new SecurityException("Invalid URL encoding");
        }
    }

    public File toSafeFile(String userPath) throws SecurityException {
        String sanitized = sanitize(userPath);
        File file = new File(baseDirectory, sanitized);

        try {
            String canonical = file.getCanonicalPath();
            String baseCanonical = new File(baseDirectory).getCanonicalPath();

            if (!canonical.startsWith(baseCanonical)) {
                throw new SecurityException("Path escapes base directory");
            }
            return new File(canonical);
        } catch (Exception e) {
            if (e instanceof SecurityException) throw (SecurityException) e;
            throw new SecurityException("Path validation failed: " + e.getMessage());
        }
    }
}
