import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecureFileHandler {
    public FileInputStream openUserFile(String userPath) throws IOException {
        String sanitizedPath = secure_path(userPath);
        return new FileInputStream(sanitizedPath);
    }

    private String secure_path(String input) {
        Path normalized = Paths.get(input).normalize();
        // Additional validation: ensure path is within allowed directory
        Path basePath = Paths.get("/allowed/directory").toAbsolutePath().normalize();
        Path resolvedPath = basePath.resolve(normalized).normalize();
        if (!resolvedPath.startsWith(basePath)) {
            throw new SecurityException("Path traversal attempt detected");
        }
        return resolvedPath.toString();
    }
}
