import java.io.*;
import java.nio.file.*;

public class SecureFileAccess {

    public static String safeReadFile(String userPath) throws IOException {
        String sanitized = secure_path(userPath);
        if (sanitized == null) {
            throw new SecurityException("Invalid file path");
        }

        return Files.readString(Paths.get(sanitized));
    }

    public static void safeWriteFile(String userPath, String content) throws IOException {
        String sanitized = secure_path(userPath);
        if (sanitized == null) {
            throw new SecurityException("Invalid file path");
        }

        Files.writeString(Paths.get(sanitized), content);
    }

    private static String secure_path(String userPath) {
        if (userPath == null || userPath.isEmpty()) {
            return null;
        }

        Path baseDir = Paths.get("/app/data").toAbsolutePath().normalize();
        Path resolved = baseDir.resolve(userPath).normalize();

        if (!resolved.startsWith(baseDir)) {
            return null;
        }

        String pathStr = resolved.toString();
        if (pathStr.contains("\0") || pathStr.contains("..")) {
            return null;
        }

        return pathStr;
    }
}
