import java.text.Normalizer;
import java.util.regex.Pattern;

public class InputSanitizer {

    private static final Pattern NULL_BYTES = Pattern.compile("\\x00");
    private static final Pattern CONTROL_CHARS = Pattern.compile("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]");
    private static final Pattern PATH_TRAVERSAL = Pattern.compile("(?i)(\\.\\.[/\\\\])");
    private static final Pattern SHELL_METACHARS = Pattern.compile("[|&;`$(){}\\[\\]\\\\'\"<>*?#~]");
    private static final Pattern HTML_TAGS = Pattern.compile("<[^>]*>");

    public static String sanitize(String input) {
        if (input == null) return null;

        String normalized = Normalizer.normalize(input, Normalizer.Form.NFKC);
        normalized = NULL_BYTES.matcher(normalized).replaceAll("");
        normalized = CONTROL_CHARS.matcher(normalized).replaceAll("");

        return normalized.trim();
    }

    public static String sanitizeForHtml(String input) {
        if (input == null) return null;

        String sanitized = sanitize(input);
        StringBuilder sb = new StringBuilder();

        for (char c : sanitized.toCharArray()) {
            switch (c) {
                case '<': sb.append("&lt;"); break;
                case '>': sb.append("&gt;"); break;
                case '"': sb.append("&quot;"); break;
                case '\'': sb.append("&#x27;"); break;
                case '&': sb.append("&amp;"); break;
                case '/': sb.append("&#x2F;"); break;
                default: sb.append(c); break;
            }
        }
        return sb.toString();
    }

    public static String sanitizeForSql(String input) {
        if (input == null) return null;
        String sanitized = sanitize(input);
        return sanitized.replace("'", "''").replace("\\", "\\\\");
    }

    public static String sanitizeForCommand(String input) {
        if (input == null) return null;
        String sanitized = sanitize(input);
        return SHELL_METACHARS.matcher(sanitized).replaceAll("");
    }

    public static String sanitizeForFilePath(String input) {
        if (input == null) return null;

        String sanitized = sanitize(input);
        sanitized = PATH_TRAVERSAL.matcher(sanitized).replaceAll("");

        if (sanitized.startsWith("/") || sanitized.startsWith("\\")) {
            sanitized = sanitized.substring(1);
        }
        if (sanitized.length() > 1 && sanitized.charAt(1) == ':') {
            sanitized = sanitized.substring(2);
        }

        return sanitized.replaceAll("[<>:\"|?*]", "");
    }

    public static String sanitizeStrict(String input) {
        if (input == null) return null;
        String sanitized = sanitize(input);
        return sanitized.replaceAll("[^a-zA-Z0-9 .,!?\\-_@]", "");
    }
}
