import java.io.File;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.util.regex.Pattern;

public class InputSanitizer {

    private static final Pattern PATH_TRAVERSAL = Pattern.compile(".*\\.\\.[\\\\/].*");
    private static final Pattern CONTROL_CHARS = Pattern.compile("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]");

    public static String sanitize(String input) {
        if (input == null) return "";
        String cleaned = input.trim();
        cleaned = CONTROL_CHARS.matcher(cleaned).replaceAll("");
        cleaned = cleaned.replace("\0", "");
        return limitLength(cleaned, 10000);
    }

    public static String sanitizeForHtml(String input) {
        if (input == null) return "";
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '<': sb.append("&lt;"); break;
                case '>': sb.append("&gt;"); break;
                case '&': sb.append("&amp;"); break;
                case '"': sb.append("&quot;"); break;
                case '\'': sb.append("&#x27;"); break;
                case '/': sb.append("&#x2F;"); break;
                default:
                    if (c > 0x7F || c < 0x20) {
                        sb.append("&#").append((int) c).append(";");
                    } else {
                        sb.append(c);
                    }
            }
        }
        return sb.toString();
    }

    public static String sanitizeForSql(String input) {
        if (input == null) return "";
        return input.replace("'", "''")
                   .replace("\\", "\\\\")
                   .replace("\0", "")
                   .replace("\b", "")
                   .replace("\n", "\\n")
                   .replace("\r", "\\r")
                   .replace("\t", "\\t")
                   .replace((char) 26, ' ');
    }

    public static String sanitizeForShell(String input) {
        if (input == null) return "";
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (c >= 'a' && c <= 'z' || c >= 'A' && c <= 'Z' || 
                c >= '0' && c <= '9' || c == '-' || c == '_' || 
                c == '.' || c == ',' || c == '/' || c == '@' || 
                c == ':' || c == '=' || c == '+' || c == '%') {
                sb.append(c);
            } else {
                sb.append('\\').append(c);
            }
        }
        return sb.toString();
    }

    public static String sanitizeFilePath(String input, String basePath) throws SecurityException {
        if (input == null || input.isEmpty()) throw new SecurityException("Invalid path");

        String cleaned = sanitize(input);
        cleaned = cleaned.replace("\0", "").replace("\n", "").replace("\r", "");

        if (PATH_TRAVERSAL.matcher(cleaned).matches() || cleaned.contains("..")) {
            throw new SecurityException("Path traversal detected");
        }

        if (basePath != null && !basePath.isEmpty()) {
            try {
                File base = new File(basePath).getCanonicalFile();
                File target = new File(base, cleaned).getCanonicalFile();
                if (!target.getPath().startsWith(base.getPath())) {
                    throw new SecurityException("Path outside allowed directory");
                }
                return target.getPath();
            } catch (IOException e) {
                throw new SecurityException("Invalid path: " + e.getMessage());
            }
        }

        return cleaned;
    }

    public static String sanitizeForJson(String input) {
        if (input == null) return "";
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '"': sb.append("\\\""); break;
                case '\\': sb.append("\\\\"); break;
                case '\b': sb.append("\\b"); break;
                case '\f': sb.append("\\f"); break;
                case '\n': sb.append("\\n"); break;
                case '\r': sb.append("\\r"); break;
                case '\t': sb.append("\\t"); break;
                default:
                    if (c < 0x20 || c > 0x7E) {
                        sb.append(String.format("\\u%04x", (int) c));
                    } else {
                        sb.append(c);
                    }
            }
        }
        return sb.toString();
    }

    public static String sanitizeForXml(String input) {
        if (input == null) return "";
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (c == '<') sb.append("&lt;");
            else if (c == '>') sb.append("&gt;");
            else if (c == '&') sb.append("&amp;");
            else if (c == '"') sb.append("&quot;");
            else if (c == '\'') sb.append("&apos;");
            else if (c > 0x7E || (c < 0x20 && c != '\t' && c != '\n' && c != '\r')) {
                sb.append("&#").append((int) c).append(";");
            } else sb.append(c);
        }
        return sb.toString();
    }

    public static String sanitizeAlphanumeric(String input) {
        if (input == null) return "";
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (Character.isLetterOrDigit(c) || c == '_' || c == '-') {
                sb.append(c);
            }
        }
        return sb.toString();
    }

    public static String whitelist(String input, String allowedChars) {
        if (input == null) return "";
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (allowedChars.indexOf(c) >= 0 || Character.isLetterOrDigit(c)) {
                sb.append(c);
            }
        }
        return sb.toString();
    }

    public static String sanitizeEmail(String input) {
        if (input == null) return "";
        String cleaned = sanitize(input).toLowerCase().trim();
        if (!cleaned.matches("^[a-z0-9._%+-]+@[a-z0-9.-]+\\.[a-z]{2,}$")) {
            return "";
        }
        return cleaned;
    }

    public static byte[] sanitizeBytes(byte[] input) {
        if (input == null) return new byte[0];
        byte[] cleaned = new byte[input.length];
        int j = 0;
        for (byte b : input) {
            if (b != 0x00 && b != 0x0B && b != 0x0C) {
                cleaned[j++] = b;
            }
        }
        byte[] result = new byte[j];
        System.arraycopy(cleaned, 0, result, 0, j);
        return result;
    }

    private static String limitLength(String input, int maxLength) {
        if (input == null) return "";
        return input.length() > maxLength ? input.substring(0, maxLength) : input;
    }
}
