import java.text.Normalizer;

public class InputSanitizer {

    public static String sanitize(String input) {
        if (input == null) return null;
        String cleaned = input;
        cleaned = cleaned.replace("\0", "");
        cleaned = cleaned.replaceAll("[\\x00-\\x08\\x0b-\\x0c\\x0e-\\x1f\\x7f]", "");
        cleaned = Normalizer.normalize(cleaned, Normalizer.Form.NFKC);
        cleaned = cleaned.trim();
        return cleaned;
    }

    public static String forHtml(String input) {
        if (input == null) return null;
        StringBuilder sb = new StringBuilder();
        for (char c : sanitize(input).toCharArray()) {
            switch (c) {
                case '<': sb.append("&lt;"); break;
                case '>': sb.append("&gt;"); break;
                case '&': sb.append("&amp;"); break;
                case '"': sb.append("&quot;"); break;
                case '\'': sb.append("&#x27;"); break;
                case '/': sb.append("&#x2F;"); break;
                case '\\': sb.append("&#x5C;"); break;
                default: sb.append(c);
            }
        }
        return sb.toString();
    }

    public static String forSql(String input) {
        if (input == null) return null;
        String cleaned = sanitize(input);
        cleaned = cleaned.replace("'", "''");
        cleaned = cleaned.replace("\\", "\\\\");
        cleaned = cleaned.replace(";", "");
        cleaned = cleaned.replace("/*", "").replace("*/", "");
        cleaned = cleaned.replace("--", "");
        cleaned = cleaned.replace("xp_", "");
        cleaned = cleaned.replace("sp_", "");
        return cleaned;
    }

    public static String forShell(String input) {
        if (input == null) return null;
        String cleaned = sanitize(input);
        String[] dangerous = {";", "&", "|", "`", "$", "(", ")", "{", "}", 
                             "[", "]", "\\", "*", "?", "~", "<", ">", "^", 
                             "#", "\n", "\r", "'", "\""};
        for (String ch : dangerous) {
            cleaned = cleaned.replace(ch, "");
        }
        return cleaned;
    }

    public static String forPath(String input) {
        if (input == null) return null;
        String cleaned = sanitize(input);
        cleaned = cleaned.replace("..", "");
        cleaned = cleaned.replace("\\", "/");
        cleaned = cleaned.replaceAll("[\\x00-\\x1f\\x7f]", "");
        while (cleaned.contains("//")) {
            cleaned = cleaned.replace("//", "/");
        }
        if (cleaned.startsWith("/")) {
            cleaned = cleaned.substring(1);
        }
        return cleaned;
    }

    public static String forAlphanumeric(String input) {
        if (input == null) return null;
        return input.replaceAll("[^a-zA-Z0-9]", "");
    }

    public static String forEmail(String input) {
        if (input == null) return null;
        String cleaned = sanitize(input);
        return cleaned.replaceAll("[^a-zA-Z0-9@.\\-_+]", "");
    }

    public static String forNumber(String input) {
        if (input == null) return null;
        String cleaned = sanitize(input);
        cleaned = cleaned.replaceAll("[^0-9\\-]", "");
        if (cleaned.contains("-")) {
            if (cleaned.indexOf("-") > 0) {
                cleaned = cleaned.replace("-", "");
            } else if (cleaned.indexOf("-") != cleaned.lastIndexOf("-")) {
                cleaned = cleaned.replace("-", "");
            }
        }
        return cleaned;
    }

    public static byte[] sanitizeBinary(byte[] input) {
        if (input == null) return null;
        byte[] cleaned = new byte[input.length];
        int j = 0;
        for (int i = 0; i < input.length; i++) {
            if (input[i] != 0x00) {
                cleaned[j++] = input[i];
            }
        }
        byte[] result = new byte[j];
        System.arraycopy(cleaned, 0, result, 0, j);
        return result;
    }
}
