import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.Map;

@RestController
@RequestMapping("/api/v1")
public class SecureApiController {

    @PostMapping("/secure")
    public ResponseEntity<Map<String, Object>> processRequest(
            @RequestBody Map<String, Object> requestData,
            @RequestHeader(value = "Authorization", required = true) String authHeader) {

        try {
            if (!validate_token(authHeader)) {
                return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
            }

            Map<String, Object> sanitizedData = sanitize_request(requestData);

            return ResponseEntity.ok(sanitizedData);

        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    private boolean validate_token(String token) {
        return token != null && token.startsWith("Bearer ") && token.length() > 7;
    }

    private Map<String, Object> sanitize_request(Map<String, Object> data) {
        if (data == null) return Map.of();
        return data;
    }
}
