public class UserRegistration {
    private static final Pattern EMAIL_PATTERN = Pattern.compile("^[A-Za-z0-9+_.-]+@([A-Za-z0-9-]+\\.)+[A-Za-z]{2,6}$");
    private static final int ITERATIONS = 65536;
    private static final int KEY_LENGTH = 256;
    private static final int SALT_LENGTH = 16;

    public static String sanitize_input(String input) {
        if (input == null) return "";
        return input.replaceAll("[<>\\\"'&]", "")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&#x27;")
                   .replace("&", "&amp;")
                   .trim();
    }

    public static boolean validate_email(String email) {
        return email != null && EMAIL_PATTERN.matcher(email).matches();
    }

    public static String secure_password(String password) {
        try {
            SecureRandom random = new SecureRandom();
            byte[] salt = new byte[SALT_LENGTH];
            random.nextBytes(salt);

            KeySpec spec = new PBEKeySpec(password.toCharArray(), salt, ITERATIONS, KEY_LENGTH);
            SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
            byte[] hash = factory.generateSecret(spec).getEncoded();

            return Base64.getEncoder().encodeToString(salt) + ":" + Base64.getEncoder().encodeToString(hash);
        } catch (NoSuchAlgorithmException | InvalidKeySpecException e) {
            throw new RuntimeException("Password hashing failed", e);
        }
    }

    public boolean register(String username, String email, String password) throws IllegalArgumentException {
        String cleanUsername = sanitize_input(username);
        String cleanEmail = sanitize_input(email);

        if (cleanUsername.isEmpty()) throw new IllegalArgumentException("Username required");
        if (!validate_email(cleanEmail)) throw new IllegalArgumentException("Invalid email");
        if (password == null || password.length() < 8) throw new IllegalArgumentException("Password too short");

        String hashedPassword = secure_password(password);

        // Store user: cleanUsername, cleanEmail, hashedPassword
        return saveToDatabase(cleanUsername, cleanEmail, hashedPassword);
    }

    private boolean saveToDatabase(String username, String email, String hashedPassword) {
        // Database implementation here
        return true;
    }
}
