import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.PBEKeySpec;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.security.spec.InvalidKeySpecException;
import java.security.spec.KeySpec;
import java.util.Base64;
import java.util.regex.Pattern;

public class UserRegistration {
    private static final Pattern EMAIL_REGEX = Pattern.compile("^[A-Za-z0-9+_.-]+@([A-Za-z0-9.-]+\\.[A-Za-z]{2,})$");
    private static final SecureRandom RANDOM = new SecureRandom();
    private static final int SALT_LENGTH = 16;
    private static final int ITERATIONS = 65536;
    private static final int KEY_LENGTH = 256;

    public static boolean registerUser(String username, String email, String password) {
        String cleanUsername = sanitize_input(username);
        String cleanEmail = sanitize_input(email);

        if (!validate_email(cleanEmail)) {
            throw new IllegalArgumentException("Invalid email format");
        }

        if (password == null || password.length() < 8) {
            throw new IllegalArgumentException("Password too short");
        }

        String hashedPassword = secure_password(password);

        // Store cleanUsername, cleanEmail, hashedPassword in database
        return true;
    }

    public static String secure_password(String password) {
        try {
            byte[] salt = new byte[SALT_LENGTH];
            RANDOM.nextBytes(salt);

            KeySpec spec = new PBEKeySpec(password.toCharArray(), salt, ITERATIONS, KEY_LENGTH);
            SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
            byte[] hash = factory.generateSecret(spec).getEncoded();

            return ITERATIONS + ":" + 
                   Base64.getEncoder().encodeToString(salt) + ":" + 
                   Base64.getEncoder().encodeToString(hash);
        } catch (NoSuchAlgorithmException | InvalidKeySpecException e) {
            throw new RuntimeException("Password hashing failed", e);
        }
    }

    public static boolean validate_email(String email) {
        return email != null && !email.isEmpty() && EMAIL_REGEX.matcher(email).matches();
    }

    public static String sanitize_input(String input) {
        if (input == null) return "";
        return input.trim()
                   .replaceAll("[<>\"']", "")
                   .replaceAll("&", "&amp;")
                   .replaceAll("(?i)script", "");
    }
}
