def sanitize(obj):
    """Recursively sanitize user input to prevent injection attacks."""
    if isinstance(obj, str):
        return _clean_string(obj)
    elif isinstance(obj, bytes):
        return _clean_string(obj.decode('utf-8', errors='ignore'))
    elif isinstance(obj, dict):
        return {k: sanitize(v) for k, v in obj.items()}
    elif isinstance(obj, (list, tuple)):
        return type(obj)(sanitize(x) for x in obj)
    elif obj is None:
        return None
    else:
        return _clean_string(str(obj))

def _clean_string(s):
    """Sanitize a single string value."""
    if not isinstance(s, str):
        s = str(s)

    # Remove null bytes
    s = s.replace('\x00', '')

    # Remove control characters (keep tab, newline, carriage return)
    control_chars = ''.join(chr(i) for i in range(32) if i not in (9, 10, 13))
    trans_table = str.maketrans('', '', control_chars)
    s = s.translate(trans_table)

    # HTML entity encoding (XSS prevention)
    s = s.replace('&', '&amp;')
    s = s.replace('<', '&lt;')
    s = s.replace('>', '&gt;')
    s = s.replace('"', '&quot;')
    s = s.replace("'", '&#x27;')
    s = s.replace('/', '&#x2F;')

    # Escape backslashes
    s = s.replace('\\', '\\\\')

    # SQL injection mitigation (basic)
    s = s.replace('--', '')
    s = s.replace('/*', '')
    s = s.replace('*/', '')
    s = s.replace(';', '')

    # Path traversal prevention
    s = s.replace('..', '')
    s = s.replace('//', '/')

    # Normalize unicode to prevent homograph attacks
    try:
        s = s.encode('ascii', 'ignore').decode('ascii')
    except:
        pass

    return s.strip()
