def sanitize_input(data, strict=False):
    if data is None:
        return None

    if isinstance(data, bool):
        return data

    if isinstance(data, (int, float)):
        if isinstance(data, float):
            s = str(data).lower()
            if s in ('nan', 'inf', '-inf', 'infinity', '-infinity'):
                return 0.0
        return data

    if isinstance(data, bytes):
        try:
            data = data.decode('utf-8', errors='ignore')
        except:
            data = str(data)

    if isinstance(data, str):
        return _sanitize_string(data, strict)

    if isinstance(data, (list, tuple)):
        cleaned = [sanitize_input(item, strict) for item in data]
        return tuple(cleaned) if isinstance(data, tuple) else cleaned

    if isinstance(data, dict):
        result = {}
        for key, value in data.items():
            clean_key = sanitize_input(key, strict)
            clean_val = sanitize_input(value, strict)
            if isinstance(clean_key, str):
                if clean_key.startswith('$'):
                    clean_key = '_' + clean_key
                clean_key = clean_key.replace('.', '_')
            result[clean_key] = clean_val
        return result

    if isinstance(data, set):
        return {sanitize_input(item, strict) for item in data}

    return _sanitize_string(str(data), strict)

def _sanitize_string(s, strict):
    s = s.replace('\x00', '')

    chars = []
    for char in s:
        o = ord(char)
        if (o < 32 and char not in ('\t', '\n', '\r')) or o == 127:
            continue
        chars.append(char)
    s = ''.join(chars)

    if strict:
        allowed = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 .,!?-_')
        return ''.join(c if c in allowed else '_' for c in s).strip()

    s = s.replace('&', '&amp;')
    s = s.replace('<', '&lt;')
    s = s.replace('>', '&gt;')
    s = s.replace('"', '&quot;')

