from flask import Flask, request, jsonify, abort
from functools import wraps

app = Flask(__name__)

def validate_token(token):
    return isinstance(token, str) and len(token) >= 32

def sanitize_request(data):
    if not isinstance(data, dict):
        return {}
    return {str(k): str(v)[:1024] for k, v in data.items() if isinstance(k, (str, int))}

def security_middleware(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        token = auth_header.split(' ')[-1] if 'Bearer' in auth_header else auth_header

        if not token or not validate_token(token):
            return jsonify({"error": "Unauthorized"}), 401

        raw_data = request.get_json(silent=True) or {}
        sanitized_data = sanitize_request(raw_data)

        return f(sanitized_data, *args, **kwargs)
    return decorated

@app.route('/api/secure', methods=['POST'])
@security_middleware
def secure_endpoint(data):
    return jsonify({"status": "success", "processed": data}), 200

if __name__ == '__main__':
    app.run(ssl_context='adhoc', host='0.0.0.0', port=443)
