function sanitizeSQL(input) {
  if (input === null || input === undefined) return '';

  const str = String(input);
  let result = '';

  for (let i = 0; i < str.length; i++) {
    const char = str[i];
    switch (char) {
      case '\\':
        result += '\\\\';
        break;
      case "'":
        result += "''";
        break;
      case '"':
        result += '\\"';
        break;
      case '\0':
        result += '\\0';
        break;
      case '\n':
        result += '\\n';
        break;
      case '\r':
        result += '\\r';
        break;
      case '\x1a':
        result += '\\Z';
        break;
      default:
        result += char;
    }
  }

  return result;
}
