class HTMLSanitizer {
  constructor(options = {}) {
    this.config = {
      allowedTags: options.allowedTags || [
        'p', 'br', 'strong', 'b', 'em', 'i', 'u', 'strike', 'del', 's',
        'a', 'img', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
        'ul', 'ol', 'li', 'blockquote', 'code', 'pre', 'hr',
        'div', 'span', 'table', 'thead', 'tbody', 'tfoot', 'tr', 'td', 'th',
        'sup', 'sub', 'small', 'mark', 'abbr', 'cite', 'dfn', 'kbd', 'samp', 'var'
      ],
      allowedAttributes: options.allowedAttributes || {
        '*': ['class', 'id', 'title', 'dir', 'lang'],
        'a': ['href', 'target', 'rel', 'download'],
        'img': ['src', 'alt', 'width', 'height', 'loading'],
        'table': ['border', 'cellpadding', 'cellspacing', 'width'],
        'td': ['colspan', 'rowspan', 'width', 'height'],
        'th': ['colspan', 'rowspan', 'scope', 'width', 'height'],
        'blockquote': ['cite'],
        'q': ['cite'],
        'del': ['cite', 'datetime'],
        'ins': ['cite', 'datetime'],
        'time': ['datetime']
      },
      allowedSchemes: options.allowedSchemes || ['http', 'https', 'mailto', 'tel'],
      allowDataImages: options.allowDataImages || false,
      stripComments: options.stripComments !== false,
      preserveTextContent: options.preserveTextContent !== false
    };

    this.blockedTags = new Set([
      'script', 'style', 'iframe', 'frame', 'object', 'embed', 'param',
      'applet', 'form', 'input', 'textarea', 'button', 'select', 'option',
      'optgroup', 'fieldset', 'label', 'datalist', 'output', 'canvas',
      'svg', 'math', 'meta', 'link', 'base', 'head', 'body', 'html',
      'title', 'noscript', 'template', 'slot', 'shadow'
    ]);
  }

  sanitize(html) {
    if (typeof html !== 'string') return '';

    // Parse HTML into a disconnected DOM tree
    const parser = new DOMParser();
    const doc = parser.parseFromString(`<div id="sanitizer-wrapper">${html}</div>`, 'text/html');
    const wrapper = doc.getElementById('sanitizer-wrapper');

    if (!wrapper) return '';

    // Process the tree
    const fragment = document.createDocumentFragment();
    while (wrapper.firstChild) {
      const node = wrapper.firstChild;
      wrapper.removeChild(node);
      const cleaned = this._sanitizeNode(node);
      if (cleaned) {
        fragment.appendChild(cleaned);
      }
    }

    // Serialize back to string
    const container = document.createElement('div');
    container.appendChild(fragment);
    return container.innerHTML;
  }

  _sanitizeNode(node) {
    // Handle text nodes
    if (node.nodeType === Node.TEXT_NODE) {
      return document.createTextNode(node.textContent);
    }

    // Handle comments
    if (node.nodeType === Node.COMMENT_NODE) {
      return this.config.stripComments ? null : document.createComment(node.data);
    }

    // Only process element nodes
    if (node.nodeType !== Node.ELEMENT_NODE) {
      return null;
    }

    const tagName = node.tagName.toLowerCase();

    // Always remove dangerous tags completely (don't preserve children for scripts/styles)
    if (this.blockedTags.has(tagName)) {
      return null;
    }

    // Check if tag is in whitelist
    const isAllowed = this.config.allowedTags.includes(tagName);

    if (!isAllowed) {
      if (this.config.preserveTextContent) {
        // Replace tag with its text content
        const fragment = document.createDocumentFragment();
        this._extractTextContent(node, fragment);
        return fragment;
      }
      return null;
    }

    // Create clean element
    const cleanElem = document.createElement(tagName);

    // Process attributes
    const allowedAttrs = [
      ...(this.config.allowedAttributes['*'] || []),
      ...(this.config.allowedAttributes[tagName] || [])
    ];

    for (const attr of Array.from(node.attributes)) {
      const attrName = attr.name.toLowerCase();
      const attrValue = attr.value;

      if (this._isSafeAttribute(tagName, attrName, attrValue, allowedAttrs)) {
        cleanElem.setAttribute(attrName, attrValue);
      }
    }

    // Add security attributes for links
    if (tagName === 'a' && cleanElem.getAttribute('target') === '_blank') {
      const rel = (cleanElem.getAttribute('rel') || '').split(/\s+/);
      if (!rel.includes('noopener')) rel.push('noopener');
      if (!rel.includes('noreferrer')) rel.push('noreferrer');
      cleanElem.setAttribute('rel', rel.join(' ').trim());
    }

    // Recursively process children
    while (node.firstChild) {
      const child = node.firstChild;
      node.removeChild(child);
      const cleanedChild = this._sanitizeNode(child);
      if (cleanedChild) {
        cleanElem.appendChild(cleanedChild);
      }
    }

    return cleanElem;
  }

  _isSafeAttribute(tag, name, value, allowedList) {
    // Block event handlers
    if (name.startsWith('on')) return false;

    // Block srcdoc (can contain scripts)
    if (name === 'srcdoc') return false;

    // Block formaction (can be javascript:)
    if (name === 'formaction') return false;

    // Check if attribute is allowed for this tag
    if (!allowedList.includes(name)) return false;

    // Validate URL attributes
    const urlAttrs = ['href', 'src', 'action', 'cite', 'poster', 'background', 'longdesc', 'profile', 'usemap'];
    if (urlAttrs.includes(name)) {
      return this._isSafeUrl(value);
    }

    // Sanitize style attributes
    if (name === 'style') {
      return this._isSafeStyle(value);
    }

    return true;
  }

  _isSafeUrl(url) {
    if (!url) return true;

    try {
      // Create anchor to parse URL
      const anchor = document.createElement('a');
      anchor.href = url;
      const protocol = anchor.protocol.toLowerCase();

      // Block dangerous protocols
      const dangerous = ['javascript:', 'vbscript:', 'file:', 'about:', 'blob:', 'data:'];
      if (dangerous.includes(protocol)) {
        // Special case: allow data: images if configured
        if (protocol === 'data:' && this.config.allowDataImages) {
          return /^data:image\/(png|jpeg|jpg|gif|webp|svg\+xml);/i.test(url);
        }
        return false;
      }

      // Check for protocol spoofing attempts (e.g., "javascript://%0Aalert(1)")
      const decoded = decodeURIComponent(url).toLowerCase().replace(/\s+/g, '');
      if (decoded.includes('javascript:') || decoded.includes('vbscript:')) {
        return false;
      }

      // Check scheme against whitelist
      const scheme = protocol.replace(':', '');
