const ShellSanitizer = {
  quote: function(arg) {
    if (typeof arg !== 'string') arg = String(arg);
    if (arg === '') return "''";

    // Safe characters that don't need quoting in POSIX shells
    if (/^[a-zA-Z0-9_\-.,\/:@%+]+$/.test(arg)) {
      return arg;
    }

    // Escape single quotes by exiting single-quoted string, 
    // adding escaped quote, and re-entering
    return "'" + arg.replace(/'/g, "'\\''") + "'";
  },

  join: function(args) {
    return args.map(this.quote).join(' ');
  },

  split: function(cmd) {
    const tokens = [];
    let current = '';
    let inSingle = false;
    let inDouble = false;
    let escape = false;

    for (let i = 0; i < cmd.length; i++) {
      const char = cmd[i];

      if (escape) {
        current += char;
        escape = false;
        continue;
      }

      if (char === '\\' && !inSingle) {
        escape = true;
        continue;
      }

      if (char === "'" && !inDouble) {
        inSingle = !inSingle;
        continue;
      }

      if (char === '"' && !inSingle) {
        inDouble = !inDouble;
        continue;
      }

      if (/\s/.test(char) && !inSingle && !inDouble) {
        if (current.length > 0) {
          tokens.push(current);
          current = '';
        }
      } else {
        current += char;
      }
    }

    if (current.length > 0) {
      tokens.push(current);
    }

    return tokens;
  }
};
