function sanitizeShellArg(arg) {
  if (typeof arg !== 'string') {
    throw new TypeError('Argument must be a string');
  }

  if (arg.length === 0) {
    return "''";
  }

  // If only safe characters (alphanumeric and common safe symbols), return as-is
  if (/^[a-zA-Z0-9_./:@-]+$/.test(arg)) {
    return arg;
  }

  // Wrap in single quotes and escape any single quotes
  // To escape ' in single quotes: end quote, escaped quote, start quote: '\''
  return "'" + arg.replace(/'/g, "'\\''") + "'";
}

function sanitizeShellCommand(args) {
  if (!Array.isArray(args)) {
    throw new TypeError('Expected array of string arguments');
  }

  return args.map(sanitizeShellArg).join(' ');
}

function isShellSafe(str) {
  if (typeof str !== 'string') return false;
  // Check for shell metacharacters that could enable injection
  return !/[;&|$\(\)\{\}\[\]<>!#*`?\\\s]/.test(str);
}

function sanitizeShellInput(input) {
  if (typeof input !== 'string') return '';
  // Remove null bytes
  input = input.replace(/\x00/g, '');
  // Aggressive sanitization: escape all shell metacharacters with backslash
  return input.replace(/([;&|$\(\)\{\}\[\]<>!#*`?\\])/g, '\\$1');
}

// Export for different module systems
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { sanitizeShellArg, sanitizeShellCommand, isShellSafe, sanitizeShellInput };
}
