function parseShellCommand(input) {
    if (typeof input !== 'string') return [];

    const args = [];
    let current = '';
    let i = 0;
    const len = input.length;

    const isWhitespace = (c) => /^\s$/.test(c);

    while (i < len) {
        while (i < len && isWhitespace(input[i])) i++;
        if (i >= len) break;

        const char = input[i];

        if (char === '#') break;

        if (char === "'") {
            i++;
            while (i < len && input[i] !== "'") {
                current += input[i];
                i++;
            }
            if (i < len) i++;
            continue;
        }

        if (char === '"') {
            i++;
            while (i < len) {
                if (input[i] === '\\' && i + 1 < len && ['"', '\\', '$', '`', '\n'].includes(input[i + 1])) {
                    current += input[i + 1];
                    i += 2;
                } else if (input[i] === '"') {
                    i++;
                    break;
                } else {
                    current += input[i];
                    i++;
                }
            }
            continue;
        }

        if (char === '\\') {
            if (i + 1 < len) {
                current += input[i + 1];
                i += 2;
            } else {
                i++;
            }
            continue;
        }

        while (i < len && !isWhitespace(input[i]) && input[i] !== '#' && input[i] !== "'" && input[i] !== '"' && input[i] !== '\\') {
            current += input[i];
            i++;
        }

        if (current.length > 0) {
            args.push(current);
            current = '';
        }
    }

    if (current.length > 0) args.push(current);
    return args;
}

function escapeShellArg(arg) {
    if (typeof arg !== 'string') throw new TypeError('Argument must be a string');
    if (/^[a-zA-Z0-9_.\-\/:@]+$/.test(arg)) return arg;
    return "'" + arg.replace(/'/g, "'\"'\"'") + "'";
}

function sanitizeShellInput(input, options = {}) {
    const { 
        allowRedirects = false, 
        allowPipes = false, 
        allowSubshells = false,
        allowEnvVars = false 
    } = options;

    if (typeof input !== 'string') return null;

    const forbidden = [
        /[;&\n\r]/,
        allowRedirects ? null : /[<>]/,
        allowPipes ? null : /\|/,
        allowSubshells ? null : /[(){}]/,
        allowSubshells ? null : /`.*?`/,
        allowSubshells ? null : /\$\(.*?\)/,
        allowEnvVars ? null : /\$[a-zA-Z_][a-zA-Z0-9_]*/
    ].filter(Boolean);

    for (const pattern of forbidden) {
        if (pattern.test(input)) return null;
    }

    return parseShellCommand(input);
}
