function sanitizePath(input, root) {
  if (typeof input !== 'string') return null;

  // Null byte injection check
  if (input.indexOf('\0') !== -1) return null;

  // Decode percent encoding recursively to catch double-encoded attacks (%252f -> %2f -> /)
  let path = input;
  try {
    let previous;
    do {
      previous = path;
      path = decodeURIComponent(previous.replace(/\+/g, ' '));
    } while (path !== previous);
  } catch (e) {
    return null;
  }

  // Check null bytes again after decoding
  if (path.indexOf('\0') !== -1) return null;

  // Normalize backslashes to forward slashes
  path = path.replace(/\\/g, '/');

  // Strip absolute path indicators (drive letters C:/ and leading slashes)
  path = path.replace(/^[a-zA-Z]:\//i, '').replace(/^\/+/, '');

  // Split and resolve path components
  const parts = path.split('/');
  const safe = [];

  for (const part of parts) {
    if (part === '' || part === '.') {
      continue;
    }
    if (part === '..') {
      // Attempting to traverse above root
      if (safe.length === 0) return null;
      safe.pop();
    } else {
      // Optional: block Windows reserved names (CON, PRN, etc) and colons here if needed
      safe.push(part);
    }
  }

  let result = safe.join('/');

  if (root) {
    const safeRoot = String(root).replace(/\\/g, '/').replace(/\/+$/, '');
    result = safeRoot + '/' + result;
  }

  return result || '';
}
