const path = require('path');

function sanitizePath(baseDir, userPath) {
    if (typeof baseDir !== 'string' || typeof userPath !== 'string') {
        throw new Error('Invalid input: paths must be strings');
    }

    if (userPath.includes('\0')) {
        throw new Error('Null byte detected in path');
    }

    const resolvedBase = path.resolve(baseDir);
    let normalized = userPath.replace(/\\/g, '/');

    normalized = normalized.replace(/^\/+/, '');
    normalized = normalized.replace(/^[a-zA-Z]:\/?/i, '');

    const segments = normalized.split('/');
    const safeSegments = [];

    for (const segment of segments) {
        if (segment === '' || segment === '.') continue;
        if (segment === '..') throw new Error('Directory traversal attempt detected');
        safeSegments.push(segment);
    }

    const joinedPath = path.join(resolvedBase, ...safeSegments);
    const resolvedPath = path.resolve(joinedPath);

    const baseWithSep = resolvedBase.endsWith(path.sep) 
        ? resolvedBase 
        : resolvedBase + path.sep;

    const checkPath = process.platform === 'win32' ? resolvedPath.toLowerCase() : resolvedPath;
    const checkBase = process.platform === 'win32' ? baseWithSep.toLowerCase() : baseWithSep;
    const checkBaseExact = process.platform === 'win32' ? resolvedBase.toLowerCase() : resolvedBase;

    if (!checkPath.startsWith(checkBase) && checkPath !== checkBaseExact) {
        throw new Error('Path escaped base directory');
    }

    return resolvedPath;
}

module.exports = { sanitizePath };
