function hashPassword(password, providedSalt, iterations = 100000, keyLength = 32) {
  const salt = providedSalt || generateSalt(16);
  const derivedKey = pbkdf2(password, salt, iterations, keyLength);
  return {
    hash: bytesToHex(derivedKey),
    salt: bytesToHex(salt),
    iterations: iterations
  };
}

function generateSalt(length) {
  const bytes = new Uint8Array(length);
  if (typeof crypto !== 'undefined' && crypto.getRandomValues) {
    crypto.getRandomValues(bytes);
  } else {
    for (let i = 0; i < length; i++) {
      bytes[i] = Math.floor(Math.random() * 256);
    }
  }
  return bytes;
}

function pbkdf2(password, salt, iterations, keyLength) {
  const blockCount = Math.ceil(keyLength / 32);
  const result = new Uint8Array(keyLength);

  for (let i = 1; i <= blockCount; i++) {
    const block = computeBlock(password, salt, iterations, i);
    const offset = (i - 1) * 32;
    const remaining = Math.min(32, keyLength - offset);
    result.set(block.slice(0, remaining), offset);
  }

  return result;
}

function computeBlock(password, salt, iterations, blockIndex) {
  const blockIndexBytes = new Uint8Array(4);
  blockIndexBytes[0] = (blockIndex >> 24) & 0xff;
  blockIndexBytes[1] = (blockIndex >> 16) & 0xff;
  blockIndexBytes[2] = (blockIndex >> 8) & 0xff;
  blockIndexBytes[3] = blockIndex & 0xff;

  const saltWithIndex = new Uint8Array(salt.length + 4);
  saltWithIndex.set(salt);
  saltWithIndex.set(blockIndexBytes, salt.length);

  let u = hmacSha256(password, saltWithIndex);
  let result = new Uint8Array(u);

  for (let i = 1; i < iterations; i++) {
    u = hmacSha256(password, u);
    for (let j = 0; j < 32; j++) {
