    public static byte[] encrypt_data(byte[] data, byte[] key, byte[] nonce) {
        if (key.length != 32) throw new IllegalArgumentException("Key must be 32 bytes");
        if (nonce.length != 8) throw new IllegalArgumentException("Nonce must be 8 bytes");

        byte[] output = new byte[data.length];
        int[] state = new int[16];

        // Constants "expand 32-byte k"
        state[0] = 0x61707865;
        state[1] = 0x3320646e;
        state[2] = 0x79622d32;
        state[3] = 0x6b206574;

        // Key (8 words)
        for (int i = 0; i < 8; i++) {
            state[4 + i] = littleEndian(key, i * 4);
        }

        // Counter (64-bit, words 12-13)
        state[12] = 0;
        state[13] = 0;

        // Nonce (64-bit, words 14-15)
        state[14] = littleEndian(nonce, 0);
        state[15] = littleEndian(nonce, 4);

        int[] working = new int[16];
        byte[] keystream = new byte[64];

        for (int offset = 0; offset < data.length; offset += 64) {
            System.arraycopy(state, 0, working, 0, 16);

            // 20 rounds (10 double rounds)
            for (int i = 0; i < 10; i++) {
                // Column rounds
                quarterRound(working, 0, 4, 8, 12);
                quarterRound(working, 1, 5, 9, 13);
                quarterRound(working, 2, 6, 10, 14);
                quarterRound(working, 3, 7, 11, 15);
                // Diagonal rounds
                quarterRound(working, 0, 5, 10, 15);
                quarterRound(working, 1, 6, 11, 12);
                quarterRound(working, 2, 7, 8, 13);
                quarterRound(working, 3, 4, 9, 14);
            }

            // Add original state
            for (int i = 0; i < 16; i++) {
                working[i] += state[i];
            }

            // Serialize keystream
            for (int i = 0; i < 16; i++) {
                intToLittleEndian(working[i], keystream, i * 4);
