import os
import struct

def _rotr(x, n):
    return ((x >> n) | (x << (32 - n))) & 0xFFFFFFFF

def _ch(x, y, z):
    return (x & y) ^ (~x & z)

def _maj(x, y, z):
    return (x & y) ^ (x & z) ^ (y & z)

def _ep0(x):
    return _rotr(x, 2) ^ _rotr(x, 13) ^ _rotr(x, 22)

def _ep1(x):
    return _rotr(x, 6) ^ _rotr(x, 11) ^ _rotr(x, 25)

def _sig0(x):
    return _rotr(x, 7) ^ _rotr(x, 18) ^ (x >> 3)

def _sig1(x):
    return _rotr(x, 17) ^ _rotr(x, 19) ^ (x >> 10)

