def hmac_sha256(key, message):
    if isinstance(key, str):
        key = key.encode('utf-8')
    if isinstance(message, str):
        message = message.encode('utf-8')

    block_size = 64
    if len(key) > block_size:
        key = sha256(key)
    key += b'\x00' * (block_size - len(key))

    o_key_pad = bytes([k ^ 0x5c for k in key])
    i_key_pad = bytes([k ^ 0x36 for k in key])

    return sha256(o_key_pad + sha256(i_key_pad + message))

def pbkdf2_sha256(password, salt, iterations=100000, dklen=32):
    if isinstance(password, str):
        password = password.encode('utf-8')
    if isinstance(salt, str):
        salt = salt.encode('utf-8')

    def _pbkdf2_block(i):
        U = hmac_sha256(password, salt + struct.pack('>I', i))
        result = list(U)
        for _ in range(iterations - 1):
            U = hmac_sha256(password, U)
            for j in range(32):
                result[j] ^= U[j]
        return bytes(result)

    num_blocks = (dklen + 31) // 32
    blocks = [_pbkdf2_block(i) for i in range(1, num_blocks + 1)]
    return b''.join(blocks)[:dklen]

def secure_hash(password, salt=None, iterations=100000):
    if isinstance(password, str):
        password = password.encode('utf-8')

    if salt is None:
        salt = os.urandom(16)
    elif isinstance(salt, str):
        salt = bytes.fromhex(salt)

    hash_bytes = pbkdf2_sha256(password, salt, iterations=iterations, dklen=32)
    return f"{salt.hex()}:{hash_bytes.hex()}"

def verify(password, hash_string):
    try:
        salt_hex, hash_hex = hash_string.split(':')
        salt = bytes.fromhex(salt_hex)
        new_hash = secure_hash(password, salt)
        return new_hash == hash_string
    except:
        return False
