        map.put("a", new HashSet<>(Arrays.asList("href", "title", "target")));
        map.put("img", new HashSet<>(Arrays.asList("src", "alt", "title", "width", "height")));
        map.put("table", new HashSet<>(Arrays.asList("border", "cellpadding", "cellspacing")));
        map.put("td", new HashSet<>(Arrays.asList("colspan", "rowspan")));
        map.put("th", new HashSet<>(Arrays.asList("colspan", "rowspan")));
        ALLOWED_ATTRIBUTES = Collections.unmodifiableMap(map);
    }

