                if (isClosing) tagContent = tagContent.substring(1);
                if (isSelfClosing) tagContent = tagContent.substring(0, tagContent.length() - 1).trim();

                String tagName = extractTagName(tagContent).toLowerCase();

                if (ALLOWED_TAGS.contains(tagName)) {
                    if (isClosing) {
                        output.append("</").append(tagName).append(">");
                    } else {
                        String attrs = tagContent.substring(tagName.length()).trim();
                        String cleanAttrs = sanitizeAttributes(tagName, attrs);
                        output.append("<").append(tagName);
                        if (!cleanAttrs.isEmpty()) output.append(" ").append(cleanAttrs);
                        if (isSelfClosing) output.append(" /");
                        output.append(">");
                    }
                } else {
                    // Disallowed tag - encode to prevent interpretation
                    // Special handling for script/style to remove content
                    if (tagName.equals("script") || tagName.equals("style") || tagName.equals("textarea")) {
                        int closeIndex = findClosingTag(input, tagName, tagEnd);
                        if (closeIndex != -1) {
                            i = closeIndex;
                            continue;
                        }
                    }
                    output.append(escapeHtml(input.substring(i, tagEnd + 1)));
                }
                i = tagEnd + 1;

            } else if (c == '&') {
                // Check for valid entity
                int maxScan = Math.min(i + 10, len);
                String possibleEntity = input.substring(i, maxScan);
                Matcher m = VALID_ENTITY.matcher(possibleEntity);
                if (m.find()) {
                    String entity = m.group();
                    // Check it's not a dangerous entity decoding
                    if (!entity.toLowerCase().contains("script")) {
                        output.append(entity);
                        i += entity.length();
                        continue;
                    }
                }
                output.append("&amp;");
                i++;
            } else {
                output.append(c);
                i++;
            }
        }
        return output.toString();
    }

    private static int findTagEnd(String input, int start) {
        int len = input.length();
        boolean inSingleQuote = false;
        boolean inDoubleQuote = false;

        for (int i = start; i < len; i++) {
            char c = input.charAt(i);
            if (c == '"' && !inSingleQuote) {
                inDoubleQuote = !inDoubleQuote;
            } else if (c == '\'' && !inDoubleQuote) {
                inSingleQuote = !inSingleQuote;
            } else if (c == '>' && !inSingleQuote && !inDoubleQuote) {
                return i;
            }
        }
        return -1;
    }

    private static String extractTagName(String tagContent) {
        int len = tagContent.length();
        int i = 0;
        while (i < len && (Character.isWhitespace(tagContent.charAt(i)) || tagContent.charAt(i) == '/')) i++;
        int start = i;
        while (i < len && !Character.isWhitespace(tagContent.charAt(i)) && tagContent.charAt(i) != '/') i++;
        return i > start ? tagContent.substring(start, i) : "";
    }

    private static String sanitizeAttributes(String tagName, String attributes) {
        StringBuilder result = new StringBuilder();
        Set<String> allowed = ALLOWED_ATTRIBUTES.getOrDefault(tagName, Collections.emptySet());

        int i = 0;
        int len = attributes.length();

        while (i < len) {
            // Skip whitespace
            while (i < len && Character.isWhitespace(attributes.charAt(i))) i++;
            if (i >= len) break;

            // Parse attribute name
            int nameStart = i;
            while (i < len && attributes.charAt(i) != '=' && !Character.isWhitespace(attributes.charAt(i))) i++;
            String attrName = attributes.substring(nameStart, i).toLowerCase();

            String attrValue = "";
            boolean hasValue = false;

            if (i < len && attributes.charAt(i) == '=') {
                i++;
                hasValue = true;
                while (i < len && Character.isWhitespace(attributes.charAt(i))) i++;

                if (i < len && (attributes.charAt(i) == '"' || attributes.charAt(i) == '\'')) {
                    char quote = attributes.charAt(i);
                    i++;
                    int valStart = i;
                    while (i < len && attributes.charAt(i) != quote) i++;
                    attrValue = attributes.substring(valStart, i);
                    if (i < len) i++;
                } else {
                    int valStart = i;
                    while (i < len && !Character.isWhitespace(attributes.charAt(i))) i++;
                    attrValue = attributes.substring(valStart, i);
                }
            }

            // Skip event handlers and data attributes
            if (attrName.startsWith("on") || attrName.startsWith("data-")) {
                i++;
                continue;
            }

            if (allowed.contains(attrName)) {
                if (URI_ATTRIBUTES.contains(attrName)) {
                    attrValue = sanitizeUrl(attrValue);
                    if (attrValue == null) continue;
                } else {
                    attrValue = escapeHtml(attrValue);
                }

                if (result.length() > 0) result.append(" ");
                if (hasValue) {
                    result.append(attrName).append("=\"").append(attrValue).append("\"");
                } else {
                    result.append(attrName);
                }
            }
        }
        return result.toString();
    }

    private static String sanitizeUrl(String url) {
        if (url == null) return null;
        url = decodeEntities(url).trim();

        // Remove null bytes and control characters
        url = url.replaceAll("[\\x00-\\x1F\\x7F]", "");

        // Check for dangerous protocols
        if (DANGEROUS_PROTOCOL.matcher(url).find()) {
            return null;
        }

        // Additional check for HTML entities trying to obfuscate
        if (url.toLowerCase().contains("javascript") || url.toLowerCase().contains("expression")) {
            return null;
        }

        return escapeHtml(url);
    }

    private static String decodeEntities(String text) {
        return text.replace("&lt;", "<")
                   .replace("&gt;", ">")
                   .replace("&amp;", "&")
                   .replace("&quot;", "\"")
                   .replace("&#39;", "'")
                   .replace("&#x27;", "'");
    }

    private static String escapeHtml(String text) {
        return text.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&#39;");
    }

    private static int findClosingTag(String input, String tagName, int start) {
        String search = "</" + tagName + ">";
        int idx = input.toLowerCase().indexOf(search, start);
        return idx != -1 ? idx + search.length() : -1;
    }
}
