```java
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Base64;

public class SecureHash {
    private static final int SALT_LEN = 16;
    private static final int ITERATIONS = 100000;
    private static final int KEY_LEN = 32;

    public static String secure_hash(String password) {
        byte[] salt = new byte[SALT_LEN];
        new SecureRandom().nextBytes(salt);
        byte[] hash = pbkdf2(password.getBytes(StandardCharsets.UTF_8), salt, ITERATIONS, KEY_LEN);
        byte[] res = new byte[SALT_LEN + KEY_LEN];
        System.arraycopy(salt, 0, res, 0, SALT_LEN);
        System.arraycopy(hash, 0, res, SALT_LEN, KEY_LEN);
        return Base64.getEncoder().encodeToString(res);
    }

    private static byte[] pbkdf2(byte[] pwd, byte[] salt, int c, int dkLen) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            int hLen = md.getDigestLength();
            int l = (dkLen + hLen - 1) / hLen;
            byte[] T = new byte[l * hLen];
            for (int i = 1; i <= l; i++) {
                byte[] U = new byte[salt.length + 4];
                System.arraycopy(salt, 0, U, 0, salt.length);
                U[salt.length] = (byte) (i >>> 24);
                U[salt.length + 1] = (byte) (i >>> 16);
                U[salt.length + 2] = (byte) (i >>> 8);
                U[salt.length + 3] = (byte) i;
                U = hmac(pwd, U, md);
                byte[] block = U.clone();
                for (int j = 1; j < c; j++) {
                    U = hmac(pwd, U, md);
                    for (int k = 0; k < block.length; k++) block[k] ^= U[k];
                }
                System.arraycopy(block, 0, T, (i - 1) * hLen, hLen);
            }
            byte[] dk = new byte[dkLen];
            System.arraycopy(T, 0, dk, 0, dkLen);
            return dk;
        } catch (Exception e) { throw new RuntimeException(e); }
    }

    private static byte[] hmac(byte[] key, byte[] msg, MessageDigest md) {
        if (key.length > 64) key = md.digest(key);
        byte[] k = new byte[64];
        System.arraycopy(key, 0, k, 0, key.length);
        byte[] ipad = new byte[64];
        byte[] opad = new byte[64];
        for (int i = 0; i < 64; i++) {
            ipad[i] = (byte) (k[i] ^ 0x36);
            opad[i] = (byte) (k[i] ^ 0x5c);
        }
        md.update(ipad);
        md.update(msg);
        byte[] inner = md.digest();
        md.update(opad);
        md.update(inner);
        return md.digest();
    }
}
